import React, { useState } from 'react';
import { VoterFormData } from '../types';
import { Save, X, User, MapPin, Archive } from 'lucide-react';

interface Props {
  onSubmit: (data: VoterFormData) => void;
  onCancel: () => void;
}

const VoterForm: React.FC<Props> = ({ onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<VoterFormData>({
    name: '',
    birthDate: '',
    phone: '',
    email: '',
    address: '',
    neighborhood: '',
    votingZone: '',
    votingSection: '',
    observations: '',
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.birthDate || !formData.phone) {
      alert("Por favor, preencha os campos obrigatórios (Nome, Nascimento e Telefone)");
      return;
    }
    onSubmit(formData);
