import { jsPDF } from "jspdf";
import "jspdf-autotable";
import { Voter } from "../types";

export function exportVotersToPDF(voters: Voter[]) {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4",
  });

  const now = new Date().toLocaleString("pt-BR");

  // Cabeçalho
  doc.setFontSize(18);
  doc.setTextColor(67, 56, 202); // Indigo 700
  doc.text("Relatório Geral de Eleitores", 14, 15);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139); // Slate 500
  doc.text(`Gerado em: ${now}`, 14, 22);
  doc.text(`Total de registros: ${voters.length}`, 14, 27);

  // Tabela
  const tableColumn = ["Nome", "Nascimento", "Telefone", "Bairro", "Zona", "Seção"];
  const tableRows = voters.map((voter) => [
    voter.name,
    new Date(voter.birthDate).toLocaleDateString("pt-BR"),
    voter.phone,
    voter.neighborhood,
    voter.votingZone,
    voter.votingSection,
  ]);

  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 35,
    theme: "striped",
    headStyles: {
      fillColor: [67, 56, 202],
      textColor: [255, 255, 255],
      fontSize: 10,
      fontStyle: "bold",
    },
    bodyStyles: {
      fontSize: 9,
      textColor: [30, 41, 59],
    },
    alternateRowStyles: {
      fillColor: [248, 250, 252],
    },
    margin: { top: 35 },
  });

  // Salvar o PDF
  const filename = `eleitores_${new Date().toISOString().split('T')[0]}.pdf`;
  doc.save(filename);
}

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import { exportVotersToPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  Calendar, 
  LayoutDashboard, 
  Search,
  Bell,
  BarChart3,
  FileText
} from 'lucide-react';

const App: React.FC = () => {
  const [voters, setVoters] = useState<Voter[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'add' | 'edit'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  // Load data from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('voters_data');
    if (saved) {
      setVoters(JSON.parse(saved));
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab('list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;

    setVoters(prev => prev.map(v => 
      v.id === editingVoter.id ? { ...v, ...data } : v
    ));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const startEditing = (voter: Voter) => {
    setEditingVoter(voter);
    setActiveTab('edit');
  };

  const handleExportPDF = () => {
    if (voters.length === 0) {
      alert("Não há eleitores para exportar.");
      return;
    }
    exportVotersToPDF(voters);
  };

  const filteredVoters = useMemo(() => {
    return voters.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.phone.includes(searchTerm)
    );
  }, [voters, searchTerm]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      if (parts.length !== 3) return false;
      const [, vMonth, vDay] = parts;
      return vMonth === tMonth && vDay === tDay;
    });
  }, [voters]);

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar - Desktop */}
      <nav className="w-full md:w-64 bg-indigo-900 text-white flex-shrink-0">
        <div className="p-6">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Users className="text-indigo-300" />
            Gestão Eleitoral
          </h1>
          <p className="text-indigo-300 text-xs mt-1">Sua base, seu futuro.</p>
        </div>

        <div className="mt-4 px-3 space-y-1">
          <button 
            onClick={() => { setActiveTab('dashboard'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'dashboard' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </button>
          <button 
            onClick={() => { setActiveTab('list'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'list' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Users size={20} />
            Lista de Eleitores
          </button>
          <button 
            onClick={() => { setActiveTab('add'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'add' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <UserPlus size={20} />
            Cadastrar Novo
          </button>
        </div>

        {/* Quick Stats Sidebar */}
        <div className="mt-auto p-6 hidden md:block">
          <div className="bg-indigo-800 rounded-xl p-4 border border-indigo-700">
            <p className="text-indigo-300 text-sm">Total de Eleitores</p>
            <p className="text-3xl font-bold">{voters.length}</p>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-slate-50">
        {/* Header */}
        <header className="sticky top-0 z-10 bg-white border-b border-slate-200 px-6 py-4 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="relative w-full sm:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar por nome, bairro ou telefone..."
              className="w-full pl-10 pr-4 py-2 bg-slate-100 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500 rounded-lg outline-none transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-4">
            <div className="relative">
              <Bell className="text-slate-600 cursor-pointer" />
              {birthdayVoters.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">
                  {birthdayVoters.length}
                </span>
              )}
            </div>
            <div className="h-8 w-8 rounded-full bg-indigo-500 flex items-center justify-center text-white font-medium">
              A
            </div>
          </div>
        </header>

        <div className="p-6">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <Dashboard voters={voters} />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
                <div className="lg:col-span-7">
                  <NeighborhoodChart voters={voters} />
                </div>

                <div className="lg:col-span-5 space-y-6">
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                     <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                       <BarChart3 size={18} className="text-indigo-600" />
                       Ações Rápidas
                     </h3>
                     <div className="grid grid-cols-1 gap-3">
                       <button 
                        onClick={() => setActiveTab('add')}
                        className="flex items-center justify-center gap-2 py-3 px-4 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors font-medium"
                       >
                         <UserPlus size={18} /> Novo Eleitor
                       </button>
                       <button 
                        onClick={handleExportPDF}
                        className="flex items-center justify-center gap-2 py-3 px-4 bg-white border border-slate-200 text-slate-700 rounded-xl hover:bg-slate-50 transition-colors font-medium"
                       >
                         <FileText size={18} className="text-red-500" /> Exportar PDF
                       </button>
                     </div>
                   </div>

                   <div>
                      <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                        <Calendar className="text-indigo-600" /> Aniversariantes do Mês
                      </h2>
                      <BirthdayWidget voters={voters} />
                   </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800">Listagem de Eleitores</h2>
                <button 
                  onClick={() => exportVotersToPDF(filteredVoters)}
                  className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold shadow-sm"
                >
                  <FileText size={16} className="text-red-500" /> Exportar Lista Atual
                </button>
              </div>
              <VoterList voters={filteredVoters} onDelete={deleteVoter} onEdit={startEditing} />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="max-w-3xl mx-auto">
              <VoterForm 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => { setActiveTab('list'); setEditingVoter(null); }} 
                initialData={editingVoter || undefined}
              />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Voter } from '../types';
import { Hash } from 'lucide-react';

interface Props {
  voters: Voter[];
}

const SectionSummary: React.FC<Props> = ({ voters }) => {
  const sectionStats = useMemo(() => {
    const stats: Record<string, { zone: string; section: string; count: number }> = {};

    voters.forEach(v => {
      const key = `${v.votingZone}-${v.votingSection}`;
      if (!stats[key]) {
        stats[key] = { zone: v.votingZone, section: v.votingSection, count: 0 };
      }
      stats[key].count++;
    });

    return Object.values(stats).sort((a, b) => b.count - a.count);
  }, [voters]);

  if (voters.length === 0) return null;

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
      <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
        <Hash size={18} className="text-indigo-600" />
        Eleitores por Seção
      </h3>

      <div className="grid grid-cols-2 gap-3">
        {sectionStats.slice(0, 6).map((stat) => (
          <div key={`${stat.zone}-${stat.section}`} className="p-3 bg-slate-50 rounded-xl border border-slate-100 flex flex-col items-center justify-center">
            <div className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
              Z: {stat.zone} | S: {stat.section}
            </div>
            <div className="text-2xl font-black text-indigo-600">
              {stat.count}
            </div>
            <div className="text-[9px] text-slate-400 font-medium">Eleitores</div>
          </div>
        ))}
      </div>

      {sectionStats.length > 6 && (
        <div className="mt-4 pt-4 border-t border-slate-50 text-center">
          <p className="text-xs text-slate-400 italic">Total de {sectionStats.length} seções cadastradas</p>
        </div>
      )}
    </div>
  );
};

