import React, { useMemo } from 'react';
import { Voter } from '../types';
import { Trash2, Phone, MapPin, Mail, Calendar, Users, Edit3, Hash, Heart } from 'lucide-react';

interface Props {
  voters: Voter[];
  onDelete: (id: string) => void;
  onEdit: (voter: Voter) => void;
}

const VoterList: React.FC<Props> = ({ voters, onDelete, onEdit }) => {
  // Mapa de frequencia de seções
  const sectionCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    voters.forEach(v => {
      const key = `${v.votingZone}-${v.votingSection}`;
      counts[key] = (counts[key] || 0) + 1;
    });
    return counts;
  }, [voters]);

  if (voters.length === 0) {
    return (
      <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-300">
        <Users className="mx-auto text-slate-300 mb-4" size={48} />
