                        <span className="px-2 py-1 bg-slate-100 text-slate-600 text-[10px] font-bold rounded uppercase">S: {voter.votingSection}</span>
                      </div>
                      <div className="flex items-center gap-1 text-[10px] font-semibold text-indigo-500 bg-indigo-50/50 w-fit px-1.5 py-0.5 rounded">
