        </div>

        <div className="mt-4 px-3 space-y-1">
          <button 
            onClick={() => { setActiveTab('dashboard'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'dashboard' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </button>
          <button 
            onClick={() => { setActiveTab('list'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'list' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Users size={20} />
            Todos Eleitores
          </button>
          <button 
            onClick={() => { setActiveTab('family'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'family' ? 'bg-pink-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Heart size={20} className={activeTab === 'family' ? 'text-pink-300' : ''} />
            Minha Família
          </button>
          <button 
            onClick={() => { setActiveTab('help'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'help' ? 'bg-emerald-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
