import React, { useState, useMemo } from 'react';
import { Voter, HelpRecord } from '../types';
import { HandHelping, Search, Plus, Calendar, Trash2, FileText, User, ChevronRight } from 'lucide-react';

interface Props {
  voters: Voter[];
  onAddHelp: (voterId: string, record: Omit<HelpRecord, 'id'>) => void;
  onDeleteHelp: (voterId: string, recordId: string) => void;
  onExportHelp: (voter: Voter) => void;
  initialVoter: Voter | null;
}

const HelpManager: React.FC<Props> = ({ voters, onAddHelp, onDeleteHelp, onExportHelp, initialVoter }) => {
  const [selectedVoter, setSelectedVoter] = useState<Voter | null>(initialVoter);
  const [searchTerm, setSearchTerm] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('Social');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const filteredVoters = useMemo(() => {
    if (!searchTerm) return [];
    return voters.filter(v => v.name.toLowerCase().includes(searchTerm.toLowerCase())).slice(0, 5);
  }, [voters, searchTerm]);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedVoter || !description) return;

    onAddHelp(selectedVoter.id, {
      description,
      category,
      date
    });

    setDescription('');
    // Refresh selected voter from props if needed would be complex, better to rely on local update or parent update
    // For simplicity, we just clear the form. 
    alert("Ajuda registrada com sucesso!");
  };

  // Find the most updated voter data from the list
  const currentVoter = useMemo(() => {
    if (!selectedVoter) return null;
    return voters.find(v => v.id === selectedVoter.id) || null;
  }, [voters, selectedVoter]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Search and Selection */}
      <div className="lg:col-span-4 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Search size={18} className="text-indigo-600" />
            Buscar Eleitor
          </h3>
          <div className="relative">
            <input 
              type="text"
              placeholder="Digite o nome..."
              className="w-full pl-4 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          {filteredVoters.length > 0 && (
            <div className="mt-4 border border-slate-100 rounded-xl overflow-hidden divide-y divide-slate-50">
              {filteredVoters.map(v => (
                <button
                  key={v.id}
                  onClick={() => { setSelectedVoter(v); setSearchTerm(''); }}
                  className="w-full text-left p-3 hover:bg-indigo-50 flex items-center justify-between group transition-colors"
                >
                  <span className="text-sm font-medium text-slate-700">{v.name}</span>
                  <ChevronRight size={14} className="text-slate-300 group-hover:text-indigo-500" />
                </button>
              ))}
            </div>
          )}
        </div>

        {currentVoter && (
          <div className="bg-indigo-600 p-6 rounded-2xl shadow-lg text-white">
            <div className="flex items-center gap-3 mb-4">
              <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center font-bold text-xl">
                {currentVoter.name.charAt(0)}
              </div>
              <div>
                <h4 className="font-bold leading-tight">{currentVoter.name}</h4>
                <p className="text-xs text-indigo-100">{currentVoter.neighborhood}</p>
              </div>
            </div>
            <button 
              onClick={() => onExportHelp(currentVoter)}
              className="w-full py-3 bg-white/20 hover:bg-white/30 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-all"
            >
              <FileText size={16} /> Relatório de Ajudas (PDF)
            </button>
          </div>
        )}
      </div>

      {/* Forms and History */}
      <div className="lg:col-span-8 space-y-6">
        {!currentVoter ? (
          <div className="bg-white p-20 rounded-2xl border border-dashed border-slate-300 text-center flex flex-col items-center justify-center">
            <HandHelping size={64} className="text-slate-200 mb-4" />
            <h3 className="text-xl font-medium text-slate-400">Selecione um eleitor para gerenciar as ajudas</h3>
          </div>
        ) : (
          <>
            {/* New Help Form */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Plus size={18} className="text-emerald-600" />
                Registrar Nova Ajuda / Atendimento
              </h3>
              <form onSubmit={handleAdd} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Categoria</label>
                    <select 
                      value={category}
                      onChange={(e) => setCategory(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      <option>Social</option>
                      <option>Saúde</option>
                      <option>Jurídico</option>
                      <option>Documentação</option>
                      <option>Infraestrutura</option>
                      <option>Outros</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Data</label>
                    <input 
                      type="date"
                      value={date}
                      onChange={(e) => setDate(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Descrição do que foi feito</label>
                  <textarea 
                    rows={3}
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Ex: Auxílio na marcação de exame cardiológico no postinho."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full py-4 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100"
                >
                  Salvar Registro
                </button>
              </form>
            </div>

            {/* History List */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Calendar size={18} className="text-slate-400" />
                Histórico de Atendimentos
              </h3>

              {!currentVoter.helpRecords || currentVoter.helpRecords.length === 0 ? (
                <div className="py-10 text-center text-slate-400 italic">
                  Nenhuma ajuda registrada para este eleitor até o momento.
                </div>
              ) : (
                <div className="space-y-4">
                  {currentVoter.helpRecords.slice().reverse().map(record => (
                    <div key={record.id} className="p-4 bg-slate-50 rounded-xl border border-slate-100 flex justify-between items-start gap-4">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="px-2 py-0.5 bg-slate-200 text-slate-600 text-[10px] font-bold rounded uppercase tracking-wider">
                            {record.category}
                          </span>
                          <span className="text-[10px] text-slate-400 font-medium">
                            {new Date(record.date).toLocaleDateString('pt-BR')}
                          </span>
                        </div>
                        <p className="text-sm text-slate-700 leading-relaxed">
                          {record.description}
                        </p>
                      </div>
                      <button 
                        onClick={() => {
                          if (window.confirm("Remover este registro?")) {
                            onDeleteHelp(currentVoter.id, record.id);
                          }
                        }}
                        className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default HelpManager;

import { jsPDF } from "jspdf";
import "jspdf-autotable";
import { Voter } from "../types";

export function exportVotersToPDF(voters: Voter[]) {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4",
  });

  const now = new Date().toLocaleString("pt-BR");

  doc.setFontSize(18);
  doc.setTextColor(67, 56, 202);
  doc.text("Relatório Geral de Eleitores", 14, 15);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Gerado em: ${now}`, 14, 22);
  doc.text(`Total de registros: ${voters.length}`, 14, 27);

  const tableColumn = ["Nome", "Nascimento", "Telefone", "Bairro", "Zona", "Seção", "Família"];
  const tableRows = voters.map((voter) => [
    voter.name,
    new Date(voter.birthDate).toLocaleDateString('pt-BR'),
    voter.phone,
    voter.neighborhood,
    voter.votingZone,
    voter.votingSection,
    voter.isFamilyMember ? "Sim" : "Não"
  ]);

  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 35,
    theme: 'grid',
    headStyles: { fillColor: [67, 56, 202] },
    styles: { fontSize: 8 },
  });

  doc.save(`eleitores_${new Date().getTime()}.pdf`);
}

export function exportVoterHistoryPDF(voter: Voter) {
  const doc = new jsPDF();
  const now = new Date().toLocaleString("pt-BR");

  // Header
  doc.setFontSize(20);
  doc.setTextColor(67, 56, 202);
  doc.text("Relatório de Atendimento Individual", 14, 20);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Eleitor: ${voter.name}`, 14, 30);
  doc.text(`Bairro: ${voter.neighborhood}`, 14, 35);
  doc.text(`Telefone: ${voter.phone}`, 14, 40);
  doc.text(`Gerado em: ${now}`, 14, 45);

  // Line
  doc.setDrawColor(226, 232, 240);
  doc.line(14, 50, 196, 50);

  doc.setFontSize(14);
  doc.setTextColor(51, 65, 85);
  doc.text("Histórico de Ajudas e Atendimentos", 14, 60);

  if (!voter.helpRecords || voter.helpRecords.length === 0) {
    doc.setFontSize(12);
    doc.setTextColor(148, 163, 184);
    doc.text("Nenhum registro encontrado para este eleitor.", 14, 70);
  } else {
    const tableColumn = ["Data", "Categoria", "Descrição"];
    const tableRows = voter.helpRecords.map((record) => [
      new Date(record.date).toLocaleDateString('pt-BR'),
      record.category,
      record.description
    ]);

    (doc as any).autoTable({
      head: [tableColumn],
      body: tableRows,
      startY: 65,
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] }, // Emerald color
      styles: { fontSize: 10, cellPadding: 5 },
      columnStyles: {
        2: { cellWidth: 100 }
      }
    });
  }

  // Footer note
  const finalY = (doc as any).lastAutoTable?.finalY || 80;
  doc.setFontSize(8);
  doc.setTextColor(148, 163, 184);
  doc.text("Este documento é para fins de acompanhamento social e eleitoral interno.", 14, finalY + 10);

  doc.save(`historico_${voter.name.toLowerCase().replace(/\s+/g, '_')}.pdf`);
}

import React, { useMemo } from 'react';
import { Voter } from '../types';
import { Trash2, Phone, MapPin, Mail, Calendar, Users, Edit3, Hash, Heart, HandHelping } from 'lucide-react';

interface Props {
  voters: Voter[];
  onDelete: (id: string) => void;
  onEdit: (voter: Voter) => void;
  onManageHelp: (voter: Voter) => void;
}

const VoterList: React.FC<Props> = ({ voters, onDelete, onEdit, onManageHelp }) => {
  // Mapa de frequencia de seções
  const sectionCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    voters.forEach(v => {
      const key = `${v.votingZone}-${v.votingSection}`;
      counts[key] = (counts[key] || 0) + 1;
    });
    return counts;
  }, [voters]);

  if (voters.length === 0) {
    return (
      <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-300">
        <Users className="mx-auto text-slate-300 mb-4" size={48} />
        <h3 className="text-lg font-medium text-slate-600">Nenhum registro encontrado</h3>
        <p className="text-slate-400">Tente ajustar sua busca ou cadastre um novo eleitor.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-semibold">
            <tr>
              <th className="px-6 py-4">Eleitor</th>
              <th className="px-6 py-4">Localidade</th>
              <th className="px-6 py-4">Seção/Zona</th>
              <th className="px-6 py-4">Contato</th>
              <th className="px-6 py-4 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {voters.map((voter) => {
              const sectionKey = `${voter.votingZone}-${voter.votingSection}`;
              const countInSection = sectionCounts[sectionKey] || 1;
              const helpCount = voter.helpRecords?.length || 0;

              return (
                <tr key={voter.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className="font-bold text-slate-800">{voter.name}</div>
                      {voter.isFamilyMember && (
                        <span className="flex items-center gap-0.5 px-1.5 py-0.5 bg-pink-100 text-pink-600 text-[9px] font-black rounded-full uppercase tracking-tighter">
                          <Heart size={8} fill="currentColor" /> Família
