                        <span className="flex items-center gap-0.5 px-1.5 py-0.5 bg-emerald-100 text-emerald-600 text-[9px] font-black rounded-full uppercase tracking-tighter">
                           {helpCount} {helpCount === 1 ? 'Ajuda' : 'Ajudas'}
