                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm text-slate-600 flex items-center gap-1">
                      <MapPin size={14} className="text-slate-400" /> {voter.neighborhood}
                    </div>
                    <div className="text-xs text-slate-400 mt-1 truncate max-w-[200px]">{voter.address}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-1.5">
                      <div className="flex gap-2">
                        <span className="px-2 py-1 bg-indigo-50 text-indigo-700 text-[10px] font-bold rounded uppercase">Z: {voter.votingZone}</span>
                        <span className="px-2 py-1 bg-slate-100 text-slate-600 text-[10px] font-bold rounded uppercase">S: {voter.votingSection}</span>
                      </div>
                      <div className="flex items-center gap-1 text-[10px] font-semibold text-indigo-500 bg-indigo-50/50 w-fit px-1.5 py-0.5 rounded">
                        <Hash size={10} /> Total nesta Seção: {countInSection}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm text-slate-600 flex items-center gap-1">
                      <Phone size={14} className="text-slate-400" /> {voter.phone}
                    </div>
                    <div className="text-xs text-slate-400 flex items-center gap-1 mt-1">
                      <Mail size={12} className="text-slate-400" /> {voter.email || 'N/A'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end items-center gap-1">
                      <button 
                        onClick={() => onManageHelp(voter)}
                        className="p-2 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-all"
                        title="Gerenciar Ajudas"
                      >
                        <HandHelping size={18} />
                      </button>
                      <button 
                        onClick={() => onEdit(voter)}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                        title="Editar"
                      >
                        <Edit3 size={18} />
