export default VoterList;

import React, { useMemo } from 'react';
import { Voter } from '../types';
import { Users, UserCheck, MapPin, Calendar, Heart, HandHelping } from 'lucide-react';

interface Props {
  voters: Voter[];
}

const Dashboard: React.FC<Props> = ({ voters }) => {
  const stats = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    const birthdaysToday = voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === tMonth && parts[2] === tDay;
    }).length;

    const uniqueNeighborhoods = new Set(voters.map(v => v.neighborhood)).size;
    const familyMembers = voters.filter(v => v.isFamilyMember).length;

    let totalHelpCount = 0;
    voters.forEach(v => {
      totalHelpCount += (v.helpRecords?.length || 0);
    });

    return {
      total: voters.length,
      birthdays: birthdaysToday,
      neighborhoods: uniqueNeighborhoods,
      family: familyMembers,
      helps: totalHelpCount,
      recent: voters.filter(v => {
        const date = new Date(v.createdAt);
        const sevenDaysAgo = new Date();
        sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
        return date > sevenDaysAgo;
      }).length
    };
  }, [voters]);

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-6 gap-6">
      <StatCard 
        label="Total Eleitores" 
        value={stats.total} 
        icon={<Users className="text-blue-600" />} 
        bgColor="bg-blue-50"
      />
      <StatCard 
        label="Minha Família" 
        value={stats.family} 
        icon={<Heart className="text-pink-600" fill={stats.family > 0 ? "currentColor" : "none"} />} 
        bgColor="bg-pink-50"
      />
      <StatCard 
        label="Ajudas" 
        value={stats.helps} 
        icon={<HandHelping className="text-emerald-600" />} 
        bgColor="bg-emerald-50"
      />
      <StatCard 
        label="Aniversários" 
        value={stats.birthdays} 
        icon={<Calendar className="text-amber-600" />} 
        bgColor="bg-amber-50"
      />
      <StatCard 
        label="Bairros" 
        value={stats.neighborhoods} 
        icon={<MapPin className="text-indigo-600" />} 
        bgColor="bg-indigo-50"
      />
      <StatCard 
        label="Novos" 
        value={stats.recent} 
        icon={<UserCheck className="text-orange-600" />} 
        bgColor="bg-orange-50"
      />
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: number; icon: React.ReactNode; bgColor: string }> = ({ label, value, icon, bgColor }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-start justify-between">
    <div>
      <p className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">{label}</p>
      <p className="text-2xl font-bold mt-1">{value}</p>
    </div>
    <div className={`${bgColor} p-3 rounded-xl flex-shrink-0`}>
      {icon}
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import SectionSummary from './components/SectionSummary';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  Calendar, 
  LayoutDashboard, 
  Search,
  Bell,
  BarChart3,
  FileText,
  Heart,
  HandHelping
} from 'lucide-react';

const App: React.FC = () => {
  const [voters, setVoters] = useState<Voter[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  // Load data from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('voters_data');
    if (saved) {
      setVoters(JSON.parse(saved));
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;

    setVoters(prev => prev.map(v => 
      v.id === editingVoter.id ? { ...v, ...data } : v
    ));
    setEditingVoter(null);
    setActiveTab(data.isFamilyMember ? 'family' : 'list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const startEditing = (voter: Voter) => {
    setEditingVoter(voter);
    setActiveTab('edit');
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => {
      if (v.id === voterId) {
        return {
          ...v,
          helpRecords: [...(v.helpRecords || []), newRecord]
        };
      }
      return v;
    }));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => {
      if (v.id === voterId) {
        return {
          ...v,
          helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId)
        };
      }
      return v;
    }));
  };

  const handleExportPDF = () => {
    const targetVoters = activeTab === 'family' ? voters.filter(v => v.isFamilyMember) : voters;
    if (targetVoters.length === 0) {
      alert("Não há eleitores para exportar nesta categoria.");
      return;
    }
    exportVotersToPDF(targetVoters);
  };

  const filteredVoters = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') {
      list = list.filter(v => v.isFamilyMember);
    }

    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.phone.includes(searchTerm)
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      if (parts.length !== 3) return false;
      const [, vMonth, vDay] = parts;
      return vMonth === tMonth && vDay === tDay;
    });
  }, [voters]);

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar - Desktop */}
      <nav className="w-full md:w-64 bg-indigo-900 text-white flex-shrink-0">
        <div className="p-6">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Users className="text-indigo-300" />
            Gestão de Eleitores
          </h1>
          <p className="text-indigo-300 text-xs mt-1">Sua base, seu futuro.</p>
        </div>

        <div className="mt-4 px-3 space-y-1">
          <button 
            onClick={() => { setActiveTab('dashboard'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'dashboard' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </button>
          <button 
            onClick={() => { setActiveTab('list'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'list' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Users size={20} />
            Todos Eleitores
          </button>
          <button 
            onClick={() => { setActiveTab('family'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'family' ? 'bg-pink-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Heart size={20} className={activeTab === 'family' ? 'text-pink-300' : ''} />
            Minha Família
          </button>
          <button 
            onClick={() => { setActiveTab('help'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'help' ? 'bg-emerald-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <HandHelping size={20} className={activeTab === 'help' ? 'text-emerald-300' : ''} />
            Ajudas Prestadas
          </button>
          <button 
            onClick={() => { setActiveTab('add'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'add' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <UserPlus size={20} />
            Cadastrar Novo
          </button>
        </div>

        {/* Quick Stats Sidebar */}
        <div className="mt-auto p-6 hidden md:block">
          <div className="bg-indigo-800 rounded-xl p-4 border border-indigo-700">
            <p className="text-indigo-300 text-sm">Total Geral</p>
            <p className="text-3xl font-bold">{voters.length}</p>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-slate-50">
        {/* Header */}
        <header className="sticky top-0 z-10 bg-white border-b border-slate-200 px-6 py-4 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="relative w-full sm:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar por nome, bairro ou telefone..."
              className="w-full pl-10 pr-4 py-2 bg-slate-100 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500 rounded-lg outline-none transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-4">
            <div className="relative">
              <Bell className="text-slate-600 cursor-pointer" />
              {birthdayVoters.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">
                  {birthdayVoters.length}
                </span>
              )}
            </div>
            <div className="h-8 w-8 rounded-full bg-indigo-500 flex items-center justify-center text-white font-medium">
              A
            </div>
          </div>
        </header>

        <div className="p-6">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <Dashboard voters={voters} />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
                <div className="lg:col-span-7 space-y-6">
                  <NeighborhoodChart voters={voters} />
                  <SectionSummary voters={voters} />
                </div>

                <div className="lg:col-span-5 space-y-6">
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                     <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                       <BarChart3 size={18} className="text-indigo-600" />
                       Ações Rápidas
                     </h3>
                     <div className="grid grid-cols-1 gap-3">
                       <button 
                        onClick={() => setActiveTab('add')}
                        className="flex items-center justify-center gap-2 py-3 px-4 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors font-medium"
                       >
                         <UserPlus size={18} /> Novo Eleitor
                       </button>
                       <button 
                        onClick={handleExportPDF}
                        className="flex items-center justify-center gap-2 py-3 px-4 bg-white border border-slate-200 text-slate-700 rounded-xl hover:bg-slate-50 transition-colors font-medium"
                       >
                         <FileText size={18} className="text-red-500" /> Exportar PDF ({activeTab === 'family' ? 'Família' : 'Geral'})
                       </button>
                     </div>
                   </div>

                   <div>
                      <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                        <Calendar className="text-indigo-600" /> Aniversariantes do Mês
                      </h2>
                      <BirthdayWidget voters={voters} />
                   </div>
                </div>
              </div>
            </div>
          )}

          {(activeTab === 'list' || activeTab === 'family') && (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800">
                  {activeTab === 'family' ? 'Membros da Família' : 'Listagem Geral de Eleitores'}
                </h2>
                <div className="flex gap-2">
                  <button 
                    onClick={handleExportPDF}
                    className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-all text-sm font-bold shadow-sm"
                  >
                    <FileText size={16} className="text-red-500" /> Exportar Lista
                  </button>
                </div>
              </div>
              <VoterList voters={filteredVoters} onDelete={deleteVoter} onEdit={startEditing} onManageHelp={(v) => {
                setEditingVoter(v);
                setActiveTab('help');
              }} />
            </div>
          )}

          {activeTab === 'help' && (
            <HelpManager 
              voters={voters} 
              onAddHelp={addHelpRecord} 
              onDeleteHelp={deleteHelpRecord}
              onExportHelp={exportVoterHistoryPDF}
              initialVoter={editingVoter}
            />
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="max-w-3xl mx-auto">
              <VoterForm 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => { setActiveTab('list'); setEditingVoter(null); }} 
                initialData={editingVoter || undefined}
              />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

{
  "name": "Gestão de Eleitores",
  "description": "A comprehensive voter management tool with birthday tracking and AI-powered personalized messaging using Gemini.",
  "requestFramePermissions": []
}

export interface HelpRecord {
  id: string;
  description: string;
  date: string;
  category: string;
  value: number; // Novo: Valor financeiro da ajuda
}

export interface Voter {
  id: string;
  name: string;
  birthDate: string; // ISO string YYYY-MM-DD
  phone: string;
  email: string;
  address: string;
  neighborhood: string;
  votingZone: string;
  votingSection: string;
  observations: string;
  isFamilyMember: boolean;
  helpRecords?: HelpRecord[];
  createdAt: string;
}

export interface VoterFormData extends Omit<Voter, 'id' | 'createdAt' | 'helpRecords'> {}

export interface BirthdaySummary {
  voter: Voter;
  isToday: boolean;
}

import React, { useState, useMemo } from 'react';
import { Voter, HelpRecord } from '../types';
import { HandHelping, Search, Plus, Calendar, Trash2, FileText, ChevronRight, DollarSign, PieChart, TrendingUp } from 'lucide-react';

interface Props {
  voters: Voter[];
  onAddHelp: (voterId: string, record: Omit<HelpRecord, 'id'>) => void;
  onDeleteHelp: (voterId: string, recordId: string) => void;
  onExportHelp: (voter: Voter) => void;
  initialVoter: Voter | null;
}

const HelpManager: React.FC<Props> = ({ voters, onAddHelp, onDeleteHelp, onExportHelp, initialVoter }) => {
  const [selectedVoter, setSelectedVoter] = useState<Voter | null>(initialVoter);
  const [searchTerm, setSearchTerm] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('Social');
  const [value, setValue] = useState<string>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const filteredVoters = useMemo(() => {
    if (!searchTerm) return [];
    return voters.filter(v => v.name.toLowerCase().includes(searchTerm.toLowerCase())).slice(0, 5);
  }, [voters, searchTerm]);

  // Cálculos financeiros por mês
  const monthlyStats = useMemo(() => {
    const stats: Record<string, number> = {};
    voters.forEach(v => {
      v.helpRecords?.forEach(record => {
        const d = new Date(record.date);
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        stats[key] = (stats[key] || 0) + (record.value || 0);
      });
    });

    return Object.entries(stats)
      .map(([month, total]) => ({ month, total }))
      .sort((a, b) => b.month.localeCompare(a.month));
  }, [voters]);

  const currentMonthKey = useMemo(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  }, []);

  const totalSpentThisMonth = useMemo(() => {
    return monthlyStats.find(s => s.month === currentMonthKey)?.total || 0;
  }, [monthlyStats, currentMonthKey]);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedVoter || !description) return;

    onAddHelp(selectedVoter.id, {
      description,
      category,
      date,
      value: parseFloat(value) || 0
    });

    setDescription('');
    setValue('');
    alert("Atendimento financeiro registrado!");
  };

  const currentVoter = useMemo(() => {
    if (!selectedVoter) return null;
    return voters.find(v => v.id === selectedVoter.id) || null;
  }, [voters, selectedVoter]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const formatMonth = (monthKey: string) => {
    const [year, month] = monthKey.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1);
    return date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Sidebar: Search & Monthly Report */}
      <div className="lg:col-span-4 space-y-6">
        {/* Monthly Summary Card */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 overflow-hidden relative">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <TrendingUp size={80} />
          </div>
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <PieChart size={18} className="text-indigo-600" />
            Gastos do Mês Atual
          </h3>
          <p className="text-3xl font-black text-indigo-600">{formatCurrency(totalSpentThisMonth)}</p>
          <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-wider">Investimento em assistência</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Search size={18} className="text-indigo-600" />
            Selecionar Eleitor
          </h3>
          <input 
            type="text"
            placeholder="Buscar para registrar ajuda..."
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />

          {filteredVoters.length > 0 && (
            <div className="mt-4 border border-slate-100 rounded-xl overflow-hidden divide-y divide-slate-50 shadow-sm">
              {filteredVoters.map(v => (
                <button
                  key={v.id}
                  onClick={() => { setSelectedVoter(v); setSearchTerm(''); }}
                  className="w-full text-left p-3 hover:bg-indigo-50 flex items-center justify-between group transition-colors"
                >
                  <span className="text-sm font-medium text-slate-700">{v.name}</span>
                  <ChevronRight size={14} className="text-slate-300 group-hover:text-indigo-500" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Historical Monthly Totals */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <DollarSign size={18} className="text-emerald-600" />
            Balanço por Mês
          </h3>
          <div className="space-y-3">
            {monthlyStats.length === 0 ? (
              <p className="text-sm text-slate-400 italic">Nenhum gasto registrado.</p>
            ) : (
              monthlyStats.map(stat => (
                <div key={stat.month} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-500 capitalize">{formatMonth(stat.month)}</span>
                  <span className="text-sm font-black text-slate-700">{formatCurrency(stat.total)}</span>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {/* Main Column: Register & History */}
      <div className="lg:col-span-8 space-y-6">
        {!currentVoter ? (
          <div className="bg-white p-20 rounded-2xl border border-dashed border-slate-300 text-center flex flex-col items-center justify-center">
            <HandHelping size={64} className="text-slate-200 mb-4" />
            <h3 className="text-xl font-medium text-slate-400">Escolha um eleitor na busca para registrar uma ajuda financeira</h3>
          </div>
        ) : (
          <>
            {/* New Help Form with Value */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-bold text-slate-800 flex items-center gap-2">
                  <Plus size={18} className="text-emerald-600" />
                  Registrar Atendimento para: <span className="text-indigo-600">{currentVoter.name}</span>
                </h3>
                <button 
                  onClick={() => onExportHelp(currentVoter)}
                  className="text-xs font-bold text-indigo-600 flex items-center gap-1 hover:underline"
                >
                  <FileText size={14} /> Relatório Individual
                </button>
              </div>

              <form onSubmit={handleAdd} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Categoria</label>
                    <select 
                      value={category}
                      onChange={(e) => setCategory(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      <option>Saúde (Remédios/Exames)</option>
                      <option>Social (Cestas/Auxílio)</option>
                      <option>Jurídico</option>
                      <option>Documentação</option>
                      <option>Infraestrutura</option>
                      <option>Outros</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Valor Gasto (R$)</label>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-sm">R$</span>
                      <input 
                        type="number"
                        step="0.01"
                        value={value}
                        onChange={(e) => setValue(e.target.value)}
                        placeholder="0,00"
                        className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Data</label>
                    <input 
                      type="date"
                      value={date}
                      onChange={(e) => setDate(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Descrição Detalhada</label>
                  <textarea 
                    rows={3}
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="O que foi feito ou entregue para este eleitor?"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full py-4 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100"
                >
                  Salvar Registro de Gasto
                </button>
              </form>
            </div>

            {/* History List with Values */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Calendar size={18} className="text-slate-400" />
                Histórico de Investimentos neste Eleitor
              </h3>

              {!currentVoter.helpRecords || currentVoter.helpRecords.length === 0 ? (
                <div className="py-10 text-center text-slate-400 italic">
                  Nenhuma ajuda financeira registrada ainda.
                </div>
              ) : (
                <div className="space-y-4">
                  {currentVoter.helpRecords.slice().reverse().map(record => (
                    <div key={record.id} className="p-4 bg-slate-50 rounded-xl border border-slate-100 flex justify-between items-start gap-4">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="px-2 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-bold rounded uppercase tracking-wider">
                            {record.category}
                          </span>
                          <span className="text-[10px] text-slate-400 font-medium">
                            {new Date(record.date).toLocaleDateString('pt-BR')}
                          </span>
                          <span className="ml-auto font-black text-emerald-600 text-sm">
                            {formatCurrency(record.value || 0)}
                          </span>
                        </div>
                        <p className="text-sm text-slate-700 leading-relaxed mt-2">
                          {record.description}
                        </p>
                      </div>
                      <button 
                        onClick={() => onDeleteHelp(currentVoter.id, record.id)}
                        className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all self-center"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}

                  <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
                    <span className="text-sm font-bold text-slate-500 uppercase">Total Acumulado com {currentVoter.name.split(' ')[0]}:</span>
                    <span className="text-xl font-black text-slate-800">
                      {formatCurrency(currentVoter.helpRecords.reduce((acc, curr) => acc + (curr.value || 0), 0))}
                    </span>
                  </div>
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default HelpManager;

import React, { useMemo } from 'react';
import { Voter } from '../types';
import { Users, UserCheck, MapPin, Calendar, Heart, HandHelping, DollarSign } from 'lucide-react';

interface Props {
  voters: Voter[];
}

const Dashboard: React.FC<Props> = ({ voters }) => {
  const stats = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    const birthdaysToday = voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === tMonth && parts[2] === tDay;
    }).length;

    const uniqueNeighborhoods = new Set(voters.map(v => v.neighborhood)).size;
    const familyMembers = voters.filter(v => v.isFamilyMember).length;

    let totalHelpCount = 0;
    let totalValue = 0;
    voters.forEach(v => {
      v.helpRecords?.forEach(r => {
        totalHelpCount++;
        totalValue += (r.value || 0);
      });
    });

    return {
      total: voters.length,
      birthdays: birthdaysToday,
      neighborhoods: uniqueNeighborhoods,
      family: familyMembers,
      helps: totalHelpCount,
      totalInvested: totalValue,
      recent: voters.filter(v => {
        const date = new Date(v.createdAt);
        const sevenDaysAgo = new Date();
        sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
        return date > sevenDaysAgo;
      }).length
    };
  }, [voters]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Total Eleitores" 
          value={stats.total.toString()} 
          icon={<Users className="text-blue-600" />} 
          bgColor="bg-blue-50"
        />
        <StatCard 
          label="Investimento Total" 
          value={formatCurrency(stats.totalInvested)} 
          icon={<DollarSign className="text-emerald-600" />} 
          bgColor="bg-emerald-50"
        />
        <StatCard 
          label="Ajudas Prestadas" 
          value={stats.helps.toString()} 
          icon={<HandHelping className="text-indigo-600" />} 
          bgColor="bg-indigo-50"
        />
         <StatCard 
          label="Minha Família" 
          value={stats.family.toString()} 
          icon={<Heart className="text-pink-600" fill={stats.family > 0 ? "currentColor" : "none"} />} 
          bgColor="bg-pink-50"
        />
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
        <StatCardSmall 
          label="Aniversários Hoje" 
          value={stats.birthdays} 
          icon={<Calendar size={16} className="text-amber-600" />} 
        />
        <StatCardSmall 
          label="Bairros Atendidos" 
          value={stats.neighborhoods} 
          icon={<MapPin size={16} className="text-slate-600" />} 
        />
        <StatCardSmall 
          label="Novos (7 dias)" 
          value={stats.recent} 
          icon={<UserCheck size={16} className="text-orange-600" />} 
        />
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: React.ReactNode; bgColor: string }> = ({ label, value, icon, bgColor }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-start justify-between">
    <div>
      <p className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">{label}</p>
      <p className="text-2xl font-black mt-1 text-slate-800">{value}</p>
    </div>
    <div className={`${bgColor} p-3 rounded-xl flex-shrink-0`}>
      {icon}
    </div>
  </div>
);

const StatCardSmall: React.FC<{ label: string; value: number; icon: React.ReactNode }> = ({ label, value, icon }) => (
  <div className="bg-white px-4 py-3 rounded-xl shadow-sm border border-slate-100 flex items-center gap-3">
    <div className="p-2 bg-slate-50 rounded-lg">{icon}</div>
    <div>
      <p className="text-slate-400 text-[9px] font-bold uppercase tracking-tight">{label}</p>
