export default Dashboard;

import { jsPDF } from "jspdf";
import "jspdf-autotable";
import { Voter } from "../types";

export function exportVotersToPDF(voters: Voter[]) {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4",
  });

  const now = new Date().toLocaleString("pt-BR");

  doc.setFontSize(18);
  doc.setTextColor(67, 56, 202);
  doc.text("Relatório Geral de Eleitores", 14, 15);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Gerado em: ${now}`, 14, 22);
  doc.text(`Total de registros: ${voters.length}`, 14, 27);

  const tableColumn = ["Nome", "Nascimento", "Telefone", "Bairro", "Zona", "Seção", "Família"];
  const tableRows = voters.map((voter) => [
    voter.name,
    new Date(voter.birthDate).toLocaleDateString('pt-BR'),
    voter.phone,
    voter.neighborhood,
    voter.votingZone,
    voter.votingSection,
    voter.isFamilyMember ? "Sim" : "Não"
  ]);

  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 35,
    theme: 'grid',
    headStyles: { fillColor: [67, 56, 202] },
    styles: { fontSize: 8 },
  });

  doc.save(`eleitores_${new Date().getTime()}.pdf`);
}

export function exportVoterHistoryPDF(voter: Voter) {
  const doc = new jsPDF();
  const now = new Date().toLocaleString("pt-BR");
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  // Header
  doc.setFontSize(20);
  doc.setTextColor(67, 56, 202);
  doc.text("Relatório de Atendimento Individual", 14, 20);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Eleitor: ${voter.name}`, 14, 30);
  doc.text(`Bairro: ${voter.neighborhood}`, 14, 35);
  doc.text(`Telefone: ${voter.phone}`, 14, 40);
  doc.text(`Gerado em: ${now}`, 14, 45);

  // Line
  doc.setDrawColor(226, 232, 240);
  doc.line(14, 50, 196, 50);

  doc.setFontSize(14);
  doc.setTextColor(51, 65, 85);
  doc.text("Histórico de Ajudas e Atendimentos", 14, 60);

  if (!voter.helpRecords || voter.helpRecords.length === 0) {
    doc.setFontSize(12);
    doc.setTextColor(148, 163, 184);
    doc.text("Nenhum registro encontrado para este eleitor.", 14, 70);
  } else {
    const totalSpent = voter.helpRecords.reduce((acc, curr) => acc + (curr.value || 0), 0);
    const tableColumn = ["Data", "Categoria", "Valor", "Descrição"];
    const tableRows = voter.helpRecords.map((record) => [
      new Date(record.date).toLocaleDateString('pt-BR'),
      record.category,
      formatCurrency(record.value || 0),
      record.description
    ]);

    (doc as any).autoTable({
      head: [tableColumn],
      body: tableRows,
      startY: 65,
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] }, // Emerald color
      styles: { fontSize: 9, cellPadding: 4 },
      columnStyles: {
        2: { fontStyle: 'bold' },
        3: { cellWidth: 80 }
      }
    });

    const finalY = (doc as any).lastAutoTable?.finalY || 80;
    doc.setFontSize(12);
    doc.setTextColor(51, 65, 85);
    doc.setFont("helvetica", "bold");
    doc.text(`TOTAL INVESTIDO NESTE ELEITOR: ${formatCurrency(totalSpent)}`, 14, finalY + 10);
  }

  // Footer note
  const lastY = (doc as any).lastAutoTable?.finalY || 80;
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(148, 163, 184);
  doc.text("Este documento é para fins de acompanhamento social e eleitoral interno.", 14, lastY + 20);

  doc.save(`historico_${voter.name.toLowerCase().replace(/\s+/g, '_')}.pdf`);
}

export interface HelpRecord {
  id: string;
  description: string;
  date: string;
  category: string;
  value: number;
}

export interface Voter {
  id: string;
  name: string;
  birthDate: string; // ISO string YYYY-MM-DD
  phone: string;
  email: string;
  address: string;
  neighborhood: string;
  observations: string;
  isFamilyMember: boolean;
  helpRecords?: HelpRecord[];
  createdAt: string;
}

export interface VoterFormData extends Omit<Voter, 'id' | 'createdAt' | 'helpRecords'> {}

export interface BirthdaySummary {
  voter: Voter;
  isToday: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  Calendar, 
  LayoutDashboard, 
  Search,
  Bell,
  BarChart3,
  FileText,
  Heart,
  HandHelping,
  Lock,
  LogIn
} from 'lucide-react';

const ACCESS_PASSWORD = 'admin'; // Senha única de acesso

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [voters, setVoters] = useState<Voter[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  // Load data from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('voters_data');
    if (saved) {
      setVoters(JSON.parse(saved));
    }

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    sessionStorage.removeItem('is_authenticated');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;

    setVoters(prev => prev.map(v => 
      v.id === editingVoter.id ? { ...v, ...data } : v
    ));
    setEditingVoter(null);
    setActiveTab(data.isFamilyMember ? 'family' : 'list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const startEditing = (voter: Voter) => {
    setEditingVoter(voter);
    setActiveTab('edit');
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => {
      if (v.id === voterId) {
        return {
          ...v,
          helpRecords: [...(v.helpRecords || []), newRecord]
        };
      }
      return v;
    }));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => {
      if (v.id === voterId) {
        return {
          ...v,
          helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId)
        };
      }
      return v;
    }));
  };

  const handleExportPDF = () => {
    const targetVoters = activeTab === 'family' ? voters.filter(v => v.isFamilyMember) : voters;
    if (targetVoters.length === 0) {
      alert("Não há eleitores para exportar nesta categoria.");
      return;
    }
    exportVotersToPDF(targetVoters);
  };

  const filteredVoters = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') {
      list = list.filter(v => v.isFamilyMember);
    }

    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.phone.includes(searchTerm)
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      if (parts.length !== 3) return false;
      const [, vMonth, vDay] = parts;
      return vMonth === tMonth && vDay === tDay;
    });
  }, [voters]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden">
          <div className="bg-indigo-900 p-8 text-center text-white">
            <div className="w-20 h-20 bg-indigo-800 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-indigo-700">
              <Lock size={40} className="text-indigo-300" />
            </div>
            <h1 className="text-2xl font-bold">Acesso Restrito</h1>
            <p className="text-indigo-300 text-sm mt-2">Gestão de Eleitores</p>
          </div>
          <form onSubmit={handleLogin} className="p-8 space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Senha de Acesso</label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full px-4 py-4 bg-slate-50 border ${loginError ? 'border-red-500' : 'border-slate-200'} rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-center text-xl font-bold tracking-widest`}
                  placeholder="••••••"
                  autoFocus
                />
              </div>
              {loginError && <p className="text-red-500 text-xs mt-2 text-center font-bold">Senha incorreta. Tente novamente.</p>}
            </div>
            <button 
              type="submit"
              className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-100"
            >
              <LogIn size={20} /> Entrar no Sistema
            </button>
            <p className="text-center text-[10px] text-slate-400 uppercase tracking-widest">Acesso protegido por criptografia</p>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar - Desktop */}
      <nav className="w-full md:w-64 bg-indigo-900 text-white flex-shrink-0">
        <div className="p-6">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Users className="text-indigo-300" />
            Gestão de Eleitores
          </h1>
          <p className="text-indigo-300 text-xs mt-1">Sua base, seu futuro.</p>
        </div>

        <div className="mt-4 px-3 space-y-1">
          <button 
            onClick={() => { setActiveTab('dashboard'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'dashboard' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </button>
          <button 
            onClick={() => { setActiveTab('list'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'list' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Users size={20} />
            Todos Eleitores
          </button>
          <button 
            onClick={() => { setActiveTab('family'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'family' ? 'bg-pink-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <Heart size={20} className={activeTab === 'family' ? 'text-pink-300' : ''} />
            Minha Família
          </button>
          <button 
            onClick={() => { setActiveTab('help'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'help' ? 'bg-emerald-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <HandHelping size={20} className={activeTab === 'help' ? 'text-emerald-300' : ''} />
            Ajudas Prestadas
          </button>
          <button 
            onClick={() => { setActiveTab('add'); setEditingVoter(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === 'add' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}
          >
            <UserPlus size={20} />
            Cadastrar Novo
          </button>
        </div>

        {/* Quick Stats Sidebar */}
        <div className="mt-auto p-6 hidden md:block">
          <div className="bg-indigo-800 rounded-xl p-4 border border-indigo-700">
            <p className="text-indigo-300 text-sm">Total Geral</p>
            <p className="text-3xl font-bold">{voters.length}</p>
          </div>
          <button 
            onClick={handleLogout}
            className="w-full mt-4 flex items-center justify-center gap-2 py-2 text-indigo-300 hover:text-white text-xs font-bold uppercase tracking-wider transition-colors"
          >
            Sair do Sistema
          </button>
