      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-slate-50">
        {/* Header */}
        <header className="sticky top-0 z-10 bg-white border-b border-slate-200 px-6 py-4 flex flex-col sm:flex-row justify-between items-center gap-4">
