              onAddHelp={addHelpRecord} 
              onDeleteHelp={deleteHelpRecord}
              onExportHelp={exportVoterHistoryPDF}
              initialVoter={editingVoter}
            />
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="max-w-3xl mx-auto">
              <VoterForm 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => { setActiveTab('list'); setEditingVoter(null); }} 
                initialData={editingVoter || undefined}
              />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

