  Lock,
  LogIn,
  Eye,
  EyeOff
} from 'lucide-react';

const ACCESS_PASSWORD = '20257530'; // Senha exclusiva gerada

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [voters, setVoters] = useState<Voter[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  // Load data from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('voters_data');
    if (saved) {
      setVoters(JSON.parse(saved));
    }

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  // Save data to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    sessionStorage.removeItem('is_authenticated');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;

    setVoters(prev => prev.map(v => 
      v.id === editingVoter.id ? { ...v, ...data } : v
    ));
    setEditingVoter(null);
    setActiveTab(data.isFamilyMember ? 'family' : 'list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const startEditing = (voter: Voter) => {
    setEditingVoter(voter);
    setActiveTab('edit');
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => {
      if (v.id === voterId) {
        return {
          ...v,
          helpRecords: [...(v.helpRecords || []), newRecord]
        };
      }
      return v;
    }));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => {
      if (v.id === voterId) {
        return {
          ...v,
          helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId)
        };
      }
      return v;
    }));
  };

  const handleExportPDF = () => {
    const targetVoters = activeTab === 'family' ? voters.filter(v => v.isFamilyMember) : voters;
    if (targetVoters.length === 0) {
      alert("Não há eleitores para exportar nesta categoria.");
      return;
    }
    exportVotersToPDF(targetVoters);
  };

  const filteredVoters = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') {
      list = list.filter(v => v.isFamilyMember);
    }

    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.phone.includes(searchTerm)
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      if (parts.length !== 3) return false;
      const [, vMonth, vDay] = parts;
      return vMonth === tMonth && vDay === tDay;
    });
  }, [voters]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden transform transition-all">
          <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 p-10 text-center text-white relative overflow-hidden">
            <div className="absolute top-[-20px] right-[-20px] w-40 h-40 bg-white/5 rounded-full blur-3xl"></div>
            <div className="w-24 h-24 bg-white/10 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-white/20 backdrop-blur-sm rotate-3 shadow-inner">
              <Lock size={48} className="text-indigo-200 -rotate-3" />
            </div>
            <h1 className="text-3xl font-black tracking-tight">Portal Seguro</h1>
            <p className="text-indigo-200/80 text-sm mt-2 font-medium">Gestão de Eleitores v2.5</p>
          </div>
          <form onSubmit={handleLogin} className="p-10 space-y-8 bg-white">
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 px-1">Credencial de Acesso</label>
              <div className="relative group">
                <input 
                  type={showPassword ? "text" : "password"} 
