import { jsPDF } from "jspdf";
import "jspdf-autotable";
import { Voter } from "../types";

export function exportVotersToPDF(voters: Voter[]) {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4",
  });

  const now = new Date().toLocaleString("pt-BR");

  doc.setFontSize(18);
  doc.setTextColor(67, 56, 202);
  doc.text("Relatório Geral de Eleitores", 14, 15);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Gerado em: ${now}`, 14, 22);
  doc.text(`Total de registros: ${voters.length}`, 14, 27);

  const tableColumn = ["Nome", "Nascimento", "Telefone", "Bairro", "Endereço", "Família"];
  const tableRows = voters.map((voter) => [
    voter.name,
    new Date(voter.birthDate).toLocaleDateString('pt-BR'),
    voter.phone,
    voter.neighborhood,
    voter.address,
    voter.isFamilyMember ? "Sim" : "Não"
  ]);

  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 35,
    theme: 'grid',
    headStyles: { fillColor: [67, 56, 202] },
    styles: { fontSize: 8 },
  });

  doc.save(`eleitores_${new Date().getTime()}.pdf`);
}

export function exportVoterHistoryPDF(voter: Voter) {
  const doc = new jsPDF();
  const now = new Date().toLocaleString("pt-BR");
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  // Header
  doc.setFontSize(20);
  doc.setTextColor(67, 56, 202);
  doc.text("Relatório de Atendimento Individual", 14, 20);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Eleitor: ${voter.name}`, 14, 30);
  doc.text(`Bairro: ${voter.neighborhood}`, 14, 35);
  doc.text(`Telefone: ${voter.phone}`, 14, 40);
  doc.text(`Gerado em: ${now}`, 14, 45);

  // Line
  doc.setDrawColor(226, 232, 240);
  doc.line(14, 50, 196, 50);

  doc.setFontSize(14);
  doc.setTextColor(51, 65, 85);
  doc.text("Histórico de Ajudas e Atendimentos", 14, 60);

  if (!voter.helpRecords || voter.helpRecords.length === 0) {
    doc.setFontSize(12);
    doc.setTextColor(148, 163, 184);
    doc.text("Nenhum registro encontrado para este eleitor.", 14, 70);
  } else {
    const totalSpent = voter.helpRecords.reduce((acc, curr) => acc + (curr.value || 0), 0);
    const tableColumn = ["Data", "Categoria", "Valor", "Descrição"];
    const tableRows = voter.helpRecords.map((record) => [
      new Date(record.date).toLocaleDateString('pt-BR'),
      record.category,
      formatCurrency(record.value || 0),
      record.description
    ]);

    (doc as any).autoTable({
      head: [tableColumn],
      body: tableRows,
      startY: 65,
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] }, // Emerald color
      styles: { fontSize: 9, cellPadding: 4 },
      columnStyles: {
        2: { fontStyle: 'bold' },
        3: { cellWidth: 80 }
      }
    });

    const finalY = (doc as any).lastAutoTable?.finalY || 80;
    doc.setFontSize(12);
    doc.setTextColor(51, 65, 85);
    doc.setFont("helvetica", "bold");
    doc.text(`TOTAL INVESTIDO NESTE ELEITOR: ${formatCurrency(totalSpent)}`, 14, finalY + 10);
  }

  // Footer note
  const lastY = (doc as any).lastAutoTable?.finalY || 80;
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(148, 163, 184);
  doc.text("Este documento é para fins de acompanhamento social e eleitoral interno.", 14, lastY + 20);

  doc.save(`historico_${voter.name.toLowerCase().replace(/\s+/g, '_')}.pdf`);
}

export function exportMonthlyFinancialReportPDF(voters: Voter[]) {
  const doc = new jsPDF();
  const now = new Date().toLocaleString("pt-BR");
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  // Process data for the report
  const stats: Record<string, number> = {};
  let totalOverall = 0;

  voters.forEach(v => {
    v.helpRecords?.forEach(record => {
      const d = new Date(record.date);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      const value = record.value || 0;
      stats[key] = (stats[key] || 0) + value;
      totalOverall += value;
    });
  });

  const sortedStats = Object.entries(stats)
    .map(([month, total]) => ({ month, total }))
    .sort((a, b) => b.month.localeCompare(a.month));

  // PDF Content
  doc.setFontSize(22);
  doc.setTextColor(16, 185, 129); // Emerald
  doc.text("Balanço Financeiro Mensal", 14, 20);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text("Consolidado de investimentos em assistência aos eleitores", 14, 28);
  doc.text(`Data de geração: ${now}`, 14, 33);

  doc.setDrawColor(241, 245, 249);
  doc.line(14, 40, 196, 40);

  if (sortedStats.length === 0) {
    doc.setFontSize(12);
    doc.text("Nenhum gasto financeiro registrado no sistema.", 14, 55);
  } else {
    const tableColumn = ["Período (Mês/Ano)", "Total Investido (R$)"];
    const tableRows = sortedStats.map(stat => {
      const [year, month] = stat.month.split('-');
      const date = new Date(parseInt(year), parseInt(month) - 1);
      const monthLabel = date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
      return [
        monthLabel.charAt(0).toUpperCase() + monthLabel.slice(1),
        formatCurrency(stat.total)
      ];
    });

    (doc as any).autoTable({
      head: [tableColumn],
      body: tableRows,
      startY: 45,
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] },
      styles: { fontSize: 11, cellPadding: 6 },
      columnStyles: {
        1: { halign: 'right', fontStyle: 'bold' }
      }
    });

    const finalY = (doc as any).lastAutoTable?.finalY || 60;

    // Summary Box
    doc.setFillColor(248, 250, 252);
    doc.roundedRect(14, finalY + 10, 182, 25, 3, 3, 'F');

    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139);
    doc.setFont("helvetica", "bold");
    doc.text("INVESTIMENTO TOTAL ACUMULADO", 20, finalY + 20);

    doc.setFontSize(16);
    doc.setTextColor(30, 41, 59);
    doc.text(formatCurrency(totalOverall), 20, finalY + 30);
  }

  doc.save(`balanco_financeiro_${new Date().getTime()}.pdf`);
}

import React, { useState, useMemo } from 'react';
import { Voter, HelpRecord } from '../types';
import { exportMonthlyFinancialReportPDF } from '../services/pdf';
import { HandHelping, Search, Plus, Calendar, Trash2, FileText, ChevronRight, DollarSign, PieChart, TrendingUp, Download } from 'lucide-react';

interface Props {
  voters: Voter[];
  onAddHelp: (voterId: string, record: Omit<HelpRecord, 'id'>) => void;
  onDeleteHelp: (voterId: string, recordId: string) => void;
  onExportHelp: (voter: Voter) => void;
  initialVoter: Voter | null;
}

const HelpManager: React.FC<Props> = ({ voters, onAddHelp, onDeleteHelp, onExportHelp, initialVoter }) => {
  const [selectedVoter, setSelectedVoter] = useState<Voter | null>(initialVoter);
  const [searchTerm, setSearchTerm] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('Social');
  const [value, setValue] = useState<string>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const filteredVoters = useMemo(() => {
    if (!searchTerm) return [];
    return voters.filter(v => v.name.toLowerCase().includes(searchTerm.toLowerCase())).slice(0, 5);
  }, [voters, searchTerm]);

  // Cálculos financeiros por mês
  const monthlyStats = useMemo(() => {
    const stats: Record<string, number> = {};
    voters.forEach(v => {
      v.helpRecords?.forEach(record => {
        const d = new Date(record.date);
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        stats[key] = (stats[key] || 0) + (record.value || 0);
      });
    });

    return Object.entries(stats)
      .map(([month, total]) => ({ month, total }))
      .sort((a, b) => b.month.localeCompare(a.month));
  }, [voters]);

  const currentMonthKey = useMemo(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  }, []);

  const totalSpentThisMonth = useMemo(() => {
    return monthlyStats.find(s => s.month === currentMonthKey)?.total || 0;
  }, [monthlyStats, currentMonthKey]);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedVoter || !description) return;

    onAddHelp(selectedVoter.id, {
      description,
      category,
      date,
      value: parseFloat(value) || 0
    });

    setDescription('');
    setValue('');
    alert("Atendimento financeiro registrado!");
  };

  const currentVoter = useMemo(() => {
    if (!selectedVoter) return null;
    return voters.find(v => v.id === selectedVoter.id) || null;
  }, [voters, selectedVoter]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const formatMonth = (monthKey: string) => {
    const [year, month] = monthKey.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1);
    return date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
  };

  const handleExportMonthlyBalance = () => {
    if (voters.length === 0) {
      alert("Não há dados para exportar.");
      return;
    }
    exportMonthlyFinancialReportPDF(voters);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Sidebar: Search & Monthly Report */}
      <div className="lg:col-span-4 space-y-6">
        {/* Monthly Summary Card */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 overflow-hidden relative">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <TrendingUp size={80} />
          </div>
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <PieChart size={18} className="text-indigo-600" />
            Gastos do Mês Atual
          </h3>
          <p className="text-3xl font-black text-indigo-600">{formatCurrency(totalSpentThisMonth)}</p>
          <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-wider">Investimento em assistência</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Search size={18} className="text-indigo-600" />
            Selecionar Eleitor
          </h3>
          <input 
            type="text"
            placeholder="Buscar para registrar ajuda..."
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />

          {filteredVoters.length > 0 && (
            <div className="mt-4 border border-slate-100 rounded-xl overflow-hidden divide-y divide-slate-50 shadow-sm">
              {filteredVoters.map(v => (
                <button
                  key={v.id}
                  onClick={() => { setSelectedVoter(v); setSearchTerm(''); }}
                  className="w-full text-left p-3 hover:bg-indigo-50 flex items-center justify-between group transition-colors"
                >
                  <span className="text-sm font-medium text-slate-700">{v.name}</span>
                  <ChevronRight size={14} className="text-slate-300 group-hover:text-indigo-500" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Historical Monthly Totals */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <DollarSign size={18} className="text-emerald-600" />
              Balanço por Mês
            </h3>
            {monthlyStats.length > 0 && (
              <button 
                onClick={handleExportMonthlyBalance}
                className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors group"
                title="Exportar Balanço em PDF"
              >
                <Download size={16} className="group-hover:scale-110 transition-transform" />
              </button>
            )}
          </div>
          <div className="space-y-3">
            {monthlyStats.length === 0 ? (
              <p className="text-sm text-slate-400 italic">Nenhum gasto registrado.</p>
            ) : (
              monthlyStats.map(stat => (
                <div key={stat.month} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-500 capitalize">{formatMonth(stat.month)}</span>
