import { GoogleGenAI } from "@google/genai";
import { PoliticalProfile } from "../types";

export async function generateBirthdayMessage(voterName: string, politician?: PoliticalProfile): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const senderInfo = politician 
    ? `A mensagem é enviada por ${politician.name} (${politician.office} do partido ${politician.party}).` 
    : "A mensagem é enviada por um representante da comunidade.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Escreva uma mensagem curta, carinhosa e profissional de aniversário para um eleitor chamado ${voterName}. 
      ${senderInfo}
      A mensagem deve ser amigável, desejar saúde e felicidade, e reforçar o compromisso com a comunidade. 
      Seja pessoal, mas mantenha a autoridade do cargo. 
      Não use placeholders, escreva o texto final pronto para enviar.`,
      config: {
        temperature: 0.8,
        topP: 0.95,
      }
    });

    return response.text || `Parabéns ${voterName}! Desejo muita saúde e realizações neste dia especial. Conte sempre com meu apoio e dedicação à nossa cidade. Um forte abraço!`;
  } catch (error) {
    console.error("Erro ao gerar mensagem Gemini:", error);
    return `Olá ${voterName}, parabéns pelo seu aniversário! Que seu dia seja repleto de alegrias e conquistas. Felicidades e um forte abraço!`;
  }
}

