import React, { useMemo, useState } from 'react';
import { Voter, PoliticalProfile } from '../types';
import { generateBirthdayMessage } from '../services/gemini';
import { Gift, Send, Loader2, Sparkles, CheckCircle } from 'lucide-react';

interface Props {
  voters: Voter[];
}

const BirthdayWidget: React.FC<Props> = ({ voters }) => {
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const [generatedMessages, setGeneratedMessages] = useState<Record<string, string>>({});

  const politicalProfile = useMemo(() => {
    const saved = localStorage.getItem('political_profile');
    return saved ? JSON.parse(saved) as PoliticalProfile : undefined;
  }, []);

  const birthdayData = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    const monthVoters = voters.filter(v => {
      const [, m] = v.birthDate.split('-').map(Number);
      return m === tMonth;
    }).sort((a, b) => {
        const [, , d1] = a.birthDate.split('-').map(Number);
        const [, , d2] = b.birthDate.split('-').map(Number);
        return d1 - d2;
    });

    return monthVoters.map(v => {
      const [, , d] = v.birthDate.split('-').map(Number);
      return {
        ...v,
        isToday: d === tDay
      };
    });
  }, [voters]);

  const handleGenerateMessage = async (voter: Voter) => {
    setLoadingId(voter.id);
    const message = await generateBirthdayMessage(voter.name, politicalProfile);
    setGeneratedMessages(prev => ({ ...prev, [voter.id]: message }));
    setLoadingId(null);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Mensagem copiada para a área de transferência!");
  };

  if (birthdayData.length === 0) {
    return (
      <div className="bg-white p-12 rounded-[2.5rem] border border-slate-100 text-center text-slate-400 italic">
        Nenhum aniversariante registrado neste mês.
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {birthdayData.map(voter => (
        <div 
          key={voter.id} 
          className={`bg-white p-6 rounded-3xl border transition-all ${voter.isToday ? 'border-pink-200 ring-4 ring-pink-50' : 'border-slate-100 shadow-sm'}`}
        >
          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-5">
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl font-black ${voter.isToday ? 'bg-pink-100 text-pink-600' : 'bg-slate-100 text-slate-600'}`}>
                {voter.birthDate.split('-')[2]}
              </div>
              <div>
                <h4 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                  {voter.name}
                  {voter.isToday && <Sparkles size={20} className="text-pink-500 fill-pink-500" />}
                </h4>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{voter.neighborhood}</p>
              </div>
            </div>

            {voter.isToday && (
              <button 
                onClick={() => handleGenerateMessage(voter)}
                disabled={loadingId === voter.id}
                className="px-6 py-3 bg-pink-600 text-white rounded-2xl hover:bg-pink-700 disabled:bg-pink-300 transition-all flex items-center gap-2 font-black text-sm shadow-xl shadow-pink-100"
              >
                {loadingId === voter.id ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
                Gerar com IA
              </button>
            )}
          </div>

          {generatedMessages[voter.id] && (
            <div className="mt-6 p-6 bg-slate-50 rounded-2xl border-2 border-slate-100 relative animate-in fade-in slide-in-from-top-2 duration-300">
              <p className="text-sm text-slate-700 leading-relaxed font-medium italic">
                "{generatedMessages[voter.id]}"
              </p>
              <div className="mt-4 flex justify-end gap-3">
                <button 
                  onClick={() => copyToClipboard(generatedMessages[voter.id])}
                  className="p-3 text-slate-400 hover:text-indigo-600 bg-white border border-slate-200 rounded-xl transition-all shadow-sm"
                  title="Copiar texto"
                >
                  <CheckCircle size={18} />
                </button>
                <a 
                  href={`https://wa.me/${voter.phone.replace(/\D/g, '')}?text=${encodeURIComponent(generatedMessages[voter.id])}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center gap-3 px-6 py-2 bg-green-500 text-white text-xs font-black rounded-xl hover:bg-green-600 transition-all shadow-lg shadow-green-100 uppercase tracking-widest"
                >
                  <Send size={16} /> Enviar WhatsApp
                </a>
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
};

export default BirthdayWidget;

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  Calendar, 
  LayoutDashboard, 
  Search,
  Bell,
  BarChart3,
  FileText,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  UserCircle2,
  Trophy,
  ArrowRight,
  LogOut,
  Settings
} from 'lucide-react';

const ACCESS_PASSWORD = '20257530';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  // Load data from localStorage
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') setIsAuthenticated(true);
  }, []);

  // Sync state to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);

      // Re-load profile just in case it was updated in another tab
      const savedProfile = localStorage.getItem('political_profile');
      if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair do sistema? Seus dados permanecerão salvos.')) {
      setIsAuthenticated(false);
      sessionStorage.removeItem('is_authenticated');
      // Reset sensitive UI states
      setPasswordInput('');
      setSearchTerm('');
      setActiveTab('dashboard');
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      slogan: formData.get('slogan') as string,
      number: formData.get('number') as string,
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab(data.isFamilyMember ? 'family' : 'list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir eleitor permanentemente?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVoters = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.phone.includes(searchTerm)
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [voters]);

  // Tela de Login
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 p-10 text-center text-white relative">
            <div className="w-24 h-24 bg-white/10 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-white/20 backdrop-blur-sm rotate-3">
              <Lock size={48} className="text-indigo-200" />
            </div>
            <h1 className="text-3xl font-black">Portal Seguro</h1>
            <p className="text-indigo-200/80 text-sm mt-2 font-medium">Gestão de Eleitores v3.1</p>
          </div>
          <form onSubmit={handleLogin} className="p-10 space-y-8 bg-white">
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 text-center">Digite sua Senha Exclusiva</label>
              <div className="relative group">
                <input 
                  type={showPassword ? "text" : "password"} 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                  placeholder="••••••••"
                  autoFocus
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2 transition-colors">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
              {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center animate-bounce">Acesso Negado</p>}
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 active:scale-95 transition-all shadow-xl shadow-indigo-100 flex items-center justify-center gap-3">
              <LogIn size={20} /> Entrar no Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  // Tela de Cadastro Inicial do Político (Persistente)
  if (!politicalProfile) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Gabinete Digital<br/>Primeiro Acesso</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Esses dados serão usados em todos os seus relatórios e mensagens.</p>
            </div>
            <UserCircle2 className="absolute right-[-20px] bottom-[-20px] w-64 h-64 text-white/5" />
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Seu Nome Político</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: Vereador João da Silva" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Cargo / Atuação</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: Vereador, Deputado" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Seu Partido</label>
                <input required name="party" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Sigla" />
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Seu Slogan ou Compromisso</label>
                <input required name="slogan" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold italic transition-all" placeholder="Ex: Por uma cidade melhor!" />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all group">
              Finalizar e Abrir Sistema <ArrowRight className="group-hover:translate-x-2 transition-transform" />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar - Menu Lateral */}
      <nav className="w-full md:w-72 bg-indigo-950 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg border border-indigo-400/30">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile.name}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest">{politicalProfile.party}</p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Painel de Controle" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Lista de Eleitores" />
          <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Núcleo Familiar" color="pink" />
          <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Ações Sociais" color="emerald" />
          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Cadastro" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Configurações" color="slate" />
        </div>

        {/* Footer Sidebar com Sair do Sistema */}
        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <div className="flex items-center justify-between mb-3">
              <p className="text-indigo-400 text-[9px] font-black uppercase tracking-widest">Base Ativa</p>
              <Users size={12} className="text-indigo-400 opacity-50" />
            </div>
            <p className="text-3xl font-black tracking-tighter">{voters.length}</p>
          </div>

          <div className="border-t border-white/10 pt-4">
             <button 
              onClick={handleLogout} 
              className="group w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 border border-red-500/20"
            >
              <LogOut size={16} className="group-hover:-translate-x-1 transition-transform" />
              Sair do Sistema
            </button>
            <p className="text-[8px] text-white/20 text-center mt-3 font-medium uppercase tracking-widest">Sessão Segura e Criptografada</p>
          </div>
        </div>
      </nav>

      {/* Conteúdo Principal */}
      <main className="flex-1 overflow-y-auto bg-slate-50">
        {/* Header Superior */}
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex flex-col sm:flex-row justify-between items-center gap-4 shadow-sm">
          <div className="relative w-full sm:w-[450px]">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Pesquisar na base de dados..."
              className="w-full pl-12 pr-6 py-4 bg-slate-100 border-transparent focus:bg-white focus:ring-4 focus:ring-indigo-500/10 rounded-2xl outline-none font-medium transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-6">
            <div className="relative group cursor-pointer p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-all active:scale-95">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-6 h-6 rounded-full flex items-center justify-center font-black border-4 border-white shadow-lg animate-pulse">
                  {birthdayVoters.length}
                </span>
              )}
            </div>
            <div 
              onClick={() => setActiveTab('profile')} 
              className="h-12 w-12 rounded-2xl bg-indigo-600 flex items-center justify-center text-white font-black shadow-xl cursor-pointer hover:rotate-3 hover:scale-110 transition-all border-2 border-white"
              title="Meu Perfil"
            >
              {politicalProfile.name.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="flex items-center justify-between mb-2">
                <div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight">Bem-vindo, {politicalProfile.name.split(' ')[0]}!</h2>
                  <p className="text-slate-500 font-medium text-lg">Aqui está o resumo da sua atuação política.</p>
                </div>
                <div className="hidden lg:block text-right bg-indigo-50 px-6 py-3 rounded-2xl border border-indigo-100">
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">{politicalProfile.office}</p>
                  <p className="text-sm font-bold text-slate-600">"{politicalProfile.slogan}"</p>
                </div>
              </div>

              <Dashboard voters={voters} />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7">
                  <NeighborhoodChart voters={voters} />
                </div>
                <div className="lg:col-span-5 space-y-10">
                   <div className="bg-white p-10 rounded-[3rem] shadow-xl shadow-slate-200/50 border border-slate-100 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-6 opacity-5 rotate-12 group-hover:rotate-0 transition-transform duration-700">
                       <BarChart3 size={150} />
                     </div>
                     <h3 className="font-black text-slate-800 mb-8 flex items-center gap-3 text-xl">
                       <BarChart3 size={24} className="text-indigo-600" /> 
                       Gestão de Atividades
                     </h3>
                     <div className="grid grid-cols-1 gap-4 relative z-10">
                       <button 
                        onClick={() => setActiveTab('add')} 
                        className="flex items-center justify-center gap-3 py-5 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 transition-all font-black shadow-xl shadow-indigo-100 active:scale-[0.98]"
                       >
                         <UserPlus size={22} /> Novo Eleitor
                       </button>
                       <button 
                        onClick={() => exportVotersToPDF(voters, politicalProfile)} 
                        className="flex items-center justify-center gap-3 py-5 bg-white border-2 border-slate-100 text-slate-700 rounded-[1.5rem] hover:bg-slate-50 transition-all font-black"
                       >
                         <FileText size={22} className="text-red-500" /> Relatório Completo PDF
                       </button>
                     </div>
                   </div>
                   <div>
                      <h2 className="text-2xl font-black mb-8 flex items-center gap-4 text-slate-800">
                        <Calendar className="text-indigo-600" size={28} /> Aniversariantes do Mês
                      </h2>
                      <BirthdayWidget voters={voters} />
                   </div>
                </div>
              </div>
            </div>
          )}

          {(activeTab === 'list' || activeTab === 'family') && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                <div>
                  <h2 className="text-4xl font-black text-slate-800 tracking-tight">
                    {activeTab === 'family' ? 'Minha Família' : 'Base de Eleitores'}
                  </h2>
                  <p className="text-slate-500 font-medium mt-1">Gerencie os dados e contatos de cada pessoa.</p>
                </div>
                <button 
                  onClick={() => exportVotersToPDF(activeTab === 'family' ? voters.filter(v => v.isFamilyMember) : voters, politicalProfile)} 
                  className="flex items-center gap-3 px-8 py-4 bg-white border-2 border-slate-100 text-slate-700 rounded-2xl hover:bg-slate-50 transition-all font-black shadow-sm active:scale-95"
                >
                  <FileText size={20} className="text-red-500" /> Exportar Lista
                </button>
              </div>
              <VoterList 
                voters={filteredVoters} 
                onDelete={deleteVoter} 
                onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} 
                onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} 
              />
            </div>
          )}

          {activeTab === 'help' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager 
                voters={voters} 
                onAddHelp={addHelpRecord} 
                onDeleteHelp={deleteHelpRecord}
                onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)}
                initialVoter={editingVoter}
              />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="max-w-4xl mx-auto animate-in zoom-in-95 duration-300">
              <VoterForm 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => { setActiveTab('list'); setEditingVoter(null); }} 
                initialData={editingVoter || undefined} 
              />
            </div>
          )}

          {activeTab === 'profile' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in slide-up duration-500">
                <div className="flex items-center gap-5 mb-10">
                  <div className="p-4 bg-indigo-100 text-indigo-600 rounded-3xl">
                    <UserCircle2 size={48} />
                  </div>
                  <div>
                    <h2 className="text-3xl font-black text-slate-800">Perfil do Político</h2>
                    <p className="text-slate-500 font-medium">Informações de identificação do sistema.</p>
                  </div>
                </div>

                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome que Aparece nos Relatórios</label>
                      <input name="name" defaultValue={politicalProfile.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Cargo Político</label>
                      <input name="office" defaultValue={politicalProfile.office} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Sigla do Partido</label>
                      <input name="party" defaultValue={politicalProfile.party} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Slogan ou Mensagem de Cabeçalho</label>
                      <input name="slogan" defaultValue={politicalProfile.slogan} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold italic transition-all" />
                    </div>
                  </div>
                  <div className="flex flex-col gap-4">
                    <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all active:scale-95">
                      Atualizar Perfil Político
                    </button>
                  </div>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20';

  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20';

  return (
    <button 
      onClick={onClick} 
      className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-indigo-300 hover:bg-white/5 active:scale-95'}`}
    >
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

export interface HelpRecord {
  id: string;
  description: string;
  date: string;
  category: string;
  value: number;
}

export interface PoliticalProfile {
  name: string;
  party: string;
  office: string; // Cargo (Ex: Vereador, Prefeito)
  slogan: string;
  voteGoal?: number; // Meta de votos
  number?: string;
}

export interface Voter {
  id: string;
  name: string;
  birthDate: string; // ISO string YYYY-MM-DD
  gender: 'Masculino' | 'Feminino' | 'Outro';
  phone: string;
  email: string;
  address: string;
  neighborhood: string;
  observations: string;
  isFamilyMember: boolean;
  helpRecords?: HelpRecord[];
  createdAt: string;
}

export interface VoterFormData extends Omit<Voter, 'id' | 'createdAt' | 'helpRecords'> {}

export interface BirthdaySummary {
  voter: Voter;
  isToday: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  Calendar, 
  LayoutDashboard, 
  Search,
  Bell,
  BarChart3,
  FileText,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  UserCircle2,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Target
} from 'lucide-react';

const ACCESS_PASSWORD = '20257530';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  // Load data from localStorage
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') setIsAuthenticated(true);
  }, []);

  // Sync state to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
      const savedProfile = localStorage.getItem('political_profile');
      if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair do sistema? Seus dados permanecerão salvos.')) {
      setIsAuthenticated(false);
      sessionStorage.removeItem('is_authenticated');
      setPasswordInput('');
      setSearchTerm('');
      setActiveTab('dashboard');
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      ...politicalProfile,
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      slogan: formData.get('slogan') as string,
      number: formData.get('number') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || politicalProfile?.voteGoal || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const setVoteGoal = () => {
    const goal = prompt("Qual sua meta de votos para esta eleição?", politicalProfile?.voteGoal?.toString() || "1000");
    if (goal !== null && politicalProfile) {
      setPoliticalProfile({ ...politicalProfile, voteGoal: parseInt(goal) || 0 });
    }
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab(data.isFamilyMember ? 'family' : 'list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir eleitor permanentemente?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVoters = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.phone.includes(searchTerm)
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [voters]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 p-10 text-center text-white relative">
            <div className="w-24 h-24 bg-white/10 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-white/20 backdrop-blur-sm rotate-3">
              <Lock size={48} className="text-indigo-200" />
            </div>
            <h1 className="text-3xl font-black">Portal Seguro</h1>
            <p className="text-indigo-200/80 text-sm mt-2 font-medium">Gestão de Eleitores v3.2</p>
          </div>
          <form onSubmit={handleLogin} className="p-10 space-y-8 bg-white">
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 text-center">Digite sua Senha Exclusiva</label>
              <div className="relative group">
                <input 
                  type={showPassword ? "text" : "password"} 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                  placeholder="••••••••"
                  autoFocus
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2 transition-colors">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 active:scale-95 transition-all shadow-xl shadow-indigo-100 flex items-center justify-center gap-3">
              <LogIn size={20} /> Entrar no Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (!politicalProfile) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Gabinete Digital<br/>Primeiro Acesso</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Configure sua identidade política para começar.</p>
            </div>
            <UserCircle2 className="absolute right-[-20px] bottom-[-20px] w-64 h-64 text-white/5" />
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Seu Nome Político</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: Vereador João da Silva" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Cargo / Atuação</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: Vereador, Deputado" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Seu Partido</label>
                <input required name="party" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Sigla" />
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Meta de Votos Inicial</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Quantos votos deseja conseguir?" />
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Seu Slogan</label>
                <input required name="slogan" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold italic transition-all" placeholder="Ex: Por uma cidade melhor!" />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all group">
              Finalizar e Abrir Sistema <ArrowRight className="group-hover:translate-x-2 transition-transform" />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      <nav className="w-full md:w-72 bg-indigo-950 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg border border-indigo-400/30">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile.name}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest">{politicalProfile.party}</p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Painel de Controle" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Lista de Eleitores" />
          <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Núcleo Familiar" color="pink" />
          <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Ações Sociais" color="emerald" />
          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Cadastro" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Configurações" color="slate" />
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <div className="flex items-center justify-between mb-3">
              <p className="text-indigo-400 text-[9px] font-black uppercase tracking-widest">Base Ativa</p>
              <Users size={12} className="text-indigo-400 opacity-50" />
            </div>
            <p className="text-3xl font-black tracking-tighter">{voters.length}</p>
          </div>
          <div className="border-t border-white/10 pt-4">
             <button onClick={handleLogout} className="group w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 border border-red-500/20">
              <LogOut size={16} className="group-hover:-translate-x-1 transition-transform" />
              Sair do Sistema
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex flex-col sm:flex-row justify-between items-center gap-4 shadow-sm">
          <div className="relative w-full sm:w-[450px]">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Pesquisar eleitores..."
              className="w-full pl-12 pr-6 py-4 bg-slate-100 border-transparent focus:bg-white focus:ring-4 focus:ring-indigo-500/10 rounded-2xl outline-none font-medium transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-6">
            <div className="relative group cursor-pointer p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-all active:scale-95">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-6 h-6 rounded-full flex items-center justify-center font-black border-4 border-white shadow-lg animate-pulse">
                  {birthdayVoters.length}
                </span>
              )}
            </div>
            <div onClick={() => setActiveTab('profile')} className="h-12 w-12 rounded-2xl bg-indigo-600 flex items-center justify-center text-white font-black shadow-xl cursor-pointer hover:rotate-3 hover:scale-110 transition-all border-2 border-white">
              {politicalProfile.name.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="flex items-center justify-between mb-2">
                <div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight">Bem-vindo, {politicalProfile.name.split(' ')[0]}!</h2>
                  <p className="text-slate-500 font-medium text-lg">Gerenciamento estratégico de sua campanha.</p>
                </div>
                <button onClick={setVoteGoal} className="hidden lg:flex items-center gap-2 bg-indigo-50 text-indigo-600 px-6 py-3 rounded-2xl border border-indigo-100 hover:bg-indigo-100 transition-colors font-bold text-sm">
                  <Target size={18} /> Ajustar Meta
                </button>
              </div>

              <Dashboard voters={voters} voteGoal={politicalProfile.voteGoal || 0} onEditGoal={setVoteGoal} />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={voters} /></div>
                <div className="lg:col-span-5 space-y-10">
                   <div className="bg-white p-10 rounded-[3rem] shadow-xl shadow-slate-200/50 border border-slate-100 relative overflow-hidden group">
                     <h3 className="font-black text-slate-800 mb-8 flex items-center gap-3 text-xl"><BarChart3 size={24} className="text-indigo-600" /> Atividades Rápidas</h3>
                     <div className="grid grid-cols-1 gap-4 relative z-10">
                       <button onClick={() => setActiveTab('add')} className="flex items-center justify-center gap-3 py-5 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 transition-all font-black shadow-xl active:scale-[0.98]">
                         <UserPlus size={22} /> Novo Eleitor
                       </button>
                       <button onClick={() => exportVotersToPDF(voters, politicalProfile)} className="flex items-center justify-center gap-3 py-5 bg-white border-2 border-slate-100 text-slate-700 rounded-[1.5rem] hover:bg-slate-50 transition-all font-black">
                         <FileText size={22} className="text-red-500" /> Exportar PDF
                       </button>
                     </div>
                   </div>
                   <div>
                      <h2 className="text-2xl font-black mb-8 flex items-center gap-4 text-slate-800"><Calendar className="text-indigo-600" size={28} /> Aniversariantes</h2>
                      <BirthdayWidget voters={voters} />
                   </div>
                </div>
              </div>
            </div>
          )}

          {(activeTab === 'list' || activeTab === 'family') && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">{activeTab === 'family' ? 'Núcleo Familiar' : 'Eleitores Cadastrados'}</h2>
                <button onClick={() => exportVotersToPDF(activeTab === 'family' ? voters.filter(v => v.isFamilyMember) : voters, politicalProfile)} className="flex items-center gap-3 px-8 py-4 bg-white border-2 border-slate-100 text-slate-700 rounded-2xl hover:bg-slate-50 transition-all font-black shadow-sm">
                  <FileText size={20} className="text-red-500" /> Exportar Lista
                </button>
              </div>
              <VoterList voters={filteredVoters} onDelete={deleteVoter} onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} />
            </div>
          )}

          {activeTab === 'help' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="max-w-4xl mx-auto animate-in zoom-in-95 duration-300">
              <VoterForm onSubmit={activeTab === 'edit' ? updateVoter : addVoter} onCancel={() => { setActiveTab('list'); setEditingVoter(null); }} initialData={editingVoter || undefined} />
            </div>
          )}

          {activeTab === 'profile' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><UserCircle2 className="text-indigo-600" size={32} /> Perfil Político</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Completo</label>
                      <input name="name" defaultValue={politicalProfile.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Cargo</label>
                      <input name="office" defaultValue={politicalProfile.office} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Partido</label>
                      <input name="party" defaultValue={politicalProfile.party} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta de Votos</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Slogan</label>
                      <input name="slogan" defaultValue={politicalProfile.slogan} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold italic" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all">Salvar Alterações</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20';
  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-indigo-300 hover:bg-white/5 active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Voter, VoterFormData } from '../types';
import { Save, X, User, MapPin, Archive, Edit3, Heart, Users2, Venus, Mars } from 'lucide-react';

interface Props {
  onSubmit: (data: VoterFormData) => void;
  onCancel: () => void;
  initialData?: Voter;
}

const VoterForm: React.FC<Props> = ({ onSubmit, onCancel, initialData }) => {
  const [formData, setFormData] = useState<VoterFormData>({
    name: '',
    birthDate: '',
    gender: 'Masculino',
    phone: '',
    email: '',
    address: '',
    neighborhood: '',
    observations: '',
    isFamilyMember: false,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        name: initialData.name,
        birthDate: initialData.birthDate,
        gender: initialData.gender || 'Masculino',
        phone: initialData.phone,
        email: initialData.email,
        address: initialData.address,
        neighborhood: initialData.neighborhood,
        observations: initialData.observations,
        isFamilyMember: initialData.isFamilyMember || false,
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'checkbox' ? (e.target as HTMLInputElement).checked : value;
    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const toggleFamily = () => {
    setFormData(prev => ({ ...prev, isFamilyMember: !prev.isFamilyMember }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.birthDate || !formData.phone) {
      alert("Por favor, preencha os campos obrigatórios (Nome, Nascimento e Telefone)");
      return;
    }
    onSubmit(formData);
  };

  const isEditing = !!initialData;

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden mb-10">
      <div className={`p-6 text-white flex justify-between items-center ${isEditing ? (formData.isFamilyMember ? 'bg-pink-600' : 'bg-amber-600') : 'bg-indigo-600'}`}>
        <h2 className="text-xl font-bold flex items-center gap-2">
          {isEditing ? <Edit3 /> : <User />} 
          {isEditing ? `Editando: ${initialData.name}` : 'Novo Cadastro de Eleitor'}
        </h2>
        <button onClick={onCancel} className="text-white/80 hover:text-white transition-colors">
          <X />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-8">
        <div 
          onClick={toggleFamily}
          className={`p-4 rounded-xl border-2 cursor-pointer transition-all flex items-center justify-between ${formData.isFamilyMember ? 'border-pink-500 bg-pink-50' : 'border-slate-200 bg-slate-50'}`}
        >
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-full ${formData.isFamilyMember ? 'bg-pink-100 text-pink-600' : 'bg-slate-200 text-slate-500'}`}>
              <Heart size={20} fill={formData.isFamilyMember ? "currentColor" : "none"} />
            </div>
            <div>
              <p className={`font-bold text-sm ${formData.isFamilyMember ? 'text-pink-700' : 'text-slate-700'}`}>Membro da Família</p>
              <p className="text-xs text-slate-500">Marque se este eleitor é do seu núcleo familiar direto.</p>
            </div>
          </div>
          <div className={`w-12 h-6 rounded-full relative transition-colors ${formData.isFamilyMember ? 'bg-pink-500' : 'bg-slate-300'}`}>
             <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${formData.isFamilyMember ? 'right-1' : 'left-1'}`} />
          </div>
        </div>

        <section>
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
            <Archive size={16} /> Dados Pessoais
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo *</label>
              <input name="name" value={formData.name} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all" placeholder="Ex: João da Silva" />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento *</label>
              <input type="date" name="birthDate" value={formData.birthDate} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Sexo / Gênero *</label>
              <div className="grid grid-cols-3 gap-2">
                <label className={`flex items-center justify-center gap-2 p-3 border-2 rounded-xl cursor-pointer transition-all ${formData.gender === 'Masculino' ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-100 bg-slate-50 text-slate-400'}`}>
                  <input type="radio" name="gender" value="Masculino" checked={formData.gender === 'Masculino'} onChange={handleChange} className="hidden" />
                  <Mars size={16} /> <span className="text-xs font-bold uppercase">Masc</span>
                </label>
