import React, { useMemo } from 'react';
import { Voter } from '../types';
import { Users, UserCheck, MapPin, Calendar, Heart, HandHelping, DollarSign, Target, Venus, Mars, Percent } from 'lucide-react';

interface Props {
  voters: Voter[];
  voteGoal: number;
  onEditGoal: () => void;
}

const Dashboard: React.FC<Props> = ({ voters, voteGoal, onEditGoal }) => {
  const stats = useMemo(() => {
    const today = new Date();
    const tMonth = today.getMonth() + 1;
    const tDay = today.getDate();

    const birthdaysToday = voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === tMonth && parts[2] === tDay;
    }).length;

    const uniqueNeighborhoods = new Set(voters.map(v => v.neighborhood)).size;
    const familyMembers = voters.filter(v => v.isFamilyMember).length;

    // Gênero
    const maleCount = voters.filter(v => v.gender === 'Masculino').length;
    const femaleCount = voters.filter(v => v.gender === 'Feminino').length;
    const otherCount = voters.filter(v => v.gender === 'Outro').length;

    let totalHelpCount = 0;
    let totalValue = 0;
    voters.forEach(v => {
      v.helpRecords?.forEach(r => {
        totalHelpCount++;
        totalValue += (r.value || 0);
      });
    });

    const progress = voteGoal > 0 ? (voters.length / voteGoal) * 100 : 0;
    const remaining = Math.max(0, voteGoal - voters.length);

    return {
      total: voters.length,
      birthdays: birthdaysToday,
      neighborhoods: uniqueNeighborhoods,
      family: familyMembers,
      helps: totalHelpCount,
      totalInvested: totalValue,
      gender: {
        male: { count: maleCount, pct: voters.length > 0 ? (maleCount / voters.length) * 100 : 0 },
        female: { count: femaleCount, pct: voters.length > 0 ? (femaleCount / voters.length) * 100 : 0 },
        other: { count: otherCount, pct: voters.length > 0 ? (otherCount / voters.length) * 100 : 0 },
      },
      goal: {
        progress,
        remaining,
        goal: voteGoal
      },
      recent: voters.filter(v => {
        const date = new Date(v.createdAt);
        const sevenDaysAgo = new Date();
        sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
        return date > sevenDaysAgo;
      }).length
    };
  }, [voters, voteGoal]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Total Eleitores" value={stats.total.toString()} icon={<Users className="text-blue-600" />} bgColor="bg-blue-50" />
        <StatCard label="Investimento" value={formatCurrency(stats.totalInvested)} icon={<DollarSign className="text-emerald-600" />} bgColor="bg-emerald-50" />
        <StatCard label="Ajudas Prestadas" value={stats.helps.toString()} icon={<HandHelping className="text-indigo-600" />} bgColor="bg-indigo-50" />
        <StatCard label="Minha Família" value={stats.family.toString()} icon={<Heart className="text-pink-600" fill={stats.family > 0 ? "currentColor" : "none"} />} bgColor="bg-pink-50" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Meta de Votos Section */}
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-5">
            <Target size={120} />
          </div>
          <div className="flex justify-between items-start mb-6">
            <div>
              <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl">
                <Target size={24} className="text-red-500" /> Meta Eleitoral
              </h3>
              <p className="text-sm text-slate-400 font-medium">Progresso em direção à vitória</p>
            </div>
            <button onClick={onEditGoal} className="text-xs font-black text-indigo-600 hover:underline uppercase tracking-widest">Ajustar Meta</button>
          </div>

          <div className="space-y-6 relative z-10">
            <div className="flex justify-between items-end">
              <div>
                <span className="text-4xl font-black text-slate-800">{stats.total}</span>
                <span className="text-slate-400 font-bold ml-2">/ {stats.goal.goal} votos</span>
              </div>
              <div className="text-right">
                <span className="text-2xl font-black text-indigo-600">{stats.goal.progress.toFixed(1)}%</span>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Atingido</p>
              </div>
            </div>

            <div className="h-6 w-full bg-slate-100 rounded-full overflow-hidden border border-slate-200">
              <div 
                className="h-full bg-gradient-to-r from-indigo-500 to-indigo-600 rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(79,70,229,0.3)]"
                style={{ width: `${Math.min(100, stats.goal.progress)}%` }}
              />
            </div>

            <div className="flex items-center gap-2 py-3 px-4 bg-indigo-50 rounded-2xl border border-indigo-100">
              <Target size={16} className="text-indigo-600" />
              <span className="text-sm font-bold text-indigo-700">
                {stats.goal.remaining > 0 
                  ? `Faltam apenas ${stats.goal.remaining} eleitores para atingir sua meta!` 
                  : "Parabéns! Meta atingida com sucesso!"}
              </span>
            </div>
          </div>
        </div>

        {/* Distribuição por Gênero Section */}
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl mb-6">
            <Users size={24} className="text-indigo-600" /> Distribuição de Gênero
          </h3>

          <div className="space-y-8">
            <GenderBar label="Feminino" count={stats.gender.female.count} pct={stats.gender.female.pct} color="bg-pink-500" icon={<Venus size={16} />} />
            <GenderBar label="Masculino" count={stats.gender.male.count} pct={stats.gender.male.pct} color="bg-blue-500" icon={<Mars size={16} />} />
            <GenderBar label="Outro / Não Informado" count={stats.gender.other.count} pct={stats.gender.other.pct} color="bg-slate-400" icon={<Percent size={14} />} />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
        <StatCardSmall label="Aniversários Hoje" value={stats.birthdays} icon={<Calendar size={16} className="text-amber-600" />} />
        <StatCardSmall label="Bairros Atendidos" value={stats.neighborhoods} icon={<MapPin size={16} className="text-slate-600" />} />
        <StatCardSmall label="Novos (7 dias)" value={stats.recent} icon={<UserCheck size={16} className="text-orange-600" />} />
      </div>
    </div>
  );
};

