    doc.setFont("helvetica", "bold");
    doc.text(`${politician.office.toUpperCase()} ${politician.name.toUpperCase()}`, 14, 8);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text(`Partido: ${politician.party} | ${politician.slogan}`, 14, 12);
    doc.setDrawColor(226, 232, 240);
    doc.line(14, 14, 283, 14); // Extended for landscape
  }
}

function addPoliticianHeaderPortrait(doc: jsPDF, politician?: PoliticalProfile) {
  if (politician) {
    doc.setFontSize(10);
