    styles: { fontSize: 8 },
    columnStyles: {
      2: { halign: 'center' },
      6: { halign: 'center' }
    }
  });

  doc.save(`eleitores_${new Date().getTime()}.pdf`);
}

export function exportVoterHistoryPDF(voter: Voter, politician?: PoliticalProfile) {
