import React, { useState, useEffect } from 'react';
import { CaboEleitoral } from '../types';
import { UserCheck, Save, X, MapPin, Phone, Target } from 'lucide-react';

interface Props {
  scope: 'municipal' | 'estadual';
  onSubmit: (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => void;
  onCancel: () => void;
  initialData?: CaboEleitoral;
}

const CaboForm: React.FC<Props> = ({ scope, onSubmit, onCancel, initialData }) => {
  const [formData, setFormData] = useState<Omit<CaboEleitoral, 'id' | 'hiredAt'>>({
    name: '',
    phone: '',
    location: '',
    voterGoal: 100
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        name: initialData.name,
        phone: initialData.phone,
        location: initialData.location,
        voterGoal: initialData.voterGoal
      });
    }
  }, [initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.location || !formData.phone) {
      alert("Preencha todos os campos!");
      return;
    }
    onSubmit(formData);
    onCancel();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-2xl font-black text-slate-800 flex items-center gap-2">
          <UserCheck className="text-orange-500" />
          {initialData ? 'Editar Cabo' : 'Novo Cabo'}
        </h3>
        <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
          <X size={20} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 px-1">Nome Completo</label>
          <input 
            required
            value={formData.name}
            onChange={(e) => setFormData({...formData, name: e.target.value})}
            className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-orange-500 outline-none font-bold transition-all"
            placeholder="Ex: Roberto Mendes"
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 px-1">Telefone / WhatsApp</label>
            <input 
              required
              value={formData.phone}
              onChange={(e) => setFormData({...formData, phone: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-orange-500 outline-none font-bold transition-all"
              placeholder="(00) 00000-0000"
            />
          </div>
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 px-1">Meta de Eleitores</label>
            <input 
              type="number"
              value={formData.voterGoal}
