              className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-orange-500 outline-none font-bold transition-all"
            />
          </div>
        </div>

        <div>
          <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 px-1">
            {scope === 'municipal' ? 'Bairro de Atuação' : 'Cidade de Atuação'}
          </label>
          <div className="relative">
            <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              required
              value={formData.location}
              onChange={(e) => setFormData({...formData, location: e.target.value})}
              className="w-full pl-12 pr-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-orange-500 outline-none font-bold transition-all"
              placeholder={scope === 'municipal' ? "Nome do Bairro" : "Nome da Cidade"}
            />
          </div>
        </div>

        <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-lg hover:bg-orange-600 shadow-xl shadow-orange-100 transition-all flex items-center justify-center gap-3">
          <Save size={20} /> Salvar Cabo Eleitoral
        </button>
      </form>
    </div>
  );
};

