import React from 'react';
import { CaboEleitoral, Voter } from '../types';
import { Trash2, Phone, MapPin, Edit3, Target, Users } from 'lucide-react';

interface Props {
  cabos: CaboEleitoral[];
  voters: Voter[];
  onDelete: (id: string) => void;
  onEdit: (cabo: CaboEleitoral) => void;
  scope: 'municipal' | 'estadual';
}

const CaboList: React.FC<Props> = ({ cabos, voters, onDelete, onEdit, scope }) => {
  if (cabos.length === 0) {
    return (
      <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-200">
        <Target className="mx-auto text-slate-200 mb-4" size={64} />
        <h3 className="text-xl font-black text-slate-400">Nenhum Cabo Eleitoral Cadastrado</h3>
        <p className="text-slate-300">Comece a montar sua equipe de lideranças.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
      {cabos.map((cabo) => {
        const broughtVoters = voters.filter(v => v.caboId === cabo.id).length;
        const performance = Math.min(100, (broughtVoters / (cabo.voterGoal || 1)) * 100);

        return (
          <div key={cabo.id} className="bg-white rounded-3xl p-6 border border-slate-100 shadow-sm hover:shadow-md transition-all group">
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-orange-50 rounded-2xl flex items-center justify-center text-orange-500 font-black text-xl">
                  {cabo.name.charAt(0)}
                </div>
                <div>
                  <h4 className="font-black text-slate-800 leading-tight">{cabo.name}</h4>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1">
                    <MapPin size={10} /> {cabo.location}
                  </p>
                </div>
              </div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => onEdit(cabo)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg">
                  <Edit3 size={16} />
                </button>
                <button onClick={() => onDelete(cabo.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg">
                  <Trash2 size={16} />
                </button>
              </div>
            </div>

            <div className="space-y-4">
               <div className="flex items-center gap-3 text-slate-600">
                  <Phone size={14} className="text-orange-400" />
                  <span className="text-sm font-bold">{cabo.phone}</span>
               </div>

               <div className="pt-4 border-t border-slate-50">
                  <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase mb-2">
                    <span>Avanço Individual</span>
                    <span className="text-slate-700">{broughtVoters} / {cabo.voterGoal}</span>
                  </div>
                  <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div className="h-full bg-orange-500 transition-all duration-700" style={{ width: `${performance}%` }} />
                  </div>
               </div>

               <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest mt-2">
                  <div className="flex items-center gap-1 text-orange-600">
                    <Users size={12} /> {broughtVoters} Eleitores
                  </div>
                  <div className={`px-2 py-1 rounded-lg ${performance >= 80 ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-50 text-slate-400'}`}>
                    {performance.toFixed(0)}% Meta
                  </div>
               </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default CaboList;

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile, CaboEleitoral } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import CaboForm from './components/CaboForm';
import CaboList from './components/CaboList';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  Calendar, 
  LayoutDashboard, 
  Search,
  Bell,
  BarChart3,
  FileText,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  UserCircle2,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Target,
  UserCheck,
  Flag,
  X
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Load data from localStorage
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') setIsAuthenticated(true);
  }, []);

  // Sync state to localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair do sistema? Seus dados permanecerão salvos.')) {
      setIsAuthenticated(false);
      sessionStorage.removeItem('is_authenticated');
      setPasswordInput('');
      setLoginError(false);
      setSearchTerm('');
      setActiveTab('dashboard');
      // Forçar o estado inicial
      window.location.reload(); 
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir eleitor permanentemente?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Excluir cabo eleitoral? Esta ação é irreversível.')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVoters = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [voters]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 p-10 text-center text-white relative">
            <Lock size={48} className="mx-auto mb-6 text-indigo-200" />
            <h1 className="text-3xl font-black">Portal Seguro</h1>
            <p className="text-indigo-200/80 text-sm mt-2 font-medium">Gestão de Eleitores v3.3</p>
          </div>
          <form onSubmit={handleLogin} className="p-10 space-y-8 bg-white">
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 text-center">Digite sua Senha</label>
              <div className="relative group">
                <input 
                  type={showPassword ? "text" : "password"} 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                  placeholder="•••"
                  autoFocus
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
              {loginError && <p className="text-red-500 text-xs text-center font-bold">Senha incorreta!</p>}
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 active:scale-95 transition-all shadow-xl shadow-indigo-100 flex items-center justify-center gap-3">
              <LogIn size={20} /> Entrar no Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (!politicalProfile) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Configuração Inicial</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Defina o escopo da sua atuação política.</p>
            </div>
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Nome Político</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Cargo</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Escopo de Atuação</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal (Separado por Bairros)</option>
                  <option value="estadual">Estadual (Separado por Cidades)</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Partido</label>
                <input required name="party" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Meta de Votos</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
