                </div>
                <ArrowRight size={20} className="ml-auto text-slate-300 group-hover:text-indigo-500 transition-colors" />
              </button>
              <button onClick={() => selectRole('cabo')} className="w-full p-6 bg-slate-50 hover:bg-orange-50 border-2 border-slate-100 hover:border-orange-200 rounded-3xl flex items-center gap-4 transition-all group">
                <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center text-white shadow-lg"><Briefcase size={24} /></div>
