                <ArrowRight size={20} className="ml-auto text-slate-300 group-hover:text-orange-500 transition-colors" />
              </button>
              <button onClick={() => setLoginStep('password')} className="w-full text-xs font-black text-slate-400 uppercase py-2 hover:text-slate-600">Voltar</button>
            </div>
          )}

          {loginStep === 'select-cabo' && (
            <div className="p-10 space-y-6 animate-in slide-in-from-right-4">
               <p className="text-center text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Selecione seu Nome</p>
