import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile, CaboEleitoral, UserRole } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import CaboForm from './components/CaboForm';
import CaboList from './components/CaboList';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Search,
  Bell,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Flag,
  X,
  ShieldCheck,
  Briefcase,
  UserCheck,
  ChevronLeft
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [loggedCaboId, setLoggedCaboId] = useState<string | null>(null);

  // Fluxo de login: 'role-selection' -> 'auth' -> 'selection'
  const [loginStep, setLoginStep] = useState<'role-selection' | 'auth' | 'selection'>('role-selection');
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Carregar dados e verificar sessão ao iniciar
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    const role = sessionStorage.getItem('user_role') as UserRole;
    const caboId = sessionStorage.getItem('logged_cabo_id');

    if (auth === 'true') {
      setIsAuthenticated(true);
      setUserRole(role);
      setLoggedCaboId(caboId);
    }
  }, []);

  // Persistência de dados
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handleRoleSelect = (role: UserRole) => {
    if (role === 'cabo' && cabos.length === 0) {
      alert("Aviso: Não há cabos cadastrados. Acesse como Master para cadastrar sua equipe.");
      return;
    }
    setSelectedRole(role);
    setLoginStep('auth');
    setLoginError(false);
    setPasswordInput('');
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setLoginError(false);
      if (selectedRole === 'master') {
        finalizeLogin('master', null);
      } else {
        setLoginStep('selection');
      }
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const finalizeLogin = (role: UserRole, caboId: string | null) => {
    setIsAuthenticated(true);
    setUserRole(role);
    setLoggedCaboId(caboId);
    sessionStorage.setItem('is_authenticated', 'true');
    sessionStorage.setItem('user_role', role);
    if (caboId) sessionStorage.setItem('logged_cabo_id', caboId);
  };

  // BOTÃO ENCERRAR SESSÃO - RESOLVIDO E ATIVADO
  const handleLogout = () => {
    if (window.confirm('Deseja realmente encerrar a sessão e voltar ao início?')) {
      // Limpar sessão
      sessionStorage.clear();

      // Resetar estados locais
      setIsAuthenticated(false);
      setUserRole(null);
      setLoggedCaboId(null);
      setSelectedRole(null);
      setLoginStep('role-selection');
      setPasswordInput('');
      setLoginError(false);

      // Hard Refresh para limpar qualquer resíduo de memória e voltar ao Início
      window.location.reload();
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  // Filtragem de visibilidade
  const visibleVoters = useMemo(() => {
    if (userRole === 'master') return voters;
    return voters.filter(v => v.caboId === loggedCaboId);
  }, [voters, userRole, loggedCaboId]);

  const addVoter = (data: VoterFormData) => {
    const finalData = userRole === 'cabo' ? { ...data, caboId: loggedCaboId || '' } : data;
    const newVoter: Voter = {
      ...finalData,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir este eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Excluir cabo eleitoral?')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVotersList = useMemo(() => {
    let list = visibleVoters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [visibleVoters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return visibleVoters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [visibleVoters]);

  const currentCaboName = useMemo(() => {
    if (userRole !== 'cabo') return 'Administrador Master';
    return cabos.find(c => c.id === loggedCaboId)?.name || 'Cabo Eleitoral';
  }, [userRole, loggedCaboId, cabos]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in-95 duration-500">

          {loginStep === 'role-selection' && (
            <div className="flex flex-col md:flex-row">
              <div 
                className="flex-1 p-12 bg-white flex flex-col justify-center border-b md:border-b-0 md:border-r border-slate-100 hover:bg-slate-50 transition-all group cursor-pointer" 
                onClick={() => handleRoleSelect('master')}
              >
                <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mb-8 group-hover:scale-110 transition-transform">
                  <ShieldCheck size={40} />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-2">Sou Político</h2>
                <p className="text-slate-500 text-sm leading-relaxed mb-6">Acesso total ao painel estratégico, equipe e configurações de campanha.</p>
                <div className="flex items-center gap-2 text-indigo-600 font-black uppercase text-xs tracking-widest">
                  Entrar como Master <ArrowRight size={16} />
                </div>
              </div>

              <div 
                className="flex-1 p-12 bg-white flex flex-col justify-center hover:bg-slate-50 transition-all group cursor-pointer" 
                onClick={() => handleRoleSelect('cabo')}
              >
                <div className="w-20 h-20 bg-orange-500 rounded-3xl flex items-center justify-center text-white shadow-2xl mb-8 group-hover:scale-110 transition-transform">
                  <Briefcase size={40} />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-2">Sou Liderança</h2>
                <p className="text-slate-500 text-sm leading-relaxed mb-6">Acesso restrito para cadastrar eleitores e acompanhar metas individuais.</p>
                <div className="flex items-center gap-2 text-orange-600 font-black uppercase text-xs tracking-widest">
                  Entrar como Cabo <ArrowRight size={16} />
                </div>
              </div>
            </div>
          )}

          {loginStep === 'auth' && (
            <div className="p-12 md:p-20 bg-white">
              <button 
                onClick={() => { setLoginStep('role-selection'); setSelectedRole(null); }} 
                className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest mb-10 hover:text-indigo-600 transition-colors"
              >
                <ChevronLeft size={16} /> Voltar ao Início
              </button>

              <div className="max-w-md mx-auto space-y-10">
                <div className="text-center">
                  <div className={`w-16 h-16 ${selectedRole === 'master' ? 'bg-indigo-600' : 'bg-orange-500'} rounded-2xl flex items-center justify-center text-white shadow-xl mx-auto mb-6`}>
                    <Lock size={32} />
                  </div>
                  <h2 className="text-2xl font-black text-slate-800">Senha de Acesso</h2>
                  <p className="text-slate-400 text-sm font-medium mt-1">Perfil: {selectedRole === 'master' ? 'Político / Master' : 'Cabo / Liderança'}</p>
                </div>

                <form onSubmit={handlePasswordSubmit} className="space-y-6">
                  <div className="relative group">
                    <input 
                      type={showPassword ? "text" : "password"} 
                      value={passwordInput}
                      onChange={(e) => setPasswordInput(e.target.value)}
                      className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                      placeholder="•••"
                      autoFocus
                    />
                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                      {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                    </button>
                  </div>
                  {loginError && <p className="text-red-500 text-xs text-center font-bold">Senha "123" incorreta!</p>}

                  <button type="submit" className={`w-full py-5 ${selectedRole === 'master' ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' : 'bg-orange-500 hover:bg-orange-600 shadow-orange-100'} text-white rounded-2xl font-black text-lg transition-all shadow-xl active:scale-95`}>
                    Entrar no Sistema
                  </button>
                </form>
              </div>
            </div>
          )}

          {loginStep === 'selection' && (
            <div className="p-12 md:p-20 bg-white">
              <button 
                onClick={() => { setLoginStep('role-selection'); setSelectedRole(null); }} 
                className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest mb-10 hover:text-orange-500 transition-colors"
              >
                <ChevronLeft size={16} /> Voltar ao Início
              </button>

              <div className="max-w-md mx-auto space-y-8">
                 <div className="text-center">
                    <h2 className="text-2xl font-black text-slate-800">Quem é você?</h2>
                    <p className="text-slate-400 text-sm font-medium mt-1">Selecione seu nome para acessar seus dados.</p>
                 </div>

                 <div className="max-h-[350px] overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                    {cabos.map(c => (
                      <button 
                        key={c.id} 
                        onClick={() => finalizeLogin('cabo', c.id)}
                        className="w-full p-5 bg-slate-50 hover:bg-orange-50 border-2 border-slate-100 hover:border-orange-200 rounded-[1.5rem] text-left font-bold text-slate-700 flex items-center justify-between transition-all group"
                      >
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-orange-500 font-black shadow-sm group-hover:bg-orange-500 group-hover:text-white transition-all">
                              {c.name.charAt(0)}
                           </div>
                           {c.name}
                        </div>
                        <ArrowRight size={18} className="text-orange-300 group-hover:translate-x-1 transition-all" />
                      </button>
                    ))}
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // Dashboard Inicial para o Político
  if (!politicalProfile && userRole === 'master') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Configurar Campanha</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Defina os dados mestres da sua jornada eleitoral.</p>
            </div>
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Nome do Candidato</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Cargo Almejado</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Abrangência</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal</option>
                  <option value="estadual">Estadual</option>
                </select>
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Meta de Votos</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all">
              Criar Perfil de Campanha <ArrowRight />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Menu Lateral */}
      <nav className="w-full md:w-72 bg-indigo-950 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile?.name || 'Sistema'}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                {userRole === 'master' ? <ShieldCheck size={12} /> : <UserCheck size={12} />}
                {userRole === 'master' ? 'Gestão Master' : 'Equipe de Campo'}
              </p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Início / Dashboard" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label={userRole === 'master' ? "Lista de Eleitores" : "Meus Eleitores"} />

          {userRole === 'master' && (
            <>
              <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Minha Equipe" color="orange" />
              <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Família" color="pink" />
              <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Atendimentos" color="emerald" />
            </>
          )}

          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Eleitor" />

          {userRole === 'master' && (
            <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Ajustes" color="slate" />
          )}
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <p className="text-indigo-400 text-[9px] font-black uppercase mb-1">
              Votos Garantidos
            </p>
            <p className="text-3xl font-black">
              {userRole === 'master' ? (voters.length + cabos.length) : (visibleVoters.length + 1)}
            </p>
          </div>

          {/* BOTÃO ENCERRAR SESSÃO - ATIVADO */}
          <button 
            onClick={handleLogout} 
            className="w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-red-500/20 active:scale-95"
          >
            <LogOut size={16} /> Encerrar Sessão
          </button>
        </div>
      </nav>

      {/* Conteúdo Principal */}
      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-4">
             <div>
                <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest leading-none">Usuário:</h2>
                <p className="text-xl font-black text-indigo-900">{currentCaboName}</p>
             </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar eleitor..."
                className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white focus:ring-4 focus:ring-indigo-500/10 shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="relative group cursor-pointer p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{birthdayVoters.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <div className="flex justify-between items-center">
                <div>
                  <h2 className="text-3xl font-black text-slate-800">Métricas da Campanha</h2>
                  <p className="text-slate-500">Acompanhamento do desempenho e alcance eleitoral.</p>
                </div>
              </div>

              <Dashboard 
                voters={visibleVoters} 
                cabos={userRole === 'master' ? cabos : []} 
                voteGoal={userRole === 'master' ? (politicalProfile?.voteGoal || 0) : (cabos.find(c => c.id === loggedCaboId)?.voterGoal || 0)} 
                scope={politicalProfile?.scope || 'municipal'} 
                onEditGoal={() => userRole === 'master' && setActiveTab('profile')} 
                role={userRole}
              />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={visibleVoters} /></div>
                <div className="lg:col-span-5 space-y-10">
                   {userRole === 'master' && (
                     <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                       <h3 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-xl"><Flag className="text-orange-500" /> Equipe</h3>
                       <div className="space-y-4">
                          <div className="p-4 bg-orange-50 rounded-2xl border border-orange-100 flex justify-between items-center">
                            <span className="text-xs font-black text-orange-600 uppercase">Cabos Ativos</span>
                            <span className="text-2xl font-black text-orange-700">{cabos.length}</span>
                          </div>
                          <button onClick={() => setActiveTab('cabos')} className="w-full py-4 bg-orange-500 text-white rounded-xl font-bold hover:bg-orange-600 transition-all flex items-center justify-center gap-2">
                             Gerenciar Time <ArrowRight size={18} />
                          </button>
                       </div>
                     </div>
                   )}
                   <BirthdayWidget voters={visibleVoters} />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'cabos' && userRole === 'master' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">Equipe de Lideranças</h2>
                <button onClick={() => { setEditingCabo(null); setIsCaboModalOpen(true); }} className="px-8 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg hover:bg-orange-600 transition-all flex items-center gap-2">
                  <UserPlus size={20} /> Adicionar Cabo
                </button>
              </div>
              <CaboList cabos={cabos} voters={voters} onDelete={deleteCabo} onEdit={(c) => { setEditingCabo(c); setIsCaboModalOpen(true); }} scope={politicalProfile?.scope || 'municipal'} />

              {isCaboModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-6 animate-in fade-in duration-200">
                  <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl relative">
                    <button onClick={() => setIsCaboModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600">
                      <X size={24} />
                    </button>
                    <CaboForm 
                      scope={politicalProfile?.scope || 'municipal'} 
                      onSubmit={editingCabo ? updateCabo : addCabo} 
                      onCancel={() => setIsCaboModalOpen(false)} 
                      initialData={editingCabo || undefined} 
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <h2 className="text-4xl font-black text-slate-800">Lista de Eleitores</h2>
              <VoterList 
                voters={filteredVotersList} 
                onDelete={deleteVoter} 
                onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} 
                onManageHelp={(v) => { 
                   if(userRole === 'master') {
                      setEditingVoter(v); 
                      setActiveTab('help');
                   } else {
                      alert("Acesso restrito para ações sociais.");
                   }
                }} 
              />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <VoterForm 
                cabos={userRole === 'master' ? cabos : []} 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => setActiveTab('list')} 
                initialData={editingVoter || undefined}
                fixedCaboId={userRole === 'cabo' ? (loggedCaboId || undefined) : undefined}
              />
            </div>
          )}

          {activeTab === 'help' && userRole === 'master' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {activeTab === 'profile' && userRole === 'master' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Perfil de Campanha</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome</label>
                      <input name="name" defaultValue={politicalProfile?.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile?.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all">Salvar Perfil</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 scale-[1.02]';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20 scale-[1.02]';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20 scale-[1.02]';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-indigo-300 hover:bg-white/5 active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile, CaboEleitoral, UserRole } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import CaboForm from './components/CaboForm';
import CaboList from './components/CaboList';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Search,
  Bell,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Flag,
  X,
  ShieldCheck,
  Briefcase,
  UserCheck,
  ChevronLeft,
  Sparkles
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [loggedCaboId, setLoggedCaboId] = useState<string | null>(null);

  // Fluxo de login: 'role-selection' -> 'auth' -> 'selection'
  const [loginStep, setLoginStep] = useState<'role-selection' | 'auth' | 'selection'>('role-selection');
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Carregar dados persistidos e verificar sessão existente
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    const role = sessionStorage.getItem('user_role') as UserRole;
    const caboId = sessionStorage.getItem('logged_cabo_id');

    if (auth === 'true') {
      setIsAuthenticated(true);
      setUserRole(role);
      setLoggedCaboId(caboId);
    }
  }, []);

  // Sincronização automática com LocalStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handleRoleSelect = (role: UserRole) => {
    if (role === 'cabo' && cabos.length === 0) {
      alert("⚠️ Atenção: Não existem Cabos Eleitorais cadastrados. Por favor, acesse como Político (Master) para configurar sua equipe.");
      return;
    }
    setSelectedRole(role);
    setLoginStep('auth');
    setLoginError(false);
    setPasswordInput('');
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setLoginError(false);
      if (selectedRole === 'master') {
        finalizeLogin('master', null);
      } else {
        setLoginStep('selection');
      }
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const finalizeLogin = (role: UserRole, caboId: string | null) => {
    setIsAuthenticated(true);
    setUserRole(role);
    setLoggedCaboId(caboId);
    sessionStorage.setItem('is_authenticated', 'true');
    sessionStorage.setItem('user_role', role);
    if (caboId) sessionStorage.setItem('logged_cabo_id', caboId);
  };

  /**
   * MÉTODO: ENCERRAR SESSÃO
   * Resolve o erro de fluxo garantindo que o usuário volte ao Início Real (role-selection)
   */
  const handleLogout = () => {
    if (window.confirm('Deseja realmente ENCERRAR A SESSÃO e voltar ao início?')) {
      // 1. Limpa o armazenamento temporário de sessão
      sessionStorage.clear();

      // 2. Reseta estados da aplicação para o valor padrão
      setIsAuthenticated(false);
      setUserRole(null);
      setLoggedCaboId(null);
      setSelectedRole(null);
      setLoginStep('role-selection');
      setPasswordInput('');
      setLoginError(false);

      // 3. Força o redirecionamento para o root da URL, garantindo um reset total do DOM e memória
      window.location.href = window.location.pathname;
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const visibleVoters = useMemo(() => {
    if (userRole === 'master') return voters;
    return voters.filter(v => v.caboId === loggedCaboId);
  }, [voters, userRole, loggedCaboId]);

  const addVoter = (data: VoterFormData) => {
    const finalData = userRole === 'cabo' ? { ...data, caboId: loggedCaboId || '' } : data;
    const newVoter: Voter = {
      ...finalData,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Deseja excluir este eleitor permanentemente?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Excluir cabo eleitoral da base?')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVotersList = useMemo(() => {
    let list = visibleVoters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [visibleVoters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return visibleVoters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [visibleVoters]);

  const currentCaboName = useMemo(() => {
    if (userRole !== 'cabo') return 'Candidato / Master';
    return cabos.find(c => c.id === loggedCaboId)?.name || 'Cabo Eleitoral';
  }, [userRole, loggedCaboId, cabos]);

  // TELA DE ACESSO (NÃO AUTENTICADO)
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in-95 duration-500">

          {loginStep === 'role-selection' && (
            <div className="flex flex-col md:flex-row">
              <div 
                className="flex-1 p-12 bg-white flex flex-col justify-center border-b md:border-b-0 md:border-r border-slate-100 hover:bg-slate-50 transition-all group cursor-pointer" 
                onClick={() => handleRoleSelect('master')}
              >
                <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mb-8 group-hover:scale-110 transition-transform">
                  <ShieldCheck size={40} />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-2">Painel Político</h2>
                <p className="text-slate-500 text-sm leading-relaxed mb-6">Área dedicada ao Candidato ou Administrador Master para gestão total.</p>
                <div className="flex items-center gap-2 text-indigo-600 font-black uppercase text-xs tracking-widest">
                  Entrar como Master <ArrowRight size={16} />
                </div>
              </div>

              <div 
                className="flex-1 p-12 bg-white flex flex-col justify-center hover:bg-slate-50 transition-all group cursor-pointer" 
                onClick={() => handleRoleSelect('cabo')}
              >
                <div className="w-20 h-20 bg-orange-500 rounded-3xl flex items-center justify-center text-white shadow-2xl mb-8 group-hover:scale-110 transition-transform">
                  <Briefcase size={40} />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-2">Painel Liderança</h2>
                <p className="text-slate-500 text-sm leading-relaxed mb-6">Acesso exclusivo para Cabos Eleitorais gerenciarem suas metas.</p>
                <div className="flex items-center gap-2 text-orange-600 font-black uppercase text-xs tracking-widest">
                  Entrar como Cabo <ArrowRight size={16} />
                </div>
              </div>
            </div>
          )}

          {loginStep === 'auth' && (
            <div className="p-12 md:p-20 bg-white">
              <button 
                onClick={() => { setLoginStep('role-selection'); setSelectedRole(null); }} 
                className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest mb-10 hover:text-indigo-600 transition-colors"
              >
                <ChevronLeft size={16} /> Voltar ao Início
              </button>

              <div className="max-w-md mx-auto space-y-10">
                <div className="text-center">
                  <div className={`w-16 h-16 ${selectedRole === 'master' ? 'bg-indigo-600' : 'bg-orange-500'} rounded-2xl flex items-center justify-center text-white shadow-xl mx-auto mb-6`}>
                    <Lock size={32} />
                  </div>
                  <h2 className="text-2xl font-black text-slate-800">Senha do Sistema</h2>
                  <p className="text-slate-400 text-sm font-medium mt-1">Acesso para: {selectedRole === 'master' ? 'Candidato' : 'Equipe de Campo'}</p>
                </div>

                <form onSubmit={handlePasswordSubmit} className="space-y-6">
                  <div className="relative group">
                    <input 
                      type={showPassword ? "text" : "password"} 
                      value={passwordInput}
                      onChange={(e) => setPasswordInput(e.target.value)}
                      className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                      placeholder="•••"
                      autoFocus
                    />
                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                      {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                    </button>
                  </div>
                  {loginError && <p className="text-red-500 text-xs text-center font-bold">Senha de demonstração (123) incorreta!</p>}

                  <button type="submit" className={`w-full py-5 ${selectedRole === 'master' ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' : 'bg-orange-500 hover:bg-orange-600 shadow-orange-100'} text-white rounded-2xl font-black text-lg transition-all shadow-xl active:scale-95`}>
                    Confirmar e Acessar
                  </button>
                </form>
              </div>
            </div>
          )}

          {loginStep === 'selection' && (
            <div className="p-12 md:p-20 bg-white">
              <button 
                onClick={() => { setLoginStep('role-selection'); setSelectedRole(null); }} 
                className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest mb-10 hover:text-orange-500 transition-colors"
              >
                <ChevronLeft size={16} /> Voltar ao Início
              </button>

              <div className="max-w-md mx-auto space-y-8">
                 <div className="text-center">
                    <h2 className="text-2xl font-black text-slate-800">Identifique-se</h2>
                    <p className="text-slate-400 text-sm font-medium mt-1">Selecione seu nome para gerenciar sua base de eleitores.</p>
                 </div>

                 <div className="max-h-[350px] overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                    {cabos.map(c => (
                      <button 
                        key={c.id} 
                        onClick={() => finalizeLogin('cabo', c.id)}
                        className="w-full p-5 bg-slate-50 hover:bg-orange-50 border-2 border-slate-100 hover:border-orange-200 rounded-[1.5rem] text-left font-bold text-slate-700 flex items-center justify-between transition-all group"
                      >
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-orange-500 font-black shadow-sm group-hover:bg-orange-500 group-hover:text-white transition-all">
                              {c.name.charAt(0)}
                           </div>
                           {c.name}
                        </div>
                        <ArrowRight size={18} className="text-orange-300 group-hover:translate-x-1 transition-all" />
                      </button>
                    ))}
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // TELA DE CONFIGURAÇÃO INICIAL (APENAS MASTER)
  if (!politicalProfile && userRole === 'master') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Painel de Campanha</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Primeiro, configure os dados principais da sua candidatura.</p>
            </div>
            <Sparkles className="absolute -bottom-10 -right-10 text-white/10" size={200} />
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Político</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Cargo</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: Vereador" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Escopo</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal</option>
                  <option value="estadual">Estadual</option>
                </select>
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Global de Votos</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="0" />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all active:scale-95">
              Iniciar Gerenciamento <ArrowRight />
            </button>
          </form>
        </div>
      </div>
    );
  }

  // INTERFACE PRINCIPAL (AUTENTICADO)
  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar de Navegação */}
      <nav className="w-full md:w-72 bg-indigo-950 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile?.name || 'Sistema'}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                {userRole === 'master' ? <ShieldCheck size={12} /> : <UserCheck size={12} />}
                {userRole === 'master' ? 'Gestão Master' : 'Liderança Ativa'}
              </p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label={userRole === 'master' ? "Todos Eleitores" : "Minha Base"} />

          {userRole === 'master' && (
            <>
              <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Equipe de Cabos" color="orange" />
              <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Núcleo Familiar" color="pink" />
              <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Atendimentos" color="emerald" />
            </>
          )}

          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Cadastro" />

          {userRole === 'master' && (
            <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Ajustes Campanha" color="slate" />
          )}
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <p className="text-indigo-400 text-[9px] font-black uppercase mb-1">Potencial de Votos</p>
            <p className="text-3xl font-black">
              {userRole === 'master' ? (voters.length + cabos.length) : (visibleVoters.length + 1)}
            </p>
          </div>

          {/* BOTÃO ENCERRAR SESSÃO - FUNCIONAMENTO GARANTIDO */}
          <button 
            onClick={handleLogout} 
            className="w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-red-500/20 active:scale-95"
          >
            <LogOut size={16} /> Encerrar Sessão
          </button>
        </div>
      </nav>

      {/* Área de Conteúdo */}
      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-4">
             <div>
                <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest leading-none">Usuário:</h2>
                <p className="text-xl font-black text-indigo-900">{currentCaboName}</p>
             </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Localizar eleitor..."
                className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white focus:ring-4 focus:ring-indigo-500/10 shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="relative group cursor-pointer p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{birthdayVoters.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <div className="flex justify-between items-center">
                <div>
                  <h2 className="text-3xl font-black text-slate-800">Visão Geral</h2>
                  <p className="text-slate-500">Acompanhamento de metas e evolução da base.</p>
                </div>
              </div>

              <Dashboard 
                voters={visibleVoters} 
                cabos={userRole === 'master' ? cabos : []} 
                voteGoal={userRole === 'master' ? (politicalProfile?.voteGoal || 0) : (cabos.find(c => c.id === loggedCaboId)?.voterGoal || 0)} 
                scope={politicalProfile?.scope || 'municipal'} 
                onEditGoal={() => userRole === 'master' && setActiveTab('profile')} 
                role={userRole}
              />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={visibleVoters} /></div>
                <div className="lg:col-span-5 space-y-10">
                   {userRole === 'master' && (
                     <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                       <h3 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-xl"><Flag className="text-orange-500" /> Equipe</h3>
                       <div className="space-y-4">
                          <div className="p-4 bg-orange-50 rounded-2xl border border-orange-100 flex justify-between items-center">
                            <span className="text-xs font-black text-orange-600 uppercase">Cabos Vinculados</span>
                            <span className="text-2xl font-black text-orange-700">{cabos.length}</span>
                          </div>
                          <button onClick={() => setActiveTab('cabos')} className="w-full py-4 bg-orange-500 text-white rounded-xl font-bold hover:bg-orange-600 transition-all flex items-center justify-center gap-2">
                             Gerenciar Lideranças <ArrowRight size={18} />
                          </button>
                       </div>
                     </div>
                   )}
                   <BirthdayWidget voters={visibleVoters} />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'cabos' && userRole === 'master' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">Equipe de Lideranças</h2>
                <button onClick={() => { setEditingCabo(null); setIsCaboModalOpen(true); }} className="px-8 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg hover:bg-orange-600 transition-all flex items-center gap-2">
                  <UserPlus size={20} /> Adicionar Liderança
                </button>
              </div>
              <CaboList cabos={cabos} voters={voters} onDelete={deleteCabo} onEdit={(c) => { setEditingCabo(c); setIsCaboModalOpen(true); }} scope={politicalProfile?.scope || 'municipal'} />

              {isCaboModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-6 animate-in fade-in duration-200">
                  <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl relative">
                    <button onClick={() => setIsCaboModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600">
                      <X size={24} />
                    </button>
                    <CaboForm 
                      scope={politicalProfile?.scope || 'municipal'} 
                      onSubmit={editingCabo ? updateCabo : addCabo} 
                      onCancel={() => setIsCaboModalOpen(false)} 
                      initialData={editingCabo || undefined} 
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <h2 className="text-4xl font-black text-slate-800">Base de Dados</h2>
              <VoterList 
                voters={filteredVotersList} 
                onDelete={deleteVoter} 
                onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} 
                onManageHelp={(v) => { 
                   if(userRole === 'master') {
                      setEditingVoter(v); 
                      setActiveTab('help');
                   } else {
                      alert("⚠️ Ação restrita: Somente o Master pode registrar atendimentos sociais.");
                   }
                }} 
              />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <VoterForm 
                cabos={userRole === 'master' ? cabos : []} 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => setActiveTab('list')} 
                initialData={editingVoter || undefined}
                fixedCaboId={userRole === 'cabo' ? (loggedCaboId || undefined) : undefined}
              />
            </div>
          )}

          {activeTab === 'help' && userRole === 'master' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {activeTab === 'profile' && userRole === 'master' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Ajustes Gerais</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome de Campanha</label>
                      <input name="name" defaultValue={politicalProfile?.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral (Votos)</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile?.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all">Atualizar Dados</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 scale-[1.02]';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20 scale-[1.02]';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20 scale-[1.02]';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-indigo-300 hover:bg-white/5 active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile, CaboEleitoral, UserRole } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import CaboForm from './components/CaboForm';
import CaboList from './components/CaboList';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Search,
  Bell,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Flag,
  X,
  ShieldCheck,
  Briefcase,
  UserCheck,
  ChevronLeft,
  Sparkles
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [loggedCaboId, setLoggedCaboId] = useState<string | null>(null);

  // Fluxo de login: 'role-selection' -> 'auth' -> 'selection'
  const [loginStep, setLoginStep] = useState<'role-selection' | 'auth' | 'selection'>('role-selection');
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Carregar dados persistidos e verificar sessão existente
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    const role = sessionStorage.getItem('user_role') as UserRole;
    const caboId = sessionStorage.getItem('logged_cabo_id');

    if (auth === 'true') {
      setIsAuthenticated(true);
      setUserRole(role);
      setLoggedCaboId(caboId);
    }
  }, []);

  // Sincronização automática com LocalStorage (Voters e Cabos)
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handleRoleSelect = (role: UserRole) => {
    if (role === 'cabo' && cabos.length === 0) {
      alert("⚠️ Atenção: Não existem lideranças cadastradas. Acesse como Político para cadastrar sua equipe.");
      return;
    }
    setSelectedRole(role);
    setLoginStep('auth');
    setLoginError(false);
    setPasswordInput('');
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setLoginError(false);
      if (selectedRole === 'master') {
        finalizeLogin('master', null);
      } else {
        setLoginStep('selection');
      }
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const finalizeLogin = (role: UserRole, caboId: string | null) => {
    setIsAuthenticated(true);
    setUserRole(role);
    setLoggedCaboId(caboId);
    sessionStorage.setItem('is_authenticated', 'true');
    sessionStorage.setItem('user_role', role);
    if (caboId) sessionStorage.setItem('logged_cabo_id', caboId);
  };

  /**
   * PROGRAMAÇÃO DO BOTÃO ENCERRAR SESSÃO
   * Esta função limpa tudo e força o retorno à tela inicial de login.
   */
  const handleLogout = () => {
    if (window.confirm('Deseja realmente ENCERRAR A SESSÃO e voltar à tela inicial de login?')) {
      // 1. Limpa os dados de sessão do navegador
      sessionStorage.clear();

      // 2. Reseta os estados locais da aplicação
      setIsAuthenticated(false);
      setUserRole(null);
      setLoggedCaboId(null);
      setSelectedRole(null);
      setLoginStep('role-selection');
      setPasswordInput('');
      setLoginError(false);

      // 3. Força o recarregamento total da página (Hard Refresh)
      window.location.reload();
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const visibleVoters = useMemo(() => {
    if (userRole === 'master') return voters;
    return voters.filter(v => v.caboId === loggedCaboId);
  }, [voters, userRole, loggedCaboId]);

  const addVoter = (data: VoterFormData) => {
    const finalData = userRole === 'cabo' ? { ...data, caboId: loggedCaboId || '' } : data;
    const newVoter: Voter = {
      ...finalData,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Confirmar exclusão de eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Excluir liderança da equipe?')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVotersList = useMemo(() => {
    let list = visibleVoters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [visibleVoters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return visibleVoters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [visibleVoters]);

  const currentCaboName = useMemo(() => {
    if (userRole !== 'cabo') return 'Acesso Político Master';
    return cabos.find(c => c.id === loggedCaboId)?.name || 'Cabo Eleitoral';
  }, [userRole, loggedCaboId, cabos]);

  // RENDERIZAÇÃO DA TELA DE LOGIN (ESTADO INICIAL)
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-indigo-950 to-black">
        <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in-95 duration-500">

          {loginStep === 'role-selection' && (
            <div className="flex flex-col md:flex-row">
              <div 
                className="flex-1 p-12 bg-white flex flex-col justify-center border-b md:border-b-0 md:border-r border-slate-100 hover:bg-slate-50 transition-all group cursor-pointer" 
                onClick={() => handleRoleSelect('master')}
              >
                <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mb-8 group-hover:scale-110 transition-transform">
                  <ShieldCheck size={40} />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-2">Político / Master</h2>
                <p className="text-slate-500 text-sm leading-relaxed mb-6">Controle total da campanha, equipe de campo e investimentos sociais.</p>
                <div className="flex items-center gap-2 text-indigo-600 font-black uppercase text-xs tracking-widest">
                  Entrar como Master <ArrowRight size={16} />
                </div>
              </div>

              <div 
                className="flex-1 p-12 bg-white flex flex-col justify-center hover:bg-slate-50 transition-all group cursor-pointer" 
                onClick={() => handleRoleSelect('cabo')}
              >
                <div className="w-20 h-20 bg-orange-500 rounded-3xl flex items-center justify-center text-white shadow-2xl mb-8 group-hover:scale-110 transition-transform">
                  <Briefcase size={40} />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-2">Cabo Eleitoral</h2>
                <p className="text-slate-500 text-sm leading-relaxed mb-6">Acesso individual para cadastrar sua base e acompanhar metas pessoais.</p>
                <div className="flex items-center gap-2 text-orange-600 font-black uppercase text-xs tracking-widest">
                  Entrar como Cabo <ArrowRight size={16} />
                </div>
              </div>
            </div>
          )}

          {loginStep === 'auth' && (
            <div className="p-12 md:p-20 bg-white">
              <button 
                onClick={() => { setLoginStep('role-selection'); setSelectedRole(null); }} 
                className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest mb-10 hover:text-indigo-600 transition-colors"
              >
                <ChevronLeft size={16} /> Voltar ao Início
              </button>

              <div className="max-w-md mx-auto space-y-10">
                <div className="text-center">
                  <div className={`w-16 h-16 ${selectedRole === 'master' ? 'bg-indigo-600' : 'bg-orange-500'} rounded-2xl flex items-center justify-center text-white shadow-xl mx-auto mb-6`}>
                    <Lock size={32} />
                  </div>
                  <h2 className="text-2xl font-black text-slate-800">Autenticação</h2>
                  <p className="text-slate-400 text-sm font-medium mt-1">Perfil: {selectedRole === 'master' ? 'Político Master' : 'Equipe de Liderança'}</p>
                </div>

                <form onSubmit={handlePasswordSubmit} className="space-y-6">
                  <div className="relative group">
                    <input 
                      type={showPassword ? "text" : "password"} 
                      value={passwordInput}
                      onChange={(e) => setPasswordInput(e.target.value)}
                      className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                      placeholder="•••"
                      autoFocus
                    />
                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                      {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                    </button>
                  </div>
                  {loginError && <p className="text-red-500 text-xs text-center font-bold">Senha "123" inválida!</p>}

                  <button type="submit" className={`w-full py-5 ${selectedRole === 'master' ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' : 'bg-orange-500 hover:bg-orange-600 shadow-orange-100'} text-white rounded-2xl font-black text-lg transition-all shadow-xl active:scale-95`}>
                    Confirmar Senha
                  </button>
                </form>
              </div>
            </div>
          )}

          {loginStep === 'selection' && (
            <div className="p-12 md:p-20 bg-white">
              <button 
                onClick={() => { setLoginStep('role-selection'); setSelectedRole(null); }} 
                className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest mb-10 hover:text-orange-500 transition-colors"
              >
                <ChevronLeft size={16} /> Voltar ao Início
              </button>

              <div className="max-w-md mx-auto space-y-8">
                 <div className="text-center">
                    <h2 className="text-2xl font-black text-slate-800">Selecione seu Nome</h2>
                    <p className="text-slate-400 text-sm font-medium mt-1">Identifique-se para acessar seus eleitores.</p>
                 </div>

                 <div className="max-h-[350px] overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                    {cabos.map(c => (
                      <button 
                        key={c.id} 
                        onClick={() => finalizeLogin('cabo', c.id)}
                        className="w-full p-5 bg-slate-50 hover:bg-orange-50 border-2 border-slate-100 hover:border-orange-200 rounded-[1.5rem] text-left font-bold text-slate-700 flex items-center justify-between transition-all group"
                      >
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-orange-500 font-black shadow-sm group-hover:bg-orange-500 group-hover:text-white transition-all">
                              {c.name.charAt(0)}
                           </div>
                           {c.name}
                        </div>
                        <ArrowRight size={18} className="text-orange-300 group-hover:translate-x-1 transition-all" />
                      </button>
                    ))}
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // TELA DE CONFIGURAÇÃO (APENAS MASTER NO PRIMEIRO ACESSO)
  if (!politicalProfile && userRole === 'master') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Configurar Perfil</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Dados mestres da sua candidatura política.</p>
            </div>
            <Sparkles className="absolute -bottom-10 -right-10 text-white/10" size={200} />
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Político</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Cargo</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Vereador" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Abrangência</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal</option>
                  <option value="estadual">Estadual</option>
                </select>
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral de Votos</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="5000" />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all">
              Criar Painel Eleitoral <ArrowRight />
            </button>
          </form>
        </div>
      </div>
    );
  }

  // INTERFACE PRINCIPAL (SISTEMA LOGADO)
  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      <nav className="w-full md:w-72 bg-indigo-950 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile?.name || 'Sistema'}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                {userRole === 'master' ? <ShieldCheck size={12} /> : <UserCheck size={12} />}
                {userRole === 'master' ? 'Gestão Central' : 'Liderança de Campo'}
              </p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label={userRole === 'master' ? "Lista Geral" : "Meus Eleitores"} />

          {userRole === 'master' && (
            <>
              <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Equipe (Cabos)" color="orange" />
              <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Família" color="pink" />
              <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Ações Sociais" color="emerald" />
            </>
          )}

          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Cadastrar Novo" />

          {userRole === 'master' && (
            <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Configurações" color="slate" />
          )}
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <p className="text-indigo-400 text-[9px] font-black uppercase mb-1">Total de Votos</p>
            <p className="text-3xl font-black">
              {userRole === 'master' ? (voters.length + cabos.length) : (visibleVoters.length + 1)}
            </p>
          </div>

          {/* BOTÃO ENCERRAR SESSÃO - FUNCIONANDO COM VOLTA AO INÍCIO */}
          <button 
            onClick={handleLogout} 
            className="w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-red-500/20 active:scale-95"
          >
            <LogOut size={16} /> Encerrar Sessão
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-4">
             <div>
                <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest leading-none">Usuário Ativo:</h2>
                <p className="text-xl font-black text-indigo-900">{currentCaboName}</p>
             </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar eleitor..."
                className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white focus:ring-4 focus:ring-indigo-500/10 shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="relative group cursor-pointer p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{birthdayVoters.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <div className="flex justify-between items-center">
                <div>
                  <h2 className="text-3xl font-black text-slate-800">Painel de Métricas</h2>
                  <p className="text-slate-500">Monitoramento da base de dados e meta eleitoral.</p>
                </div>
              </div>

              <Dashboard 
                voters={visibleVoters} 
                cabos={userRole === 'master' ? cabos : []} 
                voteGoal={userRole === 'master' ? (politicalProfile?.voteGoal || 0) : (cabos.find(c => c.id === loggedCaboId)?.voterGoal || 0)} 
                scope={politicalProfile?.scope || 'municipal'} 
                onEditGoal={() => userRole === 'master' && setActiveTab('profile')} 
                role={userRole}
              />

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={visibleVoters} /></div>
                <div className="lg:col-span-5 space-y-10">
                   {userRole === 'master' && (
                     <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                       <h3 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-xl"><Flag className="text-orange-500" /> Equipe</h3>
                       <div className="space-y-4">
                          <div className="p-4 bg-orange-50 rounded-2xl border border-orange-100 flex justify-between items-center">
                            <span className="text-xs font-black text-orange-600 uppercase">Lideranças Ativas</span>
                            <span className="text-2xl font-black text-orange-700">{cabos.length}</span>
                          </div>
                          <button onClick={() => setActiveTab('cabos')} className="w-full py-4 bg-orange-500 text-white rounded-xl font-bold hover:bg-orange-600 transition-all flex items-center justify-center gap-2">
                             Gerenciar Time <ArrowRight size={18} />
                          </button>
                       </div>
                     </div>
                   )}
                   <BirthdayWidget voters={visibleVoters} />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'cabos' && userRole === 'master' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">Equipe de Lideranças</h2>
                <button onClick={() => { setEditingCabo(null); setIsCaboModalOpen(true); }} className="px-8 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg hover:bg-orange-600 transition-all flex items-center gap-2">
                  <UserPlus size={20} /> Adicionar Cabo
                </button>
              </div>
              <CaboList cabos={cabos} voters={voters} onDelete={deleteCabo} onEdit={(c) => { setEditingCabo(c); setIsCaboModalOpen(true); }} scope={politicalProfile?.scope || 'municipal'} />

              {isCaboModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-6 animate-in fade-in duration-200">
                  <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl relative">
                    <button onClick={() => setIsCaboModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600">
                      <X size={24} />
                    </button>
                    <CaboForm 
                      scope={politicalProfile?.scope || 'municipal'} 
                      onSubmit={editingCabo ? updateCabo : addCabo} 
                      onCancel={() => setIsCaboModalOpen(false)} 
                      initialData={editingCabo || undefined} 
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <h2 className="text-4xl font-black text-slate-800">Eleitores Cadastrados</h2>
              <VoterList 
                voters={filteredVotersList} 
                onDelete={deleteVoter} 
                onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} 
                onManageHelp={(v) => { 
                   if(userRole === 'master') {
                      setEditingVoter(v); 
                      setActiveTab('help');
                   } else {
                      alert("⚠️ Ação exclusiva do Político Master: Registro de atendimentos sociais.");
                   }
                }} 
              />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <VoterForm 
                cabos={userRole === 'master' ? cabos : []} 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => setActiveTab('list')} 
                initialData={editingVoter || undefined}
                fixedCaboId={userRole === 'cabo' ? (loggedCaboId || undefined) : undefined}
              />
            </div>
          )}

          {activeTab === 'help' && userRole === 'master' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {activeTab === 'profile' && userRole === 'master' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Perfil da Campanha</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome</label>
                      <input name="name" defaultValue={politicalProfile?.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral (Votos)</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile?.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all">Salvar Alterações</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 scale-[1.02]';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20 scale-[1.02]';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20 scale-[1.02]';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-indigo-300 hover:bg-white/5 active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

export interface HelpRecord {
  id: string;
  description: string;
  date: string;
  category: string;
  value: number;
}

export interface PoliticalProfile {
  name: string;
  party: string;
  office: string; // Cargo (Ex: Vereador, Prefeito)
  scope: 'municipal' | 'estadual';
  slogan: string;
  voteGoal?: number; // Meta de votos
  number?: string;
}

export interface CaboEleitoral {
  id: string;
  name: string;
  phone: string;
  location: string; // Bairro se municipal, Cidade se estadual
  voterGoal: number; // Quantos eleitores este cabo pretende trazer
  hiredAt: string;
}

export interface Voter {
  id: string;
  name: string;
  birthDate: string; // ISO string YYYY-MM-DD
  gender: 'Masculino' | 'Feminino' | 'Outro';
  phone: string;
  email: string;
  address: string;
  neighborhood: string;
  observations: string;
  isFamilyMember: boolean;
  helpRecords?: HelpRecord[];
  createdAt: string;
  caboId?: string; // ID do cabo eleitoral responsável por este eleitor
}

export interface VoterFormData extends Omit<Voter, 'id' | 'createdAt' | 'helpRecords'> {}

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile, CaboEleitoral } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import CaboForm from './components/CaboForm';
import CaboList from './components/CaboList';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Search,
  Bell,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Flag,
  X,
  ShieldCheck,
  Briefcase,
  UserCheck,
  ChevronLeft,
  Sparkles
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Carregar dados
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  // Persistência
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente ENCERRAR A SESSÃO e sair do sistema?')) {
      sessionStorage.clear();
      setIsAuthenticated(false);
      window.location.reload();
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir eleitor?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Remover esta liderança?')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVotersList = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [voters]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-800 via-slate-900 to-black">
        <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden p-12 animate-in fade-in zoom-in-95 duration-500">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mx-auto mb-6">
              <ShieldCheck size={40} />
            </div>
            <h2 className="text-3xl font-black text-slate-800">Acesso Exclusivo</h2>
            <p className="text-slate-500 font-medium mt-2">Gestor de Campanha</p>
          </div>

          <form onSubmit={handlePasswordSubmit} className="space-y-6">
            <div className="relative group">
              <input 
                type={showPassword ? "text" : "password"} 
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                placeholder="•••"
                autoFocus
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
            {loginError && <p className="text-red-500 text-xs text-center font-bold">Senha de acesso inválida!</p>}

            <button type="submit" className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-indigo-100 active:scale-95">
              Entrar no Sistema
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (!politicalProfile) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Painel Administrativo</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Configure os dados principais para iniciar o gerenciamento.</p>
            </div>
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Nome Completo</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Cargo</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Âmbito</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal</option>
                  <option value="estadual">Estadual</option>
                </select>
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all">
              Criar Perfil <ArrowRight />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      <nav className="w-full md:w-72 bg-slate-900 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile.name}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                <ShieldCheck size={12} /> Administrador
              </p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Painel Geral" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Lista Eleitores" />
          <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Lideranças" color="orange" />
          <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Família" color="pink" />
          <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Atendimentos" color="emerald" />
          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Registro" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Configurações" color="slate" />
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <p className="text-indigo-400 text-[9px] font-black uppercase mb-1">Total da Base</p>
            <p className="text-3xl font-black">{voters.length}</p>
          </div>
          <button 
            onClick={handleLogout} 
            className="w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-red-500/20 active:scale-95"
          >
            <LogOut size={16} /> Encerrar Sessão
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-4">
             <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Sistema de Gestão</h2>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Pesquisar..."
                className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="relative group p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors cursor-pointer">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{birthdayVoters.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <Dashboard 
                voters={voters} 
                cabos={cabos} 
                voteGoal={politicalProfile.voteGoal || 0} 
                scope={politicalProfile.scope} 
                onEditGoal={() => setActiveTab('profile')} 
              />
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={voters} /></div>
                <div className="lg:col-span-5"><BirthdayWidget voters={voters} /></div>
              </div>
            </div>
          )}

          {activeTab === 'cabos' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">Equipe de Lideranças</h2>
                <button onClick={() => { setEditingCabo(null); setIsCaboModalOpen(true); }} className="px-8 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg hover:bg-orange-600 transition-all flex items-center gap-2">
                  <UserPlus size={20} /> Nova Liderança
                </button>
              </div>
              <CaboList cabos={cabos} voters={voters} onDelete={deleteCabo} onEdit={(c) => { setEditingCabo(c); setIsCaboModalOpen(true); }} scope={politicalProfile.scope} />

              {isCaboModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-6 animate-in fade-in duration-200">
                  <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl relative">
                    <button onClick={() => setIsCaboModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600">
                      <X size={24} />
                    </button>
                    <CaboForm 
                      scope={politicalProfile.scope} 
                      onSubmit={editingCabo ? updateCabo : addCabo} 
                      onCancel={() => setIsCaboModalOpen(false)} 
                      initialData={editingCabo || undefined} 
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <h2 className="text-4xl font-black text-slate-800">Eleitores Cadastrados</h2>
              <VoterList voters={filteredVotersList} onDelete={deleteVoter} onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <VoterForm 
                cabos={cabos} 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => setActiveTab('list')} 
                initialData={editingVoter || undefined}
              />
            </div>
          )}

          {activeTab === 'help' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {activeTab === 'profile' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Perfil de Campanha</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Político</label>
                      <input name="name" defaultValue={politicalProfile.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta de Votos</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all">Salvar Alterações</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 scale-[1.02]';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20 scale-[1.02]';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20 scale-[1.02]';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-slate-400 hover:bg-white/5 hover:text-white active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

