import React, { useMemo } from 'react';
import { Voter, CaboEleitoral } from '../types';
import { Users, UserCheck, MapPin, Target, Venus, Mars, Percent, Flag, Trophy } from 'lucide-react';

interface Props {
  voters: Voter[];
  cabos: CaboEleitoral[];
  voteGoal: number;
  scope: 'municipal' | 'estadual';
  onEditGoal: () => void;
}

const Dashboard: React.FC<Props> = ({ voters, cabos, voteGoal, scope, onEditGoal }) => {
  const stats = useMemo(() => {
    const totalPotentialVotes = voters.length + cabos.length;

    const maleCount = voters.filter(v => v.gender === 'Masculino').length;
    const femaleCount = voters.filter(v => v.gender === 'Feminino').length;

    const localDistribution: Record<string, { voters: number; cabos: number }> = {};

    voters.forEach(v => {
      const loc = v.neighborhood || 'Não Informado';
      if (!localDistribution[loc]) localDistribution[loc] = { voters: 0, cabos: 0 };
      localDistribution[loc].voters++;
    });

    cabos.forEach(c => {
      const loc = c.location || 'Não Informado';
      if (!localDistribution[loc]) localDistribution[loc] = { voters: 0, cabos: 0 };
      localDistribution[loc].cabos++;
    });

    const progress = voteGoal > 0 ? (totalPotentialVotes / voteGoal) * 100 : 0;
    const remaining = Math.max(0, voteGoal - totalPotentialVotes);

    return {
      total: totalPotentialVotes,
      votersOnly: voters.length,
      cabosTotal: cabos.length,
      gender: {
        male: { count: maleCount, pct: voters.length > 0 ? (maleCount / voters.length) * 100 : 0 },
        female: { count: femaleCount, pct: voters.length > 0 ? (femaleCount / voters.length) * 100 : 0 },
      },
      goal: { progress, remaining, goal: voteGoal },
      localDistribution: Object.entries(localDistribution)
        .map(([name, data]) => ({ name, ...data }))
        .sort((a, b) => (b.voters + b.cabos) - (a.voters + a.cabos))
        .slice(0, 5)
    };
  }, [voters, cabos, voteGoal]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Votos Estimados" 
          value={stats.total.toString()} 
          icon={<Users className="text-blue-600" />} 
          bgColor="bg-blue-50" 
        />
        <StatCard 
          label="Lideranças" 
          value={stats.cabosTotal.toString()} 
          icon={<Flag className="text-orange-600" />} 
          bgColor="bg-orange-50" 
        />
        <StatCard 
          label="Meta Atingida" 
          value={`${stats.goal.progress.toFixed(1)}%`} 
          icon={<Trophy className="text-amber-600" />} 
          bgColor="bg-amber-50" 
        />
        <StatCard 
          label="Restante p/ Meta" 
          value={stats.goal.remaining.toString()} 
          icon={<Target className="text-red-600" />} 
          bgColor="bg-red-50" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <div className="flex justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl">
              <Target size={24} className="text-indigo-600" /> 
              Progresso Geral
            </h3>
            <button onClick={onEditGoal} className="text-xs font-black text-indigo-600 uppercase">Ajustar Meta</button>
          </div>

          <div className="space-y-6">
            <div>
              <div className="flex justify-between text-sm font-bold mb-2">
                <span className="text-slate-500">Avanço Consolidado</span>
                <span className="text-indigo-600">{stats.total} / {voteGoal}</span>
              </div>
              <div className="h-4 w-full bg-slate-100 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-600 transition-all duration-1000" 
                  style={{ width: `${Math.min(100, stats.goal.progress)}%` }} 
                />
              </div>
            </div>

            <div className="pt-6 border-t border-slate-100">
              <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">
                Top {scope === 'municipal' ? 'Bairros' : 'Cidades'}
              </h4>
              <div className="space-y-3">
                {stats.localDistribution.length === 0 ? (
                  <p className="text-xs text-slate-400 italic">Sem registros geográficos.</p>
                ) : (
                  stats.localDistribution.map(loc => {
                    const totalInLoc = loc.voters + loc.cabos;
                    return (
                      <div key={loc.name} className="flex items-center gap-4">
                        <div className="w-24 text-[10px] font-black text-slate-400 uppercase truncate">{loc.name}</div>
                        <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-indigo-400" style={{ width: `${(totalInLoc / (stats.total || 1)) * 100}%` }} />
                        </div>
                        <div className="w-12 text-right text-xs font-black text-slate-700">{totalInLoc}</div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl mb-6"><Users size={24} className="text-indigo-600" /> Demografia</h3>
          <div className="space-y-10 py-4">
             <div className="flex items-center justify-around text-center">
                <div>
                  <div className="w-20 h-20 bg-pink-50 rounded-full flex items-center justify-center mx-auto mb-3 border-4 border-pink-100">
                    <Venus size={32} className="text-pink-600" />
                  </div>
                  <p className="text-2xl font-black text-slate-800">{stats.gender.female.pct.toFixed(1)}%</p>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Feminino</p>
                </div>
                <div className="h-16 w-px bg-slate-100"></div>
                <div>
                  <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-3 border-4 border-blue-100">
                    <Mars size={32} className="text-blue-600" />
                  </div>
                  <p className="text-2xl font-black text-slate-800">{stats.gender.male.pct.toFixed(1)}%</p>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Masculino</p>
                </div>
             </div>

             <div className="p-6 rounded-3xl border bg-indigo-50 border-indigo-100">
                <div className="flex items-center gap-3 mb-2">
                  <Percent size={18} className="text-indigo-600" />
                  <span className="text-sm font-black text-indigo-700">Conversão de Equipe</span>
                </div>
                <p className="text-xs text-indigo-600/70 font-medium">
                  Em média, cada liderança trouxe {(stats.votersOnly / (cabos.length || 1)).toFixed(1)} eleitores até agora.
                </p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: React.ReactNode; bgColor: string }> = ({ label, value, icon, bgColor }) => (
  <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-start justify-between">
    <div>
      <p className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">{label}</p>
      <p className="text-2xl font-black mt-1 text-slate-800">{value}</p>
    </div>
    <div className={`${bgColor} p-3 rounded-2xl`}>{icon}</div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Voter, VoterFormData, CaboEleitoral } from '../types';
import { Save, X, User, MapPin, Archive, Edit3, Heart, Users2, Venus, Mars, UserCheck } from 'lucide-react';

interface Props {
  onSubmit: (data: VoterFormData) => void;
  onCancel: () => void;
  initialData?: Voter;
  cabos: CaboEleitoral[];
}

const VoterForm: React.FC<Props> = ({ onSubmit, onCancel, initialData, cabos }) => {
  const [formData, setFormData] = useState<VoterFormData>({
    name: '',
    birthDate: '',
    gender: 'Masculino',
    phone: '',
    email: '',
    address: '',
    neighborhood: '',
    observations: '',
    isFamilyMember: false,
    caboId: '',
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        name: initialData.name,
        birthDate: initialData.birthDate,
        gender: initialData.gender || 'Masculino',
        phone: initialData.phone,
        email: initialData.email,
        address: initialData.address,
        neighborhood: initialData.neighborhood,
        observations: initialData.observations,
        isFamilyMember: initialData.isFamilyMember || false,
        caboId: initialData.caboId || '',
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'checkbox' ? (e.target as HTMLInputElement).checked : value;
    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const toggleFamily = () => {
    setFormData(prev => ({ ...prev, isFamilyMember: !prev.isFamilyMember }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.birthDate || !formData.phone) {
      alert("Por favor, preencha os campos obrigatórios (Nome, Nascimento e Telefone)");
      return;
    }
    onSubmit(formData);
  };

  const isEditing = !!initialData;

  return (
    <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden mb-10">
      <div className={`p-8 text-white flex justify-between items-center ${isEditing ? (formData.isFamilyMember ? 'bg-pink-600' : 'bg-amber-600') : 'bg-indigo-600'}`}>
        <div>
          <h2 className="text-2xl font-black flex items-center gap-3">
            {isEditing ? <Edit3 size={28} /> : <User size={28} />} 
            {isEditing ? `Editando: ${initialData.name}` : 'Novo Cadastro de Eleitor'}
          </h2>
          <p className="text-white/60 text-sm font-medium mt-1">Preencha as informações detalhadas do eleitor.</p>
        </div>
        <button onClick={onCancel} className="bg-white/10 hover:bg-white/20 p-2 rounded-xl transition-colors">
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-10 space-y-10">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div 
            onClick={toggleFamily}
            className={`p-5 rounded-2xl border-2 cursor-pointer transition-all flex items-center justify-between ${formData.isFamilyMember ? 'border-pink-500 bg-pink-50' : 'border-slate-100 bg-slate-50'}`}
          >
            <div className="flex items-center gap-4">
              <div className={`p-3 rounded-2xl ${formData.isFamilyMember ? 'bg-pink-100 text-pink-600' : 'bg-white text-slate-400 shadow-sm'}`}>
                <Heart size={24} fill={formData.isFamilyMember ? "currentColor" : "none"} />
              </div>
              <div>
                <p className={`font-black text-sm ${formData.isFamilyMember ? 'text-pink-700' : 'text-slate-700'}`}>Membro da Família</p>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Acesso direto ao candidato</p>
              </div>
            </div>
            <div className={`w-12 h-6 rounded-full relative transition-colors ${formData.isFamilyMember ? 'bg-pink-500' : 'bg-slate-300'}`}>
               <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${formData.isFamilyMember ? 'right-1' : 'left-1'}`} />
            </div>
          </div>

          <div className="p-5 rounded-2xl border-2 border-slate-100 bg-slate-50 flex flex-col gap-2 relative">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Liderança Responsável</label>
            <div className="flex items-center gap-3">
              <UserCheck size={20} className="text-orange-500" />
              <select 
                name="caboId" 
                value={formData.caboId} 
                onChange={handleChange}
                className="flex-1 bg-transparent font-bold text-slate-700 outline-none"
              >
                <option value="">Nenhuma liderança atribuída</option>
                {cabos.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        <section>
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-indigo-50 text-indigo-600 flex items-center justify-center"><Archive size={16} /></div>
            Dados Pessoais
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="md:col-span-2">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Completo *</label>
              <input name="name" value={formData.name} onChange={handleChange} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: João da Silva" />
            </div>
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Data de Nascimento *</label>
              <input type="date" name="birthDate" value={formData.birthDate} onChange={handleChange} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
            </div>
            <div>
