import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Search,
  Bell,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Flag,
  X,
  ShieldCheck,
  Briefcase,
  UserCheck,
  ChevronLeft,
  Sparkles
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Carregar dados iniciais e verificar autenticação
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  // Persistência automática
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
      setPasswordInput('');
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  /**
   * PROGRAMAÇÃO DO BOTÃO ENCERRAR SESSÃO
   * Realiza a limpeza completa e redireciona para a tela inicial.
   */
  const handleLogout = () => {
    if (window.confirm('Deseja realmente ENCERRAR A SESSÃO e voltar ao início?')) {
      // 1. Limpa o armazenamento de sessão (Logout persistente)
      sessionStorage.clear();

      // 2. Reseta o estado de autenticação
      setIsAuthenticated(false);

      // 3. Força o recarregamento total da URL base para garantir o reset do React
      window.location.href = window.location.origin + window.location.pathname;
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir este eleitor permanentemente?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Remover esta liderança da equipe?')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVotersList = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [voters]);

  // TELA DE LOGIN (O COMEÇO DO SISTEMA)
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-800 via-slate-900 to-black">
        <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden p-12 animate-in fade-in zoom-in-95 duration-500">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mx-auto mb-6">
              <ShieldCheck size={40} />
            </div>
            <h2 className="text-3xl font-black text-slate-800">Acesso Restrito</h2>
            <p className="text-slate-500 font-medium mt-2">Gestão Unificada de Campanha</p>
          </div>

          <form onSubmit={handlePasswordSubmit} className="space-y-6">
            <div className="relative group">
              <input 
                type={showPassword ? "text" : "password"} 
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                placeholder="•••"
                autoFocus
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
            {loginError && <p className="text-red-500 text-xs text-center font-bold">Código de segurança incorreto!</p>}

            <button type="submit" className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-indigo-100 active:scale-95">
              Entrar no Painel
            </button>
          </form>
        </div>
      </div>
    );
  }

  // CONFIGURAÇÃO INICIAL (SE NÃO HOUVER PERFIL)
  if (!politicalProfile) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Painel de Controle</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Primeiro, defina os dados principais do seu perfil político.</p>
            </div>
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Nome Completo do Candidato</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Cargo</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Vereador, Prefeito..." />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Âmbito de Atuação</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal</option>
                  <option value="estadual">Estadual</option>
                </select>
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Meta de Votos (Opcional)</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="0" />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all active:scale-95">
              Confirmar Dados <ArrowRight />
            </button>

            <button type="button" onClick={handleLogout} className="w-full text-xs font-bold text-slate-400 uppercase tracking-widest hover:text-red-500 transition-colors">
              Cancelar e Sair
            </button>
          </form>
        </div>
      </div>
    );
  }

  // INTERFACE PRINCIPAL DO SISTEMA
  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      <nav className="w-full md:w-72 bg-slate-900 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile.name}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                <ShieldCheck size={12} /> Acesso Único
              </p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Lista de Eleitores" />
          <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Equipe/Lideranças" color="orange" />
          <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Família" color="pink" />
          <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Atendimentos" color="emerald" />
          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Cadastro" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Configurações" color="slate" />
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <p className="text-indigo-400 text-[9px] font-black uppercase mb-1">Potencial de Votos</p>
            <p className="text-3xl font-black">{voters.length}</p>
          </div>

          {/* BOTÃO ENCERRAR SESSÃO - VOLTA AO INÍCIO */}
          <button 
            onClick={handleLogout} 
            className="w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-red-500/20 active:scale-95"
          >
            <LogOut size={16} /> Encerrar Sessão
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-4">
             <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Gestor de Campanha</h2>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Pesquisar..."
                className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="relative group p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors cursor-pointer">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{birthdayVoters.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <Dashboard 
                voters={voters} 
                cabos={cabos} 
                voteGoal={politicalProfile.voteGoal || 0} 
                scope={politicalProfile.scope} 
                onEditGoal={() => setActiveTab('profile')} 
              />
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={voters} /></div>
                <div className="lg:col-span-5"><BirthdayWidget voters={voters} /></div>
              </div>
            </div>
          )}

          {activeTab === 'cabos' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">Equipe de Lideranças</h2>
                <button onClick={() => { setEditingCabo(null); setIsCaboModalOpen(true); }} className="px-8 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg hover:bg-orange-600 transition-all flex items-center gap-2">
                  <UserPlus size={20} /> Nova Liderança
                </button>
              </div>
              <CaboList cabos={cabos} voters={voters} onDelete={deleteCabo} onEdit={(c) => { setEditingCabo(c); setIsCaboModalOpen(true); }} scope={politicalProfile.scope} />

              {isCaboModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-6 animate-in fade-in duration-200">
                  <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl relative">
                    <button onClick={() => setIsCaboModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600">
                      <X size={24} />
                    </button>
                    <CaboForm 
                      scope={politicalProfile.scope} 
                      onSubmit={editingCabo ? updateCabo : addCabo} 
                      onCancel={() => setIsCaboModalOpen(false)} 
                      initialData={editingCabo || undefined} 
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <h2 className="text-4xl font-black text-slate-800">Base de Eleitores</h2>
              <VoterList voters={filteredVotersList} onDelete={deleteVoter} onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <VoterForm 
                cabos={cabos} 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => setActiveTab('list')} 
                initialData={editingVoter || undefined}
              />
            </div>
          )}

          {activeTab === 'help' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {activeTab === 'profile' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Perfil da Campanha</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Político</label>
                      <input name="name" defaultValue={politicalProfile.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta de Votos</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all active:scale-95">Salvar Perfil</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 scale-[1.02]';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20 scale-[1.02]';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20 scale-[1.02]';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-slate-400 hover:bg-white/5 hover:text-white active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Voter, VoterFormData, HelpRecord, PoliticalProfile, CaboEleitoral } from './types';
import VoterList from './components/VoterList';
import VoterForm from './components/VoterForm';
import CaboForm from './components/CaboForm';
import CaboList from './components/CaboList';
import BirthdayWidget from './components/BirthdayWidget';
import Dashboard from './components/Dashboard';
import NeighborhoodChart from './components/NeighborhoodChart';
import HelpManager from './components/HelpManager';
import { exportVotersToPDF, exportVoterHistoryPDF } from './services/pdf';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Search,
  Bell,
  Heart,
  HandHelping,
  Lock,
  LogIn,
  Eye,
  EyeOff,
  Trophy,
  ArrowRight,
  LogOut,
  Settings,
  Flag,
  X,
  ShieldCheck,
  Briefcase,
  UserCheck,
  ChevronLeft,
  Sparkles
} from 'lucide-react';

const ACCESS_PASSWORD = '123';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile | null>(null);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);
  const [editingCabo, setEditingCabo] = useState<CaboEleitoral | null>(null);
  const [isCaboModalOpen, setIsCaboModalOpen] = useState(false);

  // Carregar dados iniciais e verificar autenticação persistente na sessão
  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) setPoliticalProfile(JSON.parse(savedProfile));

    const auth = sessionStorage.getItem('is_authenticated');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  // Persistência automática no localStorage
  useEffect(() => {
    localStorage.setItem('voters_data', JSON.stringify(voters));
  }, [voters]);

  useEffect(() => {
    localStorage.setItem('cabos_data', JSON.stringify(cabos));
  }, [cabos]);

  useEffect(() => {
    if (politicalProfile) {
      localStorage.setItem('political_profile', JSON.stringify(politicalProfile));
    }
  }, [politicalProfile]);

  // Função de Login
  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ACCESS_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('is_authenticated', 'true');
      setLoginError(false);
      setPasswordInput('');
    } else {
      setLoginError(true);
      setPasswordInput('');
    }
  };

  /**
   * ATIVAÇÃO DO BOTÃO ENCERRAR SESSÃO
   * Limpa todos os dados de sessão e força o sistema ao ponto inicial de login.
   */
  const handleLogout = () => {
    if (window.confirm('Tem certeza que deseja ENCERRAR A SESSÃO e sair do sistema?')) {
      // 1. Limpa a marcação de autenticação da sessão atual
      sessionStorage.removeItem('is_authenticated');
      sessionStorage.clear();

      // 2. Reseta o estado do React
      setIsAuthenticated(false);

      // 3. Força o navegador a recarregar a página do zero, voltando ao login
      window.location.reload();
    }
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0
    };
    setPoliticalProfile(profile);
    setActiveTab('dashboard');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = {
      ...data,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      helpRecords: []
    };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  const deleteVoter = (id: string) => {
    if (window.confirm('Excluir este eleitor permanentemente?')) {
      setVoters(prev => prev.filter(v => v.id !== id));
    }
  };

  const addCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    const newCabo: CaboEleitoral = {
      ...data,
      id: crypto.randomUUID(),
      hiredAt: new Date().toISOString()
    };
    setCabos(prev => [newCabo, ...prev]);
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const updateCabo = (data: Omit<CaboEleitoral, 'id' | 'hiredAt'>) => {
    if (!editingCabo) return;
    setCabos(prev => prev.map(c => c.id === editingCabo.id ? { ...c, ...data } : c));
    setEditingCabo(null);
    setIsCaboModalOpen(false);
  };

  const deleteCabo = (id: string) => {
    if (window.confirm('Remover esta liderança da equipe?')) {
      setCabos(prev => prev.filter(c => c.id !== id));
    }
  };

  const addHelpRecord = (voterId: string, record: Omit<HelpRecord, 'id'>) => {
    const newRecord = { ...record, id: crypto.randomUUID() };
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: [...(v.helpRecords || []), newRecord] } : v));
  };

  const deleteHelpRecord = (voterId: string, recordId: string) => {
    setVoters(prev => prev.map(v => v.id === voterId ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== recordId) } : v));
  };

  const filteredVotersList = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [voters, searchTerm, activeTab]);

  const birthdayVoters = useMemo(() => {
    const today = new Date();
    return voters.filter(v => {
      const parts = v.birthDate.split('-').map(Number);
      return parts[1] === (today.getMonth() + 1) && parts[2] === today.getDate();
    });
  }, [voters]);

  // TELA DE LOGIN - O PONTO DE PARTIDA UNICO
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-800 via-slate-900 to-black">
        <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden p-12 animate-in fade-in zoom-in-95 duration-500">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mx-auto mb-6">
              <ShieldCheck size={40} />
            </div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">Painel de Acesso</h2>
            <p className="text-slate-500 font-medium mt-2">Sistema Exclusivo de Gestão</p>
          </div>

          <form onSubmit={handlePasswordSubmit} className="space-y-6">
            <div className="relative group">
              <input 
                type={showPassword ? "text" : "password"} 
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                className={`w-full px-6 py-5 bg-slate-50 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-slate-100 focus:border-indigo-500'} rounded-2xl outline-none text-center text-2xl font-black tracking-[0.3em] transition-all`}
                placeholder="•••"
                autoFocus
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 p-2">
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
            {loginError && <p className="text-red-500 text-xs text-center font-bold">Chave de acesso inválida!</p>}

            <button type="submit" className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-indigo-100 active:scale-95">
              Entrar no Sistema
            </button>
          </form>

          <p className="mt-8 text-center text-[10px] text-slate-300 font-bold uppercase tracking-widest">Acesso Protegido 256-bit</p>
        </div>
      </div>
    );
  }

  // CONFIGURAÇÃO INICIAL (SOMENTE APÓS O LOGIN)
  if (!politicalProfile) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-700">
        <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="bg-indigo-600 p-12 text-white relative overflow-hidden">
            <div className="relative z-10">
              <h2 className="text-4xl font-black leading-tight">Configuração Mestra</h2>
              <p className="mt-4 text-indigo-100 text-lg opacity-80">Olá! Vamos configurar os dados base da sua candidatura.</p>
            </div>
            <Sparkles className="absolute -bottom-10 -right-10 text-white/10" size={200} />
          </div>
          <form onSubmit={handleProfileSubmit} className="p-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Completo do Candidato</label>
                <input required name="name" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Cargo Desejado</label>
                <input required name="office" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="Ex: Vereador" />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Âmbito</label>
                <select name="scope" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all">
                  <option value="municipal">Municipal (Cidade)</option>
                  <option value="estadual">Estadual (Estado)</option>
                </select>
              </div>
              <div className="md:col-span-2">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral de Votos (Planejado)</label>
                <input type="number" name="voteGoal" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold transition-all" placeholder="5000" />
              </div>
            </div>

            <div className="pt-4 space-y-4">
              <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-2xl shadow-indigo-100 transition-all active:scale-95">
                Iniciar Gestão <ArrowRight />
              </button>

              <button type="button" onClick={handleLogout} className="w-full py-3 text-xs font-black text-slate-400 uppercase tracking-widest hover:text-red-500 transition-colors">
                Sair e Cancelar
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // INTERFACE PRINCIPAL LOGADA
  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* SIDEBAR NAVIGATION */}
      <nav className="w-full md:w-72 bg-slate-900 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Trophy className="text-white" size={32} />
            </div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile.name}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                <ShieldCheck size={12} /> Acesso Administrativo
              </p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>

        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Lista de Eleitores" />
          <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Minha Equipe" color="orange" />
          <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Família" color="pink" />
          <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Assistência Social" color="emerald" />
          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Registro" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Ajustes Perfil" color="slate" />
        </div>

        <div className="p-6 mt-auto">
          <div className="bg-white/5 rounded-3xl p-5 border border-white/10 mb-4 backdrop-blur-sm">
            <p className="text-indigo-400 text-[9px] font-black uppercase mb-1">Base Consolidada</p>
            <p className="text-3xl font-black">{voters.length + cabos.length}</p>
          </div>

          {/* BOTÃO ENCERRAR SESSÃO TOTALMENTE ATIVADO */}
          <button 
            onClick={handleLogout} 
            className="w-full py-4 bg-red-600/10 hover:bg-red-600 text-red-500 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-red-500/20 active:scale-95 shadow-lg shadow-red-900/10"
          >
            <LogOut size={16} /> Encerrar Sessão
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-4">
             <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Gestor de Eleitores</h2>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Pesquisar registro..."
                className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="relative group p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors cursor-pointer">
              <Bell className="text-slate-600" size={22} />
              {birthdayVoters.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{birthdayVoters.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <Dashboard 
                voters={voters} 
                cabos={cabos} 
                voteGoal={politicalProfile.voteGoal || 0} 
                scope={politicalProfile.scope} 
                onEditGoal={() => setActiveTab('profile')} 
              />
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={voters} /></div>
                <div className="lg:col-span-5"><BirthdayWidget voters={voters} /></div>
              </div>
            </div>
          )}

          {activeTab === 'cabos' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-slate-800 tracking-tight">Lideranças Ativas</h2>
                <button onClick={() => { setEditingCabo(null); setIsCaboModalOpen(true); }} className="px-8 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg hover:bg-orange-600 transition-all flex items-center gap-2">
                  <UserPlus size={20} /> Adicionar Cabo
                </button>
              </div>
              <CaboList cabos={cabos} voters={voters} onDelete={deleteCabo} onEdit={(c) => { setEditingCabo(c); setIsCaboModalOpen(true); }} scope={politicalProfile.scope} />

              {isCaboModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-6 animate-in fade-in duration-200">
                  <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl relative">
                    <button onClick={() => setIsCaboModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600">
                      <X size={24} />
                    </button>
                    <CaboForm 
                      scope={politicalProfile.scope} 
                      onSubmit={editingCabo ? updateCabo : addCabo} 
                      onCancel={() => setIsCaboModalOpen(false)} 
                      initialData={editingCabo || undefined} 
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <h2 className="text-4xl font-black text-slate-800">Base de Eleitores</h2>
              <VoterList voters={filteredVotersList} onDelete={deleteVoter} onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} />
            </div>
          )}

          {(activeTab === 'add' || activeTab === 'edit') && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <VoterForm 
                cabos={cabos} 
                onSubmit={activeTab === 'edit' ? updateVoter : addVoter} 
                onCancel={() => setActiveTab('list')} 
                initialData={editingVoter || undefined}
              />
            </div>
          )}

          {activeTab === 'help' && (
            <div className="animate-in slide-in-from-right-4 duration-500">
              <HelpManager voters={voters} onAddHelp={addHelpRecord} onDeleteHelp={deleteHelpRecord} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />
            </div>
          )}

          {activeTab === 'profile' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Perfil de Campanha</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Político</label>
                      <input name="name" defaultValue={politicalProfile.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral (Votos)</label>
                      <input type="number" name="voteGoal" defaultValue={politicalProfile.voteGoal} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all active:scale-95">Salvar Alterações</button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 scale-[1.02]';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20 scale-[1.02]';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20 scale-[1.02]';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-slate-400 hover:bg-white/5 hover:text-white active:scale-95'}`}>
      <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span> 
      <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { PoliticalProfile } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function generateBirthdayMessage(voterName: string, politician?: PoliticalProfile): Promise<string> {
  const senderInfo = politician 
    ? `A mensagem é enviada por ${politician.name} (${politician.office} do partido ${politician.party}).` 
    : "A mensagem é enviada por um representante da comunidade.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Escreva uma mensagem curta, carinhosa e profissional de aniversário para um eleitor chamado ${voterName}. 
      ${senderInfo}
      A mensagem deve ser amigável, desejar saúde e felicidade, e reforçar o compromisso com a comunidade. 
      Não use placeholders, escreva o texto final pronto para enviar.`,
      config: {
        temperature: 0.8,
        topP: 0.95,
      }
    });

    return response.text || `Parabéns ${voterName}! Desejo muita saúde e realizações neste dia especial.`;
  } catch (error) {
    return `Olá ${voterName}, parabéns pelo seu aniversário! Felicidades e um forte abraço!`;
  }
}

export async function generateBulkCampaignMessage(location: string, politician: PoliticalProfile, topic?: string): Promise<string> {
  try {
    const topicInfo = topic ? `O tema central é: ${topic}.` : "O tema é um informativo geral sobre as ações na região.";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Escreva uma mensagem de WhatsApp para ser enviada em massa para eleitores da região: ${location}.
      O remetente é ${politician.name}, candidato ao cargo de ${politician.office}.
      ${topicInfo}
      A mensagem deve ser curta (máximo 400 caracteres), direta, amigável e focar no desenvolvimento local da região citada.
      Não use [Nome do Eleitor] ou placeholders, pois será uma mensagem padrão para todos daquela cidade/bairro.
      Inclua um convite para diálogo.`,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || `Olá, aqui é ${politician.name}. Gostaria de reafirmar meu compromisso com ${location}. Estamos juntos!`;
  } catch (error) {
    return `Olá, morador de ${location}! Aqui é ${politician.name}. Seguimos trabalhando por melhorias em nossa região. Um abraço!`;
  }
}

import React, { useState, useMemo } from 'react';
import { Voter, PoliticalProfile } from '../types';
import { generateBulkCampaignMessage } from '../services/gemini';
import { Send, MapPin, Sparkles, Loader2, MessageSquare, Copy, Check, ExternalLink } from 'lucide-react';

interface Props {
  voters: Voter[];
  profile: PoliticalProfile;
}

const BulkMessenger: React.FC<Props> = ({ voters, profile }) => {
  const [selectedLocation, setSelectedLocation] = useState<string>('');
  const [message, setMessage] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [topic, setTopic] = useState('');
  const [sentVoters, setSentVoters] = useState<Set<string>>(new Set());

  // Agrupa localizações únicas (Bairros ou Cidades conforme o scope)
  const locations = useMemo(() => {
    const locs = new Set<string>();
    voters.forEach(v => {
      if (v.neighborhood) locs.add(v.neighborhood);
    });
    return Array.from(locs).sort();
  }, [voters]);

  const filteredVoters = useMemo(() => {
    if (!selectedLocation) return [];
    return voters.filter(v => v.neighborhood === selectedLocation);
  }, [voters, selectedLocation]);

  const handleGenerateIA = async () => {
    if (!selectedLocation) {
      alert("Selecione uma localização primeiro.");
      return;
    }
    setIsGenerating(true);
    const text = await generateBulkCampaignMessage(selectedLocation, profile, topic);
    setMessage(text);
    setIsGenerating(false);
  };

  const markAsSent = (id: string) => {
    const newSet = new Set(sentVoters);
    newSet.add(id);
    setSentVoters(newSet);
  };

  const locationLabel = profile.scope === 'municipal' ? 'Bairro' : 'Cidade';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in duration-500">
      {/* Coluna de Configuração */}
      <div className="lg:col-span-5 space-y-6">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <h3 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-3">
            <MessageSquare className="text-emerald-500" /> Disparo Regional
          </h3>

          <div className="space-y-4">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">
                Filtrar por {locationLabel}
              </label>
              <div className="relative">
                <MapPin size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" />
                <select 
                  value={selectedLocation}
                  onChange={(e) => { setSelectedLocation(e.target.value); setSentVoters(new Set()); }}
                  className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none font-bold text-slate-700 appearance-none"
                >
                  <option value="">Selecione a localidade...</option>
                  {locations.map(loc => (
                    <option key={loc} value={loc}>{loc}</option>
                  ))}
                </select>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Tema da Mensagem (Opcional)</label>
              <input 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                placeholder="Ex: Reforma da praça, saúde, convite para reunião..."
                className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none font-bold"
              />
            </div>

            <button 
              onClick={handleGenerateIA}
              disabled={isGenerating || !selectedLocation}
              className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-700 disabled:bg-slate-200 transition-all flex items-center justify-center gap-3 shadow-xl shadow-indigo-100"
            >
              {isGenerating ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
              Gerar Texto com IA
            </button>
          </div>
        </div>

        {message && (
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 animate-in zoom-in-95">
             <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 px-1">Mensagem Preparada</label>
             <textarea 
               value={message}
               onChange={(e) => setMessage(e.target.value)}
               className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-2xl font-medium text-slate-700 text-sm resize-none h-48 focus:border-emerald-500 transition-all outline-none"
             />
             <div className="mt-4 text-[10px] text-slate-400 font-bold flex justify-between">
                <span>Caracteres: {message.length}</span>
                <button onClick={() => { navigator.clipboard.writeText(message); alert("Copiado!"); }} className="text-indigo-600 flex items-center gap-1">
                  <Copy size={12} /> Copiar Texto
                </button>
             </div>
          </div>
        )}
      </div>

      {/* Coluna de Destinatários */}
      <div className="lg:col-span-7">
        {!selectedLocation ? (
          <div className="bg-white p-20 rounded-[2.5rem] border-2 border-dashed border-slate-200 text-center flex flex-col items-center justify-center text-slate-400">
            <Send size={64} className="mb-4 opacity-20" />
            <p className="font-bold">Selecione uma localidade para ver os eleitores.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-slate-800">
                Eleitores em <span className="text-indigo-600">{selectedLocation}</span>
                <span className="ml-3 text-xs bg-slate-100 px-3 py-1 rounded-full text-slate-500">{filteredVoters.length} registros</span>
              </h3>
              <div className="flex items-center gap-2">
                 <div className="h-2 w-24 bg-slate-100 rounded-full overflow-hidden">
                    <div className="h-full bg-emerald-500 transition-all" style={{ width: `${(sentVoters.size / filteredVoters.length) * 100}%` }} />
                 </div>
                 <span className="text-[10px] font-black text-slate-400">{sentVoters.size}/{filteredVoters.length}</span>
              </div>
            </div>

            <div className="max-h-[700px] overflow-y-auto pr-2 space-y-3 custom-scrollbar">
               {filteredVoters.map(v => (
                 <div key={v.id} className={`bg-white p-5 rounded-3xl border-2 transition-all flex items-center justify-between group ${sentVoters.has(v.id) ? 'border-emerald-100 bg-emerald-50 opacity-60' : 'border-slate-100 shadow-sm hover:border-indigo-200'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black ${sentVoters.has(v.id) ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600'}`}>
                        {sentVoters.has(v.id) ? <Check size={20} /> : v.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-black text-slate-800 leading-none">{v.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 mt-1">{v.phone}</p>
                      </div>
                    </div>

                    <a 
                      href={`https://wa.me/${v.phone.replace(/\D/g, '')}?text=${encodeURIComponent(message)}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      onClick={() => markAsSent(v.id)}
                      className={`px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all ${!message ? 'bg-slate-100 text-slate-300 pointer-events-none' : 'bg-emerald-500 text-white hover:bg-emerald-600 shadow-lg shadow-emerald-100 active:scale-95'}`}
                    >
                      <Send size={14} /> Enviar
                    </a>
                 </div>
               ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

