    const tableColumn = ["Data", "Categoria", "Valor", "Descrição"];
    const tableRows = voter.helpRecords.map((record) => [
      new Date(record.date).toLocaleDateString('pt-BR'),
      record.category,
      formatCurrency(record.value || 0),
      record.description
    ]);

    (doc as any).autoTable({
