import React, { useMemo } from 'react';
import { Voter, CaboEleitoral, PoliticalProfile } from '../types';
import { exportFullCampaignOverviewPDF, exportDetailedFinancialReportPDF } from '../services/pdf';
import { Users, UserCheck, MapPin, Target, Venus, Mars, Percent, Flag, Trophy, Download, FileText, DollarSign } from 'lucide-react';

interface Props {
  voters: Voter[];
  cabos: CaboEleitoral[];
  voteGoal: number;
  scope: 'municipal' | 'estadual';
  onEditGoal: () => void;
}

const Dashboard: React.FC<Props> = ({ voters, cabos, voteGoal, scope, onEditGoal }) => {
  const politicalProfile = useMemo(() => {
    const saved = localStorage.getItem('political_profile');
    return saved ? JSON.parse(saved) as PoliticalProfile : null;
  }, []);

  const stats = useMemo(() => {
    const totalPotentialVotes = voters.length + cabos.length;
    const maleCount = voters.filter(v => v.gender === 'Masculino').length;
    const femaleCount = voters.filter(v => v.gender === 'Feminino').length;

    const localDistribution: Record<string, { voters: number; cabos: number }> = {};

    voters.forEach(v => {
      const loc = v.neighborhood || 'Não Informado';
      if (!localDistribution[loc]) localDistribution[loc] = { voters: 0, cabos: 0 };
      localDistribution[loc].voters++;
    });

    cabos.forEach(c => {
      const loc = c.location || 'Não Informado';
      if (!localDistribution[loc]) localDistribution[loc] = { voters: 0, cabos: 0 };
      localDistribution[loc].cabos++;
    });

    const progress = voteGoal > 0 ? (totalPotentialVotes / voteGoal) * 100 : 0;
    const remaining = Math.max(0, voteGoal - totalPotentialVotes);

    return {
      total: totalPotentialVotes,
      votersOnly: voters.length,
      cabosTotal: cabos.length,
      gender: {
        male: { count: maleCount, pct: voters.length > 0 ? (maleCount / voters.length) * 100 : 0 },
        female: { count: femaleCount, pct: voters.length > 0 ? (femaleCount / voters.length) * 100 : 0 },
      },
      goal: { progress, remaining, goal: voteGoal },
      localDistribution: Object.entries(localDistribution)
        .map(([name, data]) => ({ name, ...data }))
        .sort((a, b) => (b.voters + b.cabos) - (a.voters + a.cabos))
        .slice(0, 5)
    };
  }, [voters, cabos, voteGoal]);

  const handleDownloadReport = () => {
    if (!politicalProfile) return;
    exportFullCampaignOverviewPDF(voters, cabos, politicalProfile);
  };

  const handleDownloadFinancialDetail = () => {
    if (!politicalProfile) return;
    exportDetailedFinancialReportPDF(voters, politicalProfile);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-2">
         <div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">Visão Geral</h2>
            <p className="text-slate-400 text-sm font-medium">Acompanhamento em tempo real da sua base.</p>
         </div>
         <div className="flex flex-wrap gap-3">
            <button 
              onClick={handleDownloadFinancialDetail}
              className="px-6 py-3 bg-white border border-emerald-200 text-emerald-600 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-emerald-50 transition-all shadow-sm active:scale-95"
            >
              <DollarSign size={16} />
              Gasto Detalhado (PDF)
            </button>
            <button 
              onClick={handleDownloadReport}
              className="px-6 py-3 bg-white border border-slate-200 text-slate-600 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-slate-50 transition-all shadow-sm active:scale-95"
            >
              <FileText size={16} className="text-indigo-600" />
              Relatório Consolidado (PDF)
            </button>
         </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Apoios Totais" 
          value={stats.total.toString()} 
          icon={<Users className="text-blue-600" />} 
          bgColor="bg-blue-50" 
          tooltipText="Eleitores cadastrados + Cabos eleitorais"
        />
        <StatCard 
          label="Lideranças" 
          value={stats.cabosTotal.toString()} 
          icon={<Flag className="text-orange-600" />} 
          bgColor="bg-orange-50" 
        />
        <StatCard 
          label="Meta Atingida" 
          value={`${stats.goal.progress.toFixed(1)}%`} 
          icon={<Trophy className="text-amber-600" />} 
          bgColor="bg-amber-50" 
        />
        <StatCard 
          label="Faltam para Meta" 
          value={stats.goal.remaining.toString()} 
          icon={<Target className="text-red-600" />} 
          bgColor="bg-red-50" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <div className="flex justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl">
              <Target size={24} className="text-indigo-600" /> 
              Progresso Consolidado
            </h3>
            <button onClick={onEditGoal} className="text-xs font-black text-indigo-600 uppercase">Ajustar Meta</button>
          </div>

          <div className="space-y-6">
            <div>
              <div className="flex justify-between text-sm font-bold mb-2">
                <span className="text-slate-500">Base Ativa (Votos Reais)</span>
                <span className="text-indigo-600">{stats.total} / {voteGoal}</span>
              </div>
              <div className="h-4 w-full bg-slate-100 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-600 transition-all duration-1000" 
                  style={{ width: `${Math.min(100, stats.goal.progress)}%` }} 
                />
              </div>
              <p className="mt-2 text-[10px] text-slate-400 font-medium">* Inclui eleitores e equipe direta de liderança.</p>
            </div>

            <div className="pt-6 border-t border-slate-100">
              <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">
                Concentração em {scope === 'municipal' ? 'Bairros' : 'Cidades'}
              </h4>
              <div className="space-y-3">
                {stats.localDistribution.length === 0 ? (
                  <p className="text-xs text-slate-400 italic">Sem registros geográficos.</p>
                ) : (
                  stats.localDistribution.map(loc => {
                    const totalInLoc = loc.voters + loc.cabos;
                    return (
                      <div key={loc.name} className="flex items-center gap-4">
                        <div className="w-24 text-[10px] font-black text-slate-400 uppercase truncate">{loc.name}</div>
                        <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-indigo-400" style={{ width: `${(totalInLoc / (stats.total || 1)) * 100}%` }} />
                        </div>
                        <div className="w-12 text-right text-xs font-black text-slate-700">{totalInLoc}</div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl mb-6"><Users size={24} className="text-indigo-600" /> Perfil Demográfico</h3>
          <div className="space-y-10 py-4">
             <div className="flex items-center justify-around text-center">
                <div>
                  <div className="w-20 h-20 bg-pink-50 rounded-full flex items-center justify-center mx-auto mb-3 border-4 border-pink-100">
                    <Venus size={32} className="text-pink-600" />
                  </div>
                  <p className="text-2xl font-black text-slate-800">{stats.gender.female.pct.toFixed(1)}%</p>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Público Feminino</p>
                </div>
                <div className="h-16 w-px bg-slate-100"></div>
                <div>
                  <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-3 border-4 border-blue-100">
                    <Mars size={32} className="text-blue-600" />
                  </div>
                  <p className="text-2xl font-black text-slate-800">{stats.gender.male.pct.toFixed(1)}%</p>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Público Masculino</p>
                </div>
             </div>

             <div className="p-6 rounded-3xl border bg-indigo-50 border-indigo-100">
                <div className="flex items-center gap-3 mb-2">
                  <Percent size={18} className="text-indigo-600" />
                  <span className="text-sm font-black text-indigo-700">Multiplicadores</span>
                </div>
                <p className="text-xs text-indigo-600/70 font-medium">
                  Atualmente, cada liderança (cabo) é responsável por uma base média de {(stats.votersOnly / (cabos.length || 1)).toFixed(1)} eleitores externos.
                </p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: React.ReactNode; bgColor: string; tooltipText?: string }> = ({ label, value, icon, bgColor, tooltipText }) => (
  <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-start justify-between relative group">
    <div>
      <p className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">{label}</p>
      <p className="text-2xl font-black mt-1 text-slate-800">{value}</p>
      {tooltipText && (
        <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 px-3 py-1 bg-slate-800 text-white text-[9px] rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-50">
          {tooltipText}
        </div>
      )}
    </div>
    <div className={`${bgColor} p-3 rounded-2xl`}>{icon}</div>
  </div>
);

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Voter, HelpRecord, PoliticalProfile } from '../types';
import { exportMonthlyFinancialReportPDF, exportDetailedFinancialReportPDF } from '../services/pdf';
import { HandHelping, Search, Plus, Calendar, Trash2, FileText, ChevronRight, DollarSign, PieChart, TrendingUp, Download, ListChecks, Award, BarChart3 } from 'lucide-react';

interface Props {
  voters: Voter[];
  onAddHelp: (voterId: string, record: Omit<HelpRecord, 'id'>) => void;
  onDeleteHelp: (voterId: string, recordId: string) => void;
  onExportHelp: (voter: Voter) => void;
  initialVoter: Voter | null;
}

const HelpManager: React.FC<Props> = ({ voters, onAddHelp, onDeleteHelp, onExportHelp, initialVoter }) => {
  const [selectedVoter, setSelectedVoter] = useState<Voter | null>(initialVoter);
  const [searchTerm, setSearchTerm] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('Social');
  const [value, setValue] = useState<string>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const politicalProfile = useMemo(() => {
    const saved = localStorage.getItem('political_profile');
    return saved ? JSON.parse(saved) as PoliticalProfile : undefined;
  }, []);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const formatMonthShort = (monthKey: string) => {
    const [, month] = monthKey.split('-');
    const date = new Date(2000, parseInt(month) - 1);
    return date.toLocaleDateString('pt-BR', { month: 'short' }).replace('.', '');
  };

  // Lógica para encontrar o eleitor mais ajudado e sua evolução
  const topAssistedData = useMemo(() => {
    let topVoter: Voter | null = null;
    let maxTotal = 0;

    voters.forEach(v => {
      const total = (v.helpRecords || []).reduce((acc, curr) => acc + (curr.value || 0), 0);
      if (total > maxTotal && total > 0) {
        maxTotal = total;
        topVoter = v;
      }
    });

    if (!topVoter) return null;

    const evolution: Record<string, number> = {};
    (topVoter as Voter).helpRecords?.forEach(record => {
      const d = new Date(record.date);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      evolution[key] = (evolution[key] || 0) + (record.value || 0);
    });

    const evolutionArray = Object.entries(evolution)
      .map(([month, total]) => ({ month, total }))
      .sort((a, b) => a.month.localeCompare(b.month))
      .slice(-5); // Últimos 5 meses de atividade

    return {
      voter: topVoter as Voter,
      total: maxTotal,
      evolution: evolutionArray
    };
  }, [voters]);

  const filteredVoters = useMemo(() => {
    if (!searchTerm) return [];
    return voters.filter(v => v.name.toLowerCase().includes(searchTerm.toLowerCase())).slice(0, 5);
  }, [voters, searchTerm]);

  const monthlyStats = useMemo(() => {
    const stats: Record<string, number> = {};
    voters.forEach(v => {
      v.helpRecords?.forEach(record => {
        const d = new Date(record.date);
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        stats[key] = (stats[key] || 0) + (record.value || 0);
      });
    });

    return Object.entries(stats)
      .map(([month, total]) => ({ month, total }))
      .sort((a, b) => b.month.localeCompare(a.month));
  }, [voters]);

  const currentMonthKey = useMemo(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  }, []);

  const totalSpentThisMonth = useMemo(() => {
    return monthlyStats.find(s => s.month === currentMonthKey)?.total || 0;
  }, [monthlyStats, currentMonthKey]);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedVoter || !description) return;

    onAddHelp(selectedVoter.id, {
      description,
      category,
      date,
      value: parseFloat(value) || 0
    });

    setDescription('');
    setValue('');
    alert("Atendimento financeiro registrado!");
  };

  const currentVoter = useMemo(() => {
    if (!selectedVoter) return null;
    return voters.find(v => v.id === selectedVoter.id) || null;
  }, [voters, selectedVoter]);

  const handleExportMonthlyBalance = () => {
    if (voters.length === 0) {
      alert("Não há dados para exportar.");
      return;
    }
    exportMonthlyFinancialReportPDF(voters, politicalProfile);
  };

  const handleExportFullDetailed = () => {
    if (voters.length === 0 || !politicalProfile) {
      alert("Dados insuficientes para gerar o relatório.");
      return;
    }
    exportDetailedFinancialReportPDF(voters, politicalProfile);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Coluna Lateral de Resumo */}
      <div className="lg:col-span-4 space-y-6">
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden relative group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <TrendingUp size={80} />
          </div>
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <PieChart size={18} className="text-indigo-600" />
            Gastos do Mês Atual
          </h3>
          <p className="text-3xl font-black text-indigo-600">{formatCurrency(totalSpentThisMonth)}</p>
          <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-wider">Investimento Total Mensal</p>
        </div>

        {/* GRÁFICO DE EVOLUÇÃO DO ELEITOR MAIS AJUDADO */}
        {topAssistedData && (
          <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200 animate-in fade-in slide-in-from-left-4 duration-700">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <Award size={18} className="text-amber-500" />
                Destaque de Atendimento
              </h3>
              <span className="px-2 py-0.5 bg-amber-50 text-amber-600 text-[9px] font-black rounded-lg uppercase">Recordista</span>
            </div>

            <div className="mb-6">
              <p className="text-sm font-black text-slate-800 truncate">{topAssistedData.voter.name}</p>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Total Acumulado: {formatCurrency(topAssistedData.total)}</p>
            </div>

            <div className="flex items-end justify-between h-24 gap-2 mb-2 px-1">
              {topAssistedData.evolution.map((point, i) => {
                const maxVal = Math.max(...topAssistedData.evolution.map(p => p.total));
                const height = (point.total / maxVal) * 100;
                return (
                  <div key={point.month} className="flex-1 flex flex-col items-center gap-2 group">
                    <div className="w-full relative">
                      <div 
                        className="w-full bg-indigo-500 rounded-t-lg group-hover:bg-indigo-600 transition-all duration-1000"
