import React, { useMemo, useState } from 'react';
import { Voter, CaboEleitoral, PoliticalProfile, Appointment } from '../types';
import { exportFullCampaignOverviewPDF, exportDetailedFinancialReportPDF } from '../services/pdf';
import { performStrategicResearch } from '../services/gemini';
import { 
  Users, 
  MapPin, 
  Target, 
  Flag, 
  Trophy, 
  DollarSign, 
  CalendarClock, 
  Clock, 
  ChevronRight, 
  Sparkles, 
  MessageSquare, 
  Loader2, 
  TrendingUp,
  Map,
  CheckCircle2
} from 'lucide-react';

interface Props {
  voters: Voter[];
  cabos: CaboEleitoral[];
  appointments: Appointment[];
  voteGoal: number;
  scope: 'municipal' | 'estadual';
  onEditGoal: () => void;
  onGoToAgenda: () => void;
}

const Dashboard: React.FC<Props> = ({ voters, cabos, appointments, voteGoal, scope, onEditGoal, onGoToAgenda }) => {
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  const politicalProfile = useMemo(() => {
    const saved = localStorage.getItem('political_profile');
    return saved ? JSON.parse(saved) as PoliticalProfile : null;
  }, []);

  const stats = useMemo(() => {
    const totalPotentialVotes = voters.length + cabos.length;

    // Agrupamento Geográfico Inteligente
    const localDistribution: Record<string, { voters: number; cabos: number }> = {};
    voters.forEach(v => {
      const loc = (scope === 'estadual' ? v.city : v.neighborhood) || 'Não Informado';
      if (!localDistribution[loc]) localDistribution[loc] = { voters: 0, cabos: 0 };
      localDistribution[loc].voters++;
    });

    cabos.forEach(c => {
      const loc = c.location || 'Não Informado';
      if (!localDistribution[loc]) localDistribution[loc] = { voters: 0, cabos: 0 };
      localDistribution[loc].cabos++;
    });

    const upcomingAppointments = appointments
      .filter(a => a.status === 'pending')
      .sort((a, b) => new Date(`${a.date}T${a.time}`).getTime() - new Date(`${b.date}T${b.time}`).getTime())
      .slice(0, 3);

    const progress = voteGoal > 0 ? (totalPotentialVotes / voteGoal) * 100 : 0;
    const remaining = Math.max(0, voteGoal - totalPotentialVotes);

    return {
      total: totalPotentialVotes,
      votersOnly: voters.length,
      cabosTotal: cabos.length,
      goal: { progress, remaining, goal: voteGoal },
      localDistribution: Object.entries(localDistribution)
        .map(([name, data]) => ({ name, ...data }))
        .sort((a, b) => (b.voters + b.cabos) - (a.voters + a.cabos))
        .slice(0, 10),
      upcomingAppointments
    };
  }, [voters, cabos, appointments, voteGoal, scope]);

  const handleGetInsight = async () => {
    if (!politicalProfile) return;
    setAiLoading(true);
    try {
      const prompt = `Analise meu progresso: Tenho ${stats.total} apoios de uma meta de ${voteGoal}. Minha maior base está em ${stats.localDistribution[0]?.name || 'diversas regiões'}. O que devo fazer para atingir minha meta de forma estratégica?`;
      const result = await performStrategicResearch(prompt, politicalProfile);
      setAiInsight(result.text);
    } catch (e) {
      setAiInsight("Não consegui processar a análise agora. Tente novamente em alguns instantes.");
    } finally {
      setAiLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Cabeçalho */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-2">
         <div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">Visão Geral</h2>
            <p className="text-slate-400 text-sm font-medium">Insights e acompanhamento estratégico da sua campanha.</p>
         </div>
         <div className="flex flex-wrap gap-3">
            <button 
              onClick={() => exportDetailedFinancialReportPDF(voters, politicalProfile!)}
              className="px-6 py-3 bg-white border border-emerald-200 text-emerald-600 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-emerald-50 transition-all shadow-sm active:scale-95"
            >
              <DollarSign size={16} /> Gastos
            </button>
            <button 
              onClick={() => exportFullCampaignOverviewPDF(voters, cabos, politicalProfile!)}
              className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg active:scale-95"
            >
              <CalendarClock size={16} /> Relatório Completo
            </button>
         </div>
      </div>

      {/* Cards de Métricas Principais */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Apoios Totais" value={stats.total.toString()} icon={<Users className="text-blue-600" />} bgColor="bg-blue-50" />
        <StatCard label="Lideranças" value={stats.cabosTotal.toString()} icon={<Flag className="text-orange-600" />} bgColor="bg-orange-50" />
        <StatCard label="Meta Atingida" value={`${stats.goal.progress.toFixed(1)}%`} icon={<Trophy className="text-amber-600" />} bgColor="bg-amber-50" />
        <StatCard label="Faltam para Meta" value={stats.goal.remaining.toString()} icon={<Target className="text-red-600" />} bgColor="bg-red-50" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Painel de Progresso Geográfico */}
        <div className="lg:col-span-8 bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2 text-xl">
              <Map size={24} className="text-indigo-600" /> 
              Progresso por {scope === 'estadual' ? 'Cidade' : 'Bairro'}
            </h3>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Base Territorial</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-6">
            {stats.localDistribution.length === 0 ? (
              <p className="col-span-2 text-center py-10 text-slate-400 italic">Sem registros geográficos suficientes.</p>
            ) : (
              stats.localDistribution.map((loc, index) => {
                const totalInLoc = loc.voters + loc.cabos;
                const pct = (totalInLoc / (stats.total || 1)) * 100;
                return (
                  <div key={loc.name} className="space-y-2 group">
                    <div className="flex justify-between items-end">
                      <div className="flex items-center gap-2">
                        <span className="w-5 h-5 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600 transition-colors">
                          {index + 1}
                        </span>
                        <span className="text-xs font-black text-slate-700 uppercase truncate max-w-[150px]">{loc.name}</span>
                      </div>
                      <span className="text-xs font-black text-indigo-600">{totalInLoc} <span className="text-[9px] text-slate-400 ml-1">votos</span></span>
                    </div>
                    <div className="h-3 w-full bg-slate-50 rounded-full overflow-hidden border border-slate-100">
                      <div 
                        className="h-full bg-gradient-to-r from-indigo-400 to-indigo-600 transition-all duration-1000" 
                        style={{ width: `${pct}%` }} 
                      />
                    </div>
                  </div>
                );
              })
            )}
          </div>

          <div className="mt-8 p-6 bg-slate-50 rounded-3xl border border-slate-100 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-4 text-center md:text-left">
              <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600">
                <Target size={24} />
              </div>
              <div>
                <p className="text-xs font-black text-slate-400 uppercase">Status da Meta Geral</p>
                <p className="text-lg font-black text-slate-800">{stats.total} de {voteGoal} votos prospectados</p>
              </div>
            </div>
            <button 
              onClick={onEditGoal}
              className="px-6 py-3 bg-white text-indigo-600 border border-indigo-100 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-50 transition-all active:scale-95"
            >
              Ajustar Meta
            </button>
          </div>
        </div>

        {/* Bot de Insights (IA) e Agenda */}
        <div className="lg:col-span-4 space-y-6">
          {/* Bot de Insights IA */}
          <div className="bg-gradient-to-br from-indigo-600 to-purple-700 p-8 rounded-[2.5rem] shadow-xl text-white relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:scale-125 transition-transform">
              <Sparkles size={60} />
            </div>
            <div className="relative z-10">
              <h3 className="font-black flex items-center gap-2 text-xl mb-4">
                <MessageSquare size={20} /> Bot de Insights
              </h3>

              {!aiInsight ? (
                <div className="space-y-4">
                  <p className="text-indigo-100 text-xs font-medium leading-relaxed">
                    Precisa de uma análise estratégica rápida do seu desempenho por cidade e meta?
                  </p>
                  <button 
                    onClick={handleGetInsight}
                    disabled={aiLoading}
                    className="w-full py-4 bg-white text-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 shadow-lg hover:bg-indigo-50 transition-all disabled:opacity-50"
                  >
                    {aiLoading ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} />}
                    Pedir Análise à IA
                  </button>
                </div>
              ) : (
                <div className="animate-in fade-in zoom-in-95 duration-300">
                   <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 text-[11px] font-medium leading-relaxed italic mb-4">
                      {aiInsight}
                   </div>
                   <button 
                    onClick={() => setAiInsight(null)}
                    className="w-full py-3 bg-white/20 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white/30 transition-all"
                   >
                     Nova Pergunta
                   </button>
                </div>
              )}
            </div>
          </div>

          {/* Agenda Rápida */}
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                <CalendarClock size={20} className="text-indigo-600" /> Agenda
              </h3>
              <button onClick={onGoToAgenda} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"><ChevronRight size={20} /></button>
            </div>
            <div className="space-y-4">
              {stats.upcomingAppointments.length === 0 ? (
                <div className="py-6 text-center">
                  <p className="text-[10px] text-slate-400 font-bold uppercase">Sem compromissos</p>
                </div>
              ) : (
                stats.upcomingAppointments.map(apt => (
                  <div key={apt.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:border-indigo-100 transition-colors cursor-pointer" onClick={onGoToAgenda}>
                    <div className="flex justify-between items-start mb-1">
                      <span className="text-[9px] font-black text-indigo-600 bg-white px-2 py-0.5 rounded-lg border border-indigo-50 uppercase">{apt.type}</span>
                      <span className="text-[9px] font-bold text-slate-400 flex items-center gap-1"><Clock size={10} /> {apt.time}</span>
                    </div>
                    <h4 className="text-xs font-black text-slate-800 line-clamp-1">{apt.title}</h4>
                  </div>
                ))
              )}
              <button 
                onClick={onGoToAgenda}
                className="w-full py-4 mt-2 bg-indigo-50 text-indigo-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-100 transition-all"
              >
                Ver Agenda Completa
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: React.ReactNode; bgColor: string }> = ({ label, value, icon, bgColor }) => (
  <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-start justify-between group hover:border-indigo-200 transition-all cursor-default">
