              <input type="text" placeholder="Pesquisar..." className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white shadow-inner" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
            <div onClick={() => setActiveTab('agenda')} className="relative group p-3 bg-slate-100 rounded-2xl hover:bg-slate-200 transition-colors cursor-pointer">
              <Bell className="text-slate-600" size={22} />
              {todayAppointments.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black animate-pulse border-2 border-white">{todayAppointments.length}</span>}
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <Dashboard voters={voters} cabos={cabos} appointments={appointments} voteGoal={politicalProfile.voteGoal || 0} scope={politicalProfile.scope} onEditGoal={() => setActiveTab('profile')} onGoToAgenda={() => setActiveTab('agenda')} />
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={voters} /></div>
                <div className="lg:col-span-5"><BirthdayWidget voters={voters} /></div>
              </div>
            </div>
          )}

          {activeTab === 'agenda' && (
            <AgendaManager appointments={appointments} voters={voters} onAdd={addAppointment} onUpdateStatus={updateAppointmentStatus} onDelete={deleteAppointment} />
          )}

          {activeTab === 'reports' && (
            <ReportsCenter voters={voters} cabos={cabos} appointments={appointments} profile={politicalProfile} />
          )}

          {activeTab === 'advisor' && <AIAdvisor profile={politicalProfile} />}
          {activeTab === 'bulk' && <BulkMessenger voters={voters} profile={politicalProfile} />}
          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center"><h2 className="text-4xl font-black text-slate-800">Eleitores Cadastrados</h2></div>
              <VoterList voters={filteredVotersList} onDelete={(id) => setVoters(prev => prev.filter(v => v.id !== id))} onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} />
            </div>
          )}
          {(activeTab === 'add' || activeTab === 'edit') && <VoterForm cabos={cabos} onSubmit={activeTab === 'edit' ? updateVoter : addVoter} onCancel={() => setActiveTab('list')} initialData={editingVoter || undefined} />}
          {activeTab === 'help' && <HelpManager voters={voters} onAddHelp={(vid, rec) => setVoters(prev => prev.map(v => v.id === vid ? { ...v, helpRecords: [...(v.helpRecords || []), { ...rec, id: crypto.randomUUID() }] } : v))} onDeleteHelp={(vid, rid) => setVoters(prev => prev.map(v => v.id === vid ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== rid) } : v))} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />}
          {activeTab === 'profile' && <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">Configurações de Perfil...</div>}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20';
  if (color === 'indigo-glow') activeClass = 'bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-xl ring-2 ring-white/20';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}>
      {icon} <span className="text-sm">{label}</span>
    </button>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Appointment, Voter, PoliticalProfile } from '../types';
import { exportAgendaPDF } from '../services/pdf';
import { 
  Calendar, 
  Clock, 
  MapPin, 
  Plus, 
  Trash2, 
  CheckCircle2, 
  AlertCircle, 
  ChevronRight, 
  User, 
  X, 
  Save, 
  Edit3, 
  FileDown 
} from 'lucide-react';

interface Props {
  appointments: Appointment[];
  voters: Voter[];
  profile: PoliticalProfile;
  onAdd: (appointment: Omit<Appointment, 'id'>) => void;
  onUpdate: (id: string, appointment: Omit<Appointment, 'id'>) => void;
  onUpdateStatus: (id: string, status: Appointment['status']) => void;
  onDelete: (id: string) => void;
}

const AgendaManager: React.FC<Props> = ({ appointments, voters, profile, onAdd, onUpdate, onUpdateStatus, onDelete }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [filter, setFilter] = useState<'all' | 'pending' | 'completed'>('pending');

  const [formData, setFormData] = useState<Omit<Appointment, 'id'>>({
    title: '',
    description: '',
    date: new Date().toISOString().split('T')[0],
    time: '09:00',
    location: '',
    voterId: '',
    status: 'pending',
    type: 'visita'
  });

  const sortedAppointments = useMemo(() => {
    return appointments
      .filter(a => filter === 'all' ? true : a.status === filter)
      .sort((a, b) => {
        const dateA = new Date(`${a.date}T${a.time}`);
        const dateB = new Date(`${b.date}T${b.time}`);
        return dateA.getTime() - dateB.getTime();
      });
  }, [appointments, filter]);

  const handleOpenAdd = () => {
    setEditingId(null);
    setFormData({
      title: '',
      description: '',
      date: new Date().toISOString().split('T')[0],
      time: '09:00',
      location: '',
      voterId: '',
      status: 'pending',
      type: 'visita'
    });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (apt: Appointment) => {
    setEditingId(apt.id);
    setFormData({
      title: apt.title,
      description: apt.description,
      date: apt.date,
      time: apt.time,
      location: apt.location,
      voterId: apt.voterId || '',
      status: apt.status,
      type: apt.type
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.date) return;

    if (editingId) {
      onUpdate(editingId, formData);
    } else {
      onAdd(formData);
    }

    setIsModalOpen(false);
  };

  const getVoterName = (id?: string) => {
    if (!id) return null;
    return voters.find(v => v.id === id)?.name;
  };

  const getTypeColor = (type: Appointment['type']) => {
    switch (type) {
      case 'visita': return 'bg-blue-100 text-blue-700';
      case 'reuniao': return 'bg-purple-100 text-purple-700';
      case 'evento': return 'bg-orange-100 text-orange-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800">Agenda de Compromissos</h2>
          <p className="text-slate-400 text-sm font-medium">Gerencie suas visitas, reuniões e eventos de campanha.</p>
        </div>
        <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
          <button 
            onClick={() => exportAgendaPDF(appointments, profile)}
            className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-slate-50 transition-all shadow-sm"
          >
            <FileDown size={14} className="text-indigo-600" /> Baixar PDF
          </button>

          <div className="flex bg-white border border-slate-200 p-1 rounded-xl shadow-sm">
            <button onClick={() => setFilter('pending')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${filter === 'pending' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}>Pendentes</button>
            <button onClick={() => setFilter('completed')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${filter === 'completed' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}>Concluídos</button>
          </div>

          <button 
            onClick={handleOpenAdd}
            className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all active:scale-95"
          >
            <Plus size={18} /> Novo Compromisso
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {sortedAppointments.length === 0 ? (
          <div className="bg-white p-20 rounded-[3rem] border border-dashed border-slate-300 text-center flex flex-col items-center justify-center text-slate-400">
            <Calendar size={64} className="mb-4 opacity-20" />
            <p className="font-bold">Nenhum compromisso encontrado para este filtro.</p>
          </div>
        ) : (
          sortedAppointments.map((apt) => (
            <div key={apt.id} className={`bg-white p-6 rounded-[2rem] border-2 transition-all flex flex-col md:flex-row items-start md:items-center justify-between gap-6 hover:border-indigo-100 ${apt.status === 'completed' ? 'opacity-60 border-slate-100 shadow-none' : 'border-white shadow-sm'}`}>
              <div className="flex items-start md:items-center gap-6 flex-1">
                <div className={`w-16 h-16 rounded-2xl flex flex-col items-center justify-center font-black ${apt.status === 'completed' ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-600'}`}>
                  <span className="text-[10px] uppercase opacity-60">
                    {new Date(apt.date).toLocaleDateString('pt-BR', { month: 'short' }).replace('.', '')}
                  </span>
                  <span className="text-xl leading-none">{apt.date.split('-')[2]}</span>
                </div>

                <div className="space-y-1 flex-1">
                  <div className="flex flex-wrap items-center gap-2">
                    <span className={`px-2 py-0.5 rounded-lg text-[9px] font-black uppercase ${getTypeColor(apt.type)}`}>
                      {apt.type}
                    </span>
                    <h4 className="font-black text-slate-800 text-lg">{apt.title}</h4>
                  </div>
                  <div className="flex flex-wrap items-center gap-4 text-xs text-slate-400 font-bold uppercase tracking-wider">
                    <span className="flex items-center gap-1"><Clock size={12} /> {apt.time}</span>
                    <span className="flex items-center gap-1"><MapPin size={12} /> {apt.location}</span>
                    {apt.voterId && (
                      <span className="flex items-center gap-1 text-indigo-500">
                        <User size={12} /> {getVoterName(apt.voterId)}
                      </span>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-2 w-full md:w-auto pt-4 md:pt-0 border-t md:border-t-0 border-slate-50">
                <button 
                  onClick={() => handleOpenEdit(apt)}
                  className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                  title="Editar Compromisso"
                >
                  <Edit3 size={18} />
                </button>

                {apt.status === 'pending' ? (
                  <button 
                    onClick={() => onUpdateStatus(apt.id, 'completed')}
                    className="flex-1 md:flex-none px-4 py-3 text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase border border-emerald-100"
                  >
                    <CheckCircle2 size={18} /> Concluir
                  </button>
                ) : (
                  <button 
                    onClick={() => onUpdateStatus(apt.id, 'pending')}
                    className="flex-1 md:flex-none px-4 py-3 text-amber-600 hover:bg-amber-50 rounded-xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase border border-amber-100"
                  >
                    <AlertCircle size={18} /> Reabrir
                  </button>
                )}

                <button 
                  onClick={() => onDelete(apt.id)}
                  className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-6 animate-in fade-in duration-300">
          <div className="w-full max-w-2xl bg-white rounded-[3rem] p-10 shadow-2xl relative animate-in zoom-in-95">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-8 right-8 p-2 text-slate-400 hover:text-slate-600">
              <X size={24} />
            </button>
            <h3 className="text-2xl font-black text-slate-800 mb-8 flex items-center gap-3">
               <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner">
                {editingId ? <Edit3 size={28} /> : <Calendar size={28} />}
               </div>
               {editingId ? 'Editar Compromisso' : 'Novo Compromisso'}
            </h3>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="md:col-span-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Título do Compromisso</label>
                  <input 
                    required
                    value={formData.title}
                    onChange={(e) => setFormData({...formData, title: e.target.value})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                    placeholder="Ex: Reunião com Lideranças do Bairro"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Data</label>
                  <input 
                    type="date"
                    required
                    value={formData.date}
                    onChange={(e) => setFormData({...formData, date: e.target.value})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Horário</label>
                  <input 
                    type="time"
                    required
                    value={formData.time}
                    onChange={(e) => setFormData({...formData, time: e.target.value})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Tipo de Atividade</label>
                  <select 
                    value={formData.type}
                    onChange={(e) => setFormData({...formData, type: e.target.value as any})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                  >
                    <option value="visita">Visita Domiciliar</option>
                    <option value="reuniao">Reunião Política</option>
                    <option value="evento">Evento de Campanha</option>
                    <option value="outro">Outro</option>
                  </select>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Vincular Eleitor (Opcional)</label>
                  <select 
                    value={formData.voterId}
                    onChange={(e) => setFormData({...formData, voterId: e.target.value})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                  >
                    <option value="">Nenhum eleitor selecionado</option>
                    {voters.map(v => (
                      <option key={v.id} value={v.id}>{v.name}</option>
                    ))}
                  </select>
                </div>
                <div className="md:col-span-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Localização</label>
                  <input 
                    required
                    value={formData.location}
                    onChange={(e) => setFormData({...formData, location: e.target.value})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                    placeholder="Rua, Bairro ou Local do Evento"
                  />
                </div>
                <div className="md:col-span-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Descrição / Notas</label>
                  <textarea 
                    rows={3}
                    value={formData.description}
                    onChange={(e) => setFormData({...formData, description: e.target.value})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700 resize-none"
                    placeholder="Detalhes importantes para o compromisso..."
                  />
                </div>
              </div>

              <div className="pt-6 flex gap-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-5 bg-slate-100 text-slate-400 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-slate-200 transition-all">Cancelar</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all flex items-center justify-center gap-3 active:scale-95">
                  <Save size={20} /> {editingId ? 'Salvar Alterações' : 'Salvar na Agenda'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

