const ADMIN_PASSWORD = '4321';

const DEFAULT_PROFILE: PoliticalProfile = {
  name: 'Elias da Fonte',
  party: 'Independente',
  office: 'Candidato',
  scope: 'municipal',
  slogan: 'Trabalhando pela comunidade',
  voteGoal: 1000,
  phone: ''
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loginError, setLoginError] = useState(false);

  const [politicalProfile, setPoliticalProfile] = useState<PoliticalProfile>(DEFAULT_PROFILE);
  const [voters, setVoters] = useState<Voter[]>([]);
  const [cabos, setCabos] = useState<CaboEleitoral[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'family' | 'add' | 'edit' | 'help' | 'profile' | 'cabos' | 'bulk' | 'birthdays' | 'advisor' | 'reports' | 'agenda'>('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingVoter, setEditingVoter] = useState<Voter | null>(null);

  useEffect(() => {
    const savedVoters = localStorage.getItem('voters_data');
    if (savedVoters) setVoters(JSON.parse(savedVoters));

    const savedCabos = localStorage.getItem('cabos_data');
    if (savedCabos) setCabos(JSON.parse(savedCabos));

    const savedAppointments = localStorage.getItem('appointments_data');
    if (savedAppointments) setAppointments(JSON.parse(savedAppointments));

    const savedProfile = localStorage.getItem('political_profile');
    if (savedProfile) {
      setPoliticalProfile(JSON.parse(savedProfile));
    } else {
      localStorage.setItem('political_profile', JSON.stringify(DEFAULT_PROFILE));
    }

    const sessionAuth = sessionStorage.getItem('admin_auth');
    if (sessionAuth === 'true') setIsAuthenticated(true);
  }, []);

  useEffect(() => { localStorage.setItem('voters_data', JSON.stringify(voters)); }, [voters]);
  useEffect(() => { localStorage.setItem('cabos_data', JSON.stringify(cabos)); }, [cabos]);
  useEffect(() => { localStorage.setItem('appointments_data', JSON.stringify(appointments)); }, [appointments]);
  useEffect(() => { localStorage.setItem('political_profile', JSON.stringify(politicalProfile)); }, [politicalProfile]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
      setIsAuthenticated(true);
      sessionStorage.setItem('admin_auth', 'true');
      setLoginError(false);
      setPasswordInput('');
      setActiveTab('dashboard');
    } else {
      setLoginError(true);
      setPasswordInput('');
      setTimeout(() => setLoginError(false), 3000);
    }
  };

  const handleLogoutLogic = () => {
    setIsAuthenticated(false);
    sessionStorage.removeItem('admin_auth');
    setActiveTab('dashboard');
  };

  const addVoter = (data: VoterFormData) => {
    const newVoter: Voter = { ...data, id: crypto.randomUUID(), createdAt: new Date().toISOString(), helpRecords: [] };
    setVoters(prev => [newVoter, ...prev]);
    setActiveTab(newVoter.isFamilyMember ? 'family' : 'list');
  };

  const updateVoter = (data: VoterFormData) => {
    if (!editingVoter) return;
    setVoters(prev => prev.map(v => v.id === editingVoter.id ? { ...v, ...data } : v));
    setEditingVoter(null);
    setActiveTab('list');
  };

  // Funções de Agenda
  const addAppointment = (data: Omit<Appointment, 'id'>) => {
    const newApt: Appointment = { ...data, id: crypto.randomUUID() };
    setAppointments(prev => [newApt, ...prev]);
  };

  const updateAppointment = (id: string, data: Omit<Appointment, 'id'>) => {
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, ...data } : a));
  };

  const deleteAppointment = (id: string) => {
    if(confirm("Deseja realmente excluir este compromisso?")) {
      setAppointments(prev => prev.filter(a => a.id !== id));
    }
  };

  const updateAppointmentStatus = (id: string, status: Appointment['status']) => {
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a));
  };

  const handleProfileSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: PoliticalProfile = {
      name: formData.get('name') as string,
      party: formData.get('party') as string,
      office: formData.get('office') as string,
      scope: formData.get('scope') as 'municipal' | 'estadual',
      slogan: formData.get('slogan') as string,
      voteGoal: parseInt(formData.get('voteGoal') as string) || 0,
      phone: formData.get('phone') as string
    };
    setPoliticalProfile(profile);
    alert("Perfil da campanha salvo com sucesso!");
    setActiveTab('dashboard');
  };

  const filteredVotersList = useMemo(() => {
    let list = voters;
    if (activeTab === 'family') list = list.filter(v => v.isFamilyMember);
    return list.filter(v => 
      v.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      v.neighborhood.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [voters, searchTerm, activeTab]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-800 via-slate-900 to-black">
        <div className="bg-white/10 backdrop-blur-xl w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden p-12 border border-white/10 animate-in fade-in zoom-in-95 duration-500">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-2xl mx-auto mb-6">
              <ShieldCheck size={40} />
            </div>
            <h2 className="text-3xl font-black text-white tracking-tight">Gestor Eleitoral</h2>
            <p className="text-slate-400 font-medium mt-2">Acesso Administrativo Restrito</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div className="relative group">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-indigo-400 transition-colors" size={20} />
              <input type={showPassword ? "text" : "password"} value={passwordInput} onChange={(e) => setPasswordInput(e.target.value)} className={`w-full pl-12 pr-14 py-5 bg-white/5 border-2 ${loginError ? 'border-red-500 animate-pulse' : 'border-white/10 focus:border-indigo-500'} rounded-2xl outline-none text-white text-xl font-bold transition-all text-center tracking-widest`} placeholder="SENHA" autoFocus />
              <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white p-2">
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
            {loginError && <p className="text-red-400 text-xs text-center font-bold">Acesso Negado.</p>}
            <button type="submit" className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-indigo-900/20 active:scale-95 flex items-center justify-center gap-3">
              Entrar no Sistema <ArrowRight size={20} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      <nav className="w-full md:w-72 bg-slate-900 text-white flex-shrink-0 shadow-2xl flex flex-col relative z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg"><Trophy className="text-white" size={32} /></div>
            <div className="overflow-hidden">
              <h1 className="text-xl font-black truncate leading-tight">{politicalProfile.name}</h1>
              <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-2"><ShieldCheck size={12} /> Painel Administrativo</p>
            </div>
          </div>
          <div className="h-px bg-white/10 w-full mb-6"></div>
        </div>
        <div className="flex-1 px-4 space-y-2">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <NavButton active={activeTab === 'agenda'} onClick={() => setActiveTab('agenda')} icon={<CalendarDays size={20}/>} label="Minhas Agendas" color="indigo-glow" />
          <NavButton active={activeTab === 'advisor'} onClick={() => setActiveTab('advisor')} icon={<BrainCircuit size={20}/>} label="Consultoria IA" />
          <NavButton active={activeTab === 'reports'} onClick={() => setActiveTab('reports')} icon={<FileBarChart size={20}/>} label="Relatórios PDF" color="emerald" />
          <NavButton active={activeTab === 'bulk'} onClick={() => setActiveTab('bulk')} icon={<MessageSquare size={20}/>} label="Envios em Massa" color="emerald" />
          <NavButton active={activeTab === 'birthdays'} onClick={() => setActiveTab('birthdays')} icon={<Gift size={20}/>} label="Aniversariantes" color="orange" />
          <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Lista de Eleitores" />
          <NavButton active={activeTab === 'cabos'} onClick={() => setActiveTab('cabos')} icon={<UserCheck size={20}/>} label="Minha Equipe" color="orange" />
          <NavButton active={activeTab === 'family'} onClick={() => setActiveTab('family')} icon={<Heart size={20}/>} label="Família" color="pink" />
          <NavButton active={activeTab === 'help'} onClick={() => setActiveTab('help')} icon={<HandHelping size={20}/>} label="Assistência Social" color="emerald" />
          <NavButton active={activeTab === 'add'} onClick={() => setActiveTab('add')} icon={<UserPlus size={20}/>} label="Novo Registro" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<Settings size={20}/>} label="Ajustes Perfil" color="slate" />
        </div>
        <div className="p-6 mt-auto">
          <button onClick={handleLogoutLogic} className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-400 hover:text-white rounded-2xl text-[11px] font-black uppercase transition-all flex items-center justify-center gap-3 border border-white/10 group active:scale-95"><Home size={16} /> Sair do Painel</button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto bg-slate-50">
        <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center shadow-sm">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Gestor Estratégico</h2>
          <div className="flex items-center gap-6">
            <div className="relative w-full max-w-[300px] hidden lg:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input type="text" placeholder="Pesquisar..." className="w-full pl-12 pr-6 py-3 bg-slate-100 rounded-2xl outline-none font-medium transition-all focus:bg-white shadow-inner" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
          </div>
        </header>

        <div className="p-10">
          {activeTab === 'dashboard' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <Dashboard voters={voters} cabos={cabos} voteGoal={politicalProfile.voteGoal || 0} scope={politicalProfile.scope} onEditGoal={() => setActiveTab('profile')} />
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7"><NeighborhoodChart voters={voters} /></div>
                <div className="lg:col-span-5"><BirthdayWidget voters={voters} /></div>
              </div>
            </div>
          )}

          {activeTab === 'agenda' && (
            <AgendaManager 
              appointments={appointments}
              voters={voters}
              profile={politicalProfile}
              onAdd={addAppointment}
              onUpdate={updateAppointment}
              onUpdateStatus={updateAppointmentStatus}
              onDelete={deleteAppointment}
            />
          )}

          {activeTab === 'reports' && (
            <ReportsCenter voters={voters} cabos={cabos} profile={politicalProfile} />
          )}

          {activeTab === 'advisor' && <AIAdvisor profile={politicalProfile} />}
          {activeTab === 'bulk' && <BulkMessenger voters={voters} profile={politicalProfile} />}
          {activeTab === 'list' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="flex justify-between items-center"><h2 className="text-4xl font-black text-slate-800">Eleitores Cadastrados</h2></div>
              <VoterList voters={filteredVotersList} onDelete={(id) => setVoters(prev => prev.filter(v => v.id !== id))} onEdit={(v) => { setEditingVoter(v); setActiveTab('edit'); }} onManageHelp={(v) => { setEditingVoter(v); setActiveTab('help'); }} />
            </div>
          )}
          {(activeTab === 'add' || activeTab === 'edit') && <VoterForm cabos={cabos} onSubmit={activeTab === 'edit' ? updateVoter : addVoter} onCancel={() => setActiveTab('list')} initialData={editingVoter || undefined} />}
          {activeTab === 'help' && <HelpManager voters={voters} onAddHelp={(vid, rec) => setVoters(prev => prev.map(v => v.id === vid ? { ...v, helpRecords: [...(v.helpRecords || []), { ...rec, id: crypto.randomUUID() }] } : v))} onDeleteHelp={(vid, rid) => setVoters(prev => prev.map(v => v.id === vid ? { ...v, helpRecords: (v.helpRecords || []).filter(r => r.id !== rid) } : v))} onExportHelp={(v) => exportVoterHistoryPDF(v, politicalProfile)} initialVoter={editingVoter} />}

          {activeTab === 'profile' && (
             <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-500">
                <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800"><Settings className="text-indigo-600" /> Perfil Político</h2>
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 gap-6">
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Nome Político</label>
                      <input name="name" required defaultValue={politicalProfile.name} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">WhatsApp para Lembretes</label>
                      <div className="relative">
                         <Phone size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500" />
                         <input name="phone" required defaultValue={politicalProfile.phone} className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" placeholder="(00) 00000-0000" />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Partido</label>
                        <input name="party" required defaultValue={politicalProfile.party} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                      </div>
                      <div>
                        <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Cargo</label>
                        <input name="office" required defaultValue={politicalProfile.office} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Meta Geral (Votos)</label>
                      <div className="relative">
                         <Target size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                         <input type="number" name="voteGoal" required defaultValue={politicalProfile.voteGoal} className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Âmbito da Campanha</label>
                      <div className="relative">
                         <Flag size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                         <select name="scope" defaultValue={politicalProfile.scope} className="w-full pl-12 pr-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold appearance-none">
                            <option value="municipal">Municipal (Foco em Bairros)</option>
                            <option value="estadual">Estadual (Foco em Cidades)</option>
                         </select>
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Slogan de Campanha</label>
                      <input name="slogan" defaultValue={politicalProfile.slogan} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold" placeholder="Frase que define seu compromisso" />
                    </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3">
                    <Save size={20} /> Salvar Alterações de Perfil
                  </button>
                </form>
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; color?: string }> = ({ active, onClick, icon, label, color = 'indigo' }) => {
  let activeClass = 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20';
  if (color === 'emerald') activeClass = 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20';
  if (color === 'orange') activeClass = 'bg-orange-500 text-white shadow-lg shadow-orange-500/20';
  if (color === 'pink') activeClass = 'bg-pink-600 text-white shadow-lg shadow-pink-500/20';
  if (color === 'indigo-glow') activeClass = 'bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-xl ring-2 ring-white/20 scale-[1.02]';
  if (color === 'slate') activeClass = 'bg-slate-700 text-white shadow-lg shadow-slate-500/20';

  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold ${active ? activeClass : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}>
      {icon} <span className="text-sm tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Appointment, Voter, PoliticalProfile } from '../types';
import { exportAgendaPDF } from '../services/pdf';
import { 
  Calendar, 
  Clock, 
  MapPin, 
  Plus, 
  Trash2, 
  CheckCircle2, 
  AlertCircle, 
  User, 
  X, 
  Save, 
  Edit3, 
  FileDown,
  Loader2,
  CheckCircle,
  Search,
  MessageSquare,
  Send,
  Bell
} from 'lucide-react';

interface Props {
  appointments: Appointment[];
  voters: Voter[];
  profile: PoliticalProfile;
  onAdd: (appointment: Omit<Appointment, 'id'>) => void;
  onUpdate: (id: string, appointment: Omit<Appointment, 'id'>) => void;
  onUpdateStatus: (id: string, status: Appointment['status']) => void;
  onDelete: (id: string) => void;
}

const AgendaManager: React.FC<Props> = ({ appointments, voters, profile, onAdd, onUpdate, onUpdateStatus, onDelete }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<'all' | 'pending' | 'completed'>('pending');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);

  const [formData, setFormData] = useState<Omit<Appointment, 'id'>>({
    title: '',
    description: '',
    date: new Date().toISOString().split('T')[0],
    time: '09:00',
    location: '',
    voterId: '',
    status: 'pending',
    type: 'visita'
  });

  const groupedAppointments = useMemo<Record<string, Appointment[]>>(() => {
    const today = new Date().toISOString().split('T')[0];
    const tomorrow = new Date(Date.now() + 86400000).toISOString().split('T')[0];

    const filtered = appointments.filter(a => {
      const matchesStatus = filterStatus === 'all' ? true : a.status === filterStatus;
      const matchesSearch = a.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           a.location.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesStatus && matchesSearch;
    }).sort((a, b) => {
      const dateA = new Date(`${a.date}T${a.time}`);
      const dateB = new Date(`${b.date}T${b.time}`);
      return dateA.getTime() - dateB.getTime();
    });

    return {
      hoje: filtered.filter(a => a.date === today),
      amanha: filtered.filter(a => a.date === tomorrow),
      futuro: filtered.filter(a => a.date > tomorrow),
      passado: filtered.filter(a => a.date < today)
    };
  }, [appointments, filterStatus, searchTerm]);

  const handleOpenAdd = () => {
    setEditingId(null);
    setSaveSuccess(false);
    setIsSaving(false);
    setFormData({
      title: '',
      description: '',
      date: new Date().toISOString().split('T')[0],
      time: '09:00',
      location: '',
      voterId: '',
      status: 'pending',
      type: 'visita'
    });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (apt: Appointment) => {
    setEditingId(apt.id);
    setSaveSuccess(false);
    setIsSaving(false);
    setFormData({
      title: apt.title,
      description: apt.description,
      date: apt.date,
      time: apt.time,
      location: apt.location,
      voterId: apt.voterId || '',
      status: apt.status,
      type: apt.type
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.date) return;

    setIsSaving(true);

    setTimeout(() => {
      if (editingId) {
        onUpdate(editingId, formData);
      } else {
        onAdd(formData);
      }

      setIsSaving(false);
      setSaveSuccess(true);

      setTimeout(() => {
        setIsModalOpen(false);
        setSaveSuccess(false);
      }, 1200);
    }, 800);
  };

  const handleSendReminder = (apt: Appointment) => {
    if (!profile.phone) {
      alert("Por favor, configure o WhatsApp do Político em 'Ajustes Perfil' para enviar lembretes.");
      return;
    }

    const dateFormatted = new Date(apt.date).toLocaleDateString('pt-BR');
    const message = `🚨 *LEMBRETE DE COMPROMISSO*\n\nOlá, *${profile.name}*!\n\nVocê tem uma atividade agendada:\n📌 *${apt.title}*\n📅 Data: ${dateFormatted}\n⏰ Horário: ${apt.time}\n📍 Local: ${apt.location}\n\n📝 Notas: ${apt.description || 'Nenhuma observação.'}\n\n_Enviado via Sistema de Gestão Eleitoral_`;

    const whatsappUrl = `https://wa.me/${profile.phone.replace(/\D/g, '')}?text=${encodeURIComponent(message)}`;
    window.open(whatsappUrl, '_blank');
  };

  const getVoter = (id?: string) => {
    if (!id) return null;
    return voters.find(v => v.id === id);
  };

  const getTypeStyle = (type: Appointment['type']) => {
    switch (type) {
      case 'visita': return { bg: 'bg-blue-50', text: 'text-blue-700', border: 'border-blue-100', icon: 'bg-blue-500' };
      case 'reuniao': return { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-100', icon: 'bg-purple-500' };
      case 'evento': return { bg: 'bg-orange-50', text: 'text-orange-700', border: 'border-orange-100', icon: 'bg-orange-500' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-700', border: 'border-slate-100', icon: 'bg-slate-500' };
    }
  };

  const AppointmentCard: React.FC<{ apt: Appointment }> = ({ apt }) => {
    const style = getTypeStyle(apt.type);
    const voter = getVoter(apt.voterId);

    return (
      <div className={`bg-white p-6 rounded-[2rem] border-2 transition-all flex flex-col md:flex-row items-start md:items-center justify-between gap-6 hover:shadow-xl hover:shadow-indigo-500/5 ${apt.status === 'completed' ? 'opacity-60 grayscale border-slate-100' : 'border-white shadow-sm'}`}>
        <div className="flex items-start md:items-center gap-6 flex-1">
          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-lg ${style.icon} shrink-0`}>
            {apt.type === 'visita' && <User size={24} />}
            {apt.type === 'reuniao' && <Calendar size={24} />}
            {apt.type === 'evento' && <SparklesIcon size={24} />}
            {apt.type === 'outro' && <AlertCircle size={24} />}
          </div>

          <div className="space-y-1.5 flex-1 min-w-0">
            <div className="flex flex-wrap items-center gap-2">
              <span className={`px-2 py-0.5 rounded-lg text-[9px] font-black uppercase ${style.bg} ${style.text}`}>
                {apt.type}
              </span>
              <h4 className="font-black text-slate-800 text-lg truncate">{apt.title}</h4>
            </div>
            <div className="flex flex-wrap items-center gap-4 text-[11px] text-slate-400 font-bold uppercase tracking-wider">
              <span className="flex items-center gap-1.5 bg-slate-50 px-2 py-1 rounded-md"><Clock size={12} className="text-indigo-500" /> {apt.time}</span>
              <span className="flex items-center gap-1.5 bg-slate-50 px-2 py-1 rounded-md"><MapPin size={12} className="text-indigo-500" /> {apt.location}</span>
              {voter && (
                <div className="flex items-center gap-2 text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md">
                  <User size={12} /> {voter.name}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full md:w-auto shrink-0 flex-wrap">
          <button 
            onClick={() => handleSendReminder(apt)}
            className="flex-1 md:flex-none px-4 py-3 bg-emerald-50 text-emerald-600 hover:bg-emerald-500 hover:text-white rounded-xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase border border-emerald-100 shadow-sm"
            title="Enviar Lembrete p/ WhatsApp do Político"
          >
            <Bell size={16} /> Lembrete WhatsApp
          </button>

          <button 
            onClick={() => handleOpenEdit(apt)}
            className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
          >
            <Edit3 size={18} />
          </button>

          {apt.status === 'pending' ? (
            <button 
              onClick={() => onUpdateStatus(apt.id, 'completed')}
              className="px-5 py-3 bg-indigo-50 text-indigo-600 hover:bg-indigo-600 hover:text-white rounded-xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase border border-indigo-100"
            >
              <CheckCircle2 size={16} /> Concluir
            </button>
          ) : (
            <button 
              onClick={() => onUpdateStatus(apt.id, 'pending')}
              className="px-5 py-3 bg-amber-50 text-amber-600 hover:bg-amber-600 hover:text-white rounded-xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase border border-amber-100"
            >
              <AlertCircle size={16} /> Reabrir
            </button>
          )}

          <button 
            onClick={() => onDelete(apt.id)}
            className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
          >
            <Trash2 size={18} />
          </button>
        </div>
      </div>
    );
  };

  const AppointmentSection: React.FC<{ title: string; appointments: Appointment[]; color: string }> = ({ title, appointments, color }) => {
    if (appointments.length === 0) return null;
    return (
      <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex items-center gap-3 px-4">
          <div className={`w-2 h-8 rounded-full ${color}`} />
          <h3 className="text-sm font-black text-slate-400 uppercase tracking-[0.2em]">{title}</h3>
          <span className="text-xs font-bold text-slate-300 ml-auto">{appointments.length} compromissos</span>
        </div>
        <div className="space-y-4">
          {appointments.map(apt => <AppointmentCard key={apt.id} apt={apt} />)}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-800 tracking-tight">Minhas Agendas</h2>
          <p className="text-slate-400 text-sm font-medium">Cronograma estratégico e lembretes de campanha.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <div className="relative flex-1 lg:w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar compromisso..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-xl outline-none font-bold text-slate-700 focus:border-indigo-500 transition-all shadow-sm"
            />
          </div>

          <div className="flex bg-white border border-slate-200 p-1.5 rounded-xl shadow-sm">
            <button onClick={() => setFilterStatus('pending')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${filterStatus === 'pending' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>Pendentes</button>
            <button onClick={() => setFilterStatus('completed')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${filterStatus === 'completed' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>Concluídos</button>
            <button onClick={() => setFilterStatus('all')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${filterStatus === 'all' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
          </div>

          <button 
            onClick={() => exportAgendaPDF(appointments, profile)}
            className="p-3 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 transition-all shadow-sm"
          >
            <FileDown size={20} />
          </button>

          <button 
            onClick={handleOpenAdd}
            className="px-6 py-3 bg-gradient-to-r from-indigo-600 to-indigo-700 text-white rounded-xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:shadow-xl hover:shadow-indigo-500/20 transition-all active:scale-95"
          >
            <Plus size={18} /> Novo Compromisso
          </button>
        </div>
      </div>

      <div className="space-y-12">
        {appointments.length === 0 ? (
          <div className="bg-white p-24 rounded-[3rem] border border-dashed border-slate-200 text-center flex flex-col items-center justify-center text-slate-400">
            <Calendar size={80} className="mb-6 opacity-10" />
            <h3 className="text-xl font-black text-slate-600">Sua agenda está vazia</h3>
            <p className="max-w-xs mx-auto mt-2 text-sm">Organize suas visitas e reuniões políticas aqui.</p>
          </div>
        ) : (
          <>
            <AppointmentSection title="Hoje" appointments={groupedAppointments.hoje} color="bg-indigo-500" />
            <AppointmentSection title="Amanhã" appointments={groupedAppointments.amanha} color="bg-blue-400" />
            <AppointmentSection title="Próximos Dias" appointments={groupedAppointments.futuro} color="bg-emerald-400" />
            <AppointmentSection title="Passados" appointments={groupedAppointments.passado} color="bg-slate-300" />

            {searchTerm && 
              Object.values(groupedAppointments).every((arr: Appointment[]) => arr.length === 0) && (
                <div className="text-center py-20 text-slate-400">
                  <Search size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="font-bold">Nenhum compromisso corresponde à sua busca.</p>
                </div>
              )
            }
          </>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-6 animate-in fade-in duration-300">
          <div className="w-full max-w-2xl bg-white rounded-[3rem] shadow-2xl relative animate-in zoom-in-95 duration-300 overflow-hidden">
            {saveSuccess ? (
              <div className="flex flex-col items-center justify-center py-24 bg-gradient-to-br from-emerald-50 to-white">
                <div className="w-24 h-24 bg-emerald-500 text-white rounded-full flex items-center justify-center mb-6 shadow-xl shadow-emerald-200">
                  <CheckCircle size={60} className="animate-in zoom-in duration-500" />
                </div>
                <h3 className="text-3xl font-black text-slate-800">Salvo com Sucesso!</h3>
                <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-2">Compromisso registrado no sistema</p>
              </div>
            ) : (
              <div className="p-10">
                <div className="flex justify-between items-center mb-10">
                  <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner">
                      {editingId ? <Edit3 size={32} /> : <Calendar size={32} />}
                    </div>
                    <div>
                      <h3 className="text-2xl font-black text-slate-800 leading-tight">
                        {editingId ? 'Editar Compromisso' : 'Novo Compromisso'}
                      </h3>
                      <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Informações de Agenda</p>
                    </div>
                  </div>
                  <button onClick={() => setIsModalOpen(false)} className="p-2 text-slate-300 hover:text-slate-600 transition-colors">
                    <X size={28} />
                  </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-8">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Título do Compromisso</label>
                      <input 
                        required
                        disabled={isSaving}
                        value={formData.title}
                        onChange={(e) => setFormData({...formData, title: e.target.value})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                        placeholder="Ex: Reunião com Moradores da Vila Azul"
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Data</label>
                      <input 
                        type="date"
                        required
                        disabled={isSaving}
                        value={formData.date}
                        onChange={(e) => setFormData({...formData, date: e.target.value})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Horário</label>
                      <input 
                        type="time"
                        required
                        disabled={isSaving}
                        value={formData.time}
                        onChange={(e) => setFormData({...formData, time: e.target.value})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Tipo de Atividade</label>
                      <select 
                        disabled={isSaving}
                        value={formData.type}
                        onChange={(e) => setFormData({...formData, type: e.target.value as any})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                      >
                        <option value="visita">Visita Política</option>
                        <option value="reuniao">Reunião Interna</option>
                        <option value="evento">Evento Público</option>
                        <option value="outro">Outros</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Vincular Eleitor (Opcional)</label>
                      <select 
                        disabled={isSaving}
                        value={formData.voterId}
                        onChange={(e) => setFormData({...formData, voterId: e.target.value})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                      >
                        <option value="">Nenhum</option>
                        {voters.map(v => (
                          <option key={v.id} value={v.id}>{v.name}</option>
                        ))}
                      </select>
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Localização</label>
                      <input 
                        required
                        disabled={isSaving}
                        value={formData.location}
                        onChange={(e) => setFormData({...formData, location: e.target.value})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700"
                        placeholder="Endereço ou Local de Referência"
                      />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Observações Adicionais</label>
                      <textarea 
                        rows={3}
                        disabled={isSaving}
                        value={formData.description}
                        onChange={(e) => setFormData({...formData, description: e.target.value})}
                        className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-slate-700 resize-none"
                        placeholder="Detalhes que o político precisa saber..."
                      />
                    </div>
                  </div>

                  <div className="pt-8 flex gap-4">
                    <button 
                      type="button" 
                      onClick={() => setIsModalOpen(false)} 
                      disabled={isSaving}
                      className="flex-1 py-5 bg-slate-100 text-slate-400 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-slate-200 transition-all"
                    >
                      Cancelar
                    </button>
                    <button 
                      type="submit" 
                      disabled={isSaving}
                      className="flex-[2] py-5 bg-gradient-to-r from-indigo-600 to-indigo-800 text-white rounded-2xl font-black text-lg hover:shadow-2xl transition-all flex items-center justify-center gap-3 active:scale-95"
                    >
                      {isSaving ? <Loader2 size={24} className="animate-spin" /> : <Save size={24} />}
                      Salvar Compromisso
                    </button>
                  </div>
                </form>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

